INSERT INTO gi_entries (gi_id, country_code, country, category, primary_gi_name, all_gi_names, gi_type_primary, gi_types_all, tasting_notes, horeca_use, packaging_formats, seasonal_months, aliases, is_data_thin, source_layer) VALUES
  ('d0baf2d7-00ef-faaa-45aa-bab594a4f7bd', 'IT', 'Italy', 'cured_meats_charcuterie', 'Bresaola della Valtellina IGP', '["Bresaola della Valtellina IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lean air-dried beef with deep ruby color, delicate aromatic notes of dried herbs and juniper, clean iron-mineral finish, very low fat. Texture firm but yielding when sliced thin.', 'Sliced paper-thin and served as antipasto with rocket, shaved Grana Padano and lemon olive oil; rolled around goat cheese as canapé; chopped over salads.', '["whole-piece-vacuum-2-3kg", "half-piece-vacuum-1kg", "deli-sliced-vacuum-100g", "deli-sliced-vacuum-80g", "pre-sliced-tray-200g"]'::jsonb, '[]'::jsonb, '["Bresaola", "Valtellina bresaola"]'::jsonb, FALSE, 'L2'),
  ('f0777ecb-afb2-4804-890c-a472bfd07b57', 'IT', 'Italy', 'cured_meats_charcuterie', 'Capocollo di Calabria DOP', '["Capocollo di Calabria DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Rich, marbled cured pork neck with assertive paprika and chili spice profile, soft sweet pork notes, mild smokiness, finishing pleasantly piquant.', 'Sliced for antipasto boards, paired with sharp pecorino and crusty bread; chopped into Calabrian-style pasta and pizza toppings.', '["whole-piece-vacuum-1.5-2kg", "half-piece-vacuum-700g", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Capicollo", "Capocollo", "Calabrian coppa"]'::jsonb, FALSE, 'L2'),
  ('1d90bdda-060c-e2ca-91de-e3007e637085', 'IT', 'Italy', 'cured_meats_charcuterie', 'Ciauscolo IGP', '["Ciauscolo IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Soft spreadable salami from the Marche, garlic and wine-spiced, with a creamy texture from finely minced fat, mild and rustic with subtle fennel notes.', 'Spread on warm crostini or bread, served as antipasto; used to fill stuffed olives or as topping on regional pizzas.', '["whole-piece-vacuum-400-700g", "half-piece-vacuum-300g", "tub-spreadable-200g"]'::jsonb, '[]'::jsonb, '["Ciauscolo marchigiano", "Ciauscolo di Visso"]'::jsonb, FALSE, 'L2'),
  ('bcebf529-ab4b-a607-3981-2fb0dbe038c7', 'IT', 'Italy', 'cured_meats_charcuterie', 'Coppa di Parma IGP', '["Coppa di Parma IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Cured pork neck, rosy interior with even fat marbling, delicate sweet-savory pork flavor with light pepper and wine notes, silky melt-in-mouth texture when sliced thin.', 'Sliced thin for charcuterie boards alongside Prosciutto di Parma; rolled with melon or fig; layered in panini.', '["whole-piece-vacuum-1.5-2kg", "half-piece-vacuum-700g", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Coppa parmigiana", "Capocollo parmigiano"]'::jsonb, FALSE, 'L2'),
  ('82d3df41-9db5-492b-e75b-66b65e9d944f', 'IT', 'Italy', 'cured_meats_charcuterie', 'Coppa Piacentina DOP', '["Coppa Piacentina DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aged cured pork neck from Emilia, deep red lean meat ribboned with fat, complex sweet-spiced flavor with pepper, clove and nutmeg, firmer texture than Coppa di Parma due to longer aging (minimum 6 months).', 'Sliced thin for premium charcuterie service; paired with aged balsamic and Parmigiano; centerpiece of Piacenza-style salumi platter (with Salame and Pancetta Piacentina).', '["whole-piece-vacuum-1.5-2.5kg", "half-piece-vacuum-900g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Coppa piacentina", "Capocollo piacentino"]'::jsonb, FALSE, 'L2'),
  ('ed0fee22-3f2b-6d8b-9a8e-3cbe95da7661', 'IT', 'Italy', 'cured_meats_charcuterie', 'Cotechino Modena IGP', '["Cotechino Modena IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Large fresh-cooked pork sausage with rind, soft gelatinous texture, rich pork-fat mouthfeel, warm spice notes (clove, cinnamon, nutmeg, pepper).', 'Boiled and sliced, traditional New Year''s Eve service with lentils (Cotechino con lenticchie); also paired with mashed potatoes, polenta, or zampone-style on tasting menus.', '["vacuum-pack-pre-cooked-500g", "vacuum-pack-pre-cooked-1kg", "vacuum-pack-raw-500g", "gift-tin-500g"]'::jsonb, '[11, 12, 1]'::jsonb, '["Cotechino modenese", "Cotechino"]'::jsonb, FALSE, 'L2'),
  ('0d595e27-5adb-8cfc-9856-6963c2383614', 'IT', 'Italy', 'cured_meats_charcuterie', 'Crudo di Cuneo DOP', '["Crudo di Cuneo DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese dry-cured ham, sweet and delicate, less aromatic than Parma or San Daniele, soft pink meat with thin layer of buttery white fat, gentle salt-aged flavor.', 'Sliced thin for antipasto boards in Piedmontese restaurants; served with grissini Torinesi and Castelmagno; used in regional vitello tonnato adaptations.', '["whole-leg-bone-in-9-12kg", "whole-leg-boneless-vacuum-7-9kg", "half-leg-vacuum-4kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Prosciutto Crudo di Cuneo", "Cuneo ham"]'::jsonb, FALSE, 'L2'),
  ('d714b477-a4bf-18ec-ce2b-a04659b76f04', 'IT', 'Italy', 'cured_meats_charcuterie', 'Culatello di Zibello DOP', '["Culatello di Zibello DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Pear-shaped pressed cured pork hindquarter aged in fog of lower Po valley, deep ruby color, intense aroma of dried fruit and cellar must, silky melt-in-mouth texture, complex sweet-savory finish — the most prized Italian cured pork.', 'Premium antipasto served minimally (slice, butter, bread, or on its own); paired with aged Parmigiano and Lambrusco; centerpiece of high-end Emilian dégustation.', '["whole-piece-netted-3-5kg", "half-piece-vacuum-1.5kg", "deli-sliced-vacuum-80g", "deli-sliced-tray-100g"]'::jsonb, '[]'::jsonb, '["Culatello", "Zibello culatello"]'::jsonb, FALSE, 'L2'),
  ('2deef9b0-f98c-8594-96b5-98a5a069c6db', 'IT', 'Italy', 'cured_meats_charcuterie', 'Finocchiona IGP', '["Finocchiona IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Tuscan salami flavored with wild fennel seeds and flowers, soft pliable texture, savory pork flavor distinctly perfumed with anise notes, gentle red wine undertones.', 'Sliced thin on Tuscan salumi boards; served on crostini with chicken liver pâté contrasts; layered in panini with pecorino.', '["whole-piece-vacuum-1.5-2kg", "half-piece-vacuum-800g", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Finocchiona toscana", "Tuscan fennel salami"]'::jsonb, FALSE, 'L2'),
  ('66bfe967-382d-6a41-7f30-d67352260cdf', 'IT', 'Italy', 'cured_meats_charcuterie', 'Lardo di Colonnata IGP', '["Lardo di Colonnata IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Cured pork back-fat from Apuan Alps, aged in marble vats with herbs, salt, and garlic. Translucent ivory color, silky cool fat that melts on tongue, intensely aromatic with rosemary, sage, garlic, and pepper.', 'Sliced paper-thin and laid on warm bread to melt; draped over hot roasted meat; topping for risotto or polenta; rolled around grilled prawns.', '["slab-vacuum-1-2kg", "half-slab-vacuum-500g", "deli-sliced-vacuum-80g", "pre-sliced-tray-100g"]'::jsonb, '[]'::jsonb, '["Lardo", "Colonnata lardo", "Marble-aged lardo"]'::jsonb, FALSE, 'L2'),
  ('c33d9cb5-3159-1c66-a798-0ac5fa8fb890', 'IT', 'Italy', 'cured_meats_charcuterie', 'Lucanica di Picerno IGP', '["Lucanica di Picerno IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Long thin cured pork sausage from Basilicata flavored with local fennel, peperone crusco (dried sweet pepper), and pepper. Firm texture, balanced sweet-spicy profile, distinct rustic southern character.', 'Sliced for southern Italian salumi boards; chopped into rustic pasta sauces with peperoni cruschi; grilled in fresh form.', '["whole-piece-vacuum-300-500g", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Lucanica", "Lucania sausage"]'::jsonb, FALSE, 'L2'),
  ('d568fb9d-4664-975f-3dc8-210e10762044', 'IT', 'Italy', 'cured_meats_charcuterie', 'Mortadella Bologna IGP', '["Mortadella Bologna IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Large pink emulsified pork sausage studded with white fat cubes and pistachios. Silky-soft texture, mild sweet-savory pork flavor, gentle peppercorn and myrtle berry warmth, butter-like richness.', 'Sliced very thin or cubed; served on focaccia, in tigella sandwiches, in cubes as aperitivo with Lambrusco; minced into Bolognese mortadella mousse for gnocco fritto.', '["whole-roll-vacuum-2-5kg", "half-roll-vacuum-1.5kg", "deli-sliced-vacuum-100g", "pre-sliced-tray-200g", "cube-pack-200g", "mousse-tub-150g"]'::jsonb, '[]'::jsonb, '["Mortadella", "Bologna sausage", "Mortadella bolognese"]'::jsonb, FALSE, 'L2'),
  ('1c8fd0ce-e6a6-8c87-58e5-6ff977d4d333', 'IT', 'Italy', 'cured_meats_charcuterie', 'Mortadella di Prato IGP', '["Mortadella di Prato IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Tuscan pink mortadella distinct from Bologna by Alkermes liqueur infusion, giving rosy hue and sweet-spicy aromatic notes; firmer texture, less fat than Bologna, with garlic, mace, and clove.', 'Sliced for Tuscan antipasto boards; key ingredient in classic sedani alla pratese pasta dish; paired with regional pecorino.', '["whole-roll-vacuum-1.5-2.5kg", "half-roll-vacuum-1kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Mortadella pratese"]'::jsonb, FALSE, 'L2'),
  ('59c8dd4d-52c2-8d2a-4ecf-7c493303d9ba', 'IT', 'Italy', 'cured_meats_charcuterie', 'Pancetta di Calabria DOP', '["Pancetta di Calabria DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Cured rolled pork belly with chili and pepper coating; pink meat alternated with white fat, bold flavor with definite spicy heat, smoky-sweet notes.', 'Sliced for antipasto with Calabrian salumi; cubed for pasta amatriciana-style and bean stews; rendered for cooking.', '["whole-piece-vacuum-1.5-2kg", "half-piece-vacuum-700g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Pancetta calabrese"]'::jsonb, FALSE, 'L2'),
  ('e362035d-fb3b-be1a-978f-c208b534dbaf', 'IT', 'Italy', 'cured_meats_charcuterie', 'Pancetta Piacentina DOP', '["Pancetta Piacentina DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Rolled cured pork belly aged minimum 4 months in Piacenza microclimate, alternating ribbons of rosy meat and white fat, sweet pork flavor with pepper, clove, and nutmeg, firm but yielding texture.', 'Sliced thin for charcuterie boards; cubed for soffritto base in pasta sauces (Bolognese, Carbonara, Amatriciana); rendered for fat in regional cuisine.', '["whole-piece-vacuum-3-5kg", "half-piece-vacuum-1.5kg", "deli-sliced-vacuum-100g", "cube-pack-200g"]'::jsonb, '[]'::jsonb, '["Pancetta piacentina", "Piacenza pancetta"]'::jsonb, FALSE, 'L2'),
  ('5ee4e60f-9c3e-b50a-8832-48b6f27869ef', 'IT', 'Italy', 'cured_meats_charcuterie', 'Pitina IGP', '["Pitina IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Friulian smoked sausage made from goat or mutton with corn-flour coating, traditionally aged in mountain villages. Rustic smoky flavor, dense texture.', '[DATA THIN] Sliced as antipasto in Friulian regional restaurants; grilled or pan-fried; served with polenta.', '["whole-piece-vacuum-200-400g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Petuccia", "Peta"]'::jsonb, TRUE, 'L2'),
  ('967d14ec-9277-a4f5-f0d1-084a98a2d0a2', 'IT', 'Italy', 'cured_meats_charcuterie', 'Porchetta di Ariccia IGP', '["Porchetta di Ariccia IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Whole boned pork loin and belly, slow-roasted with rosemary, garlic, fennel, salt and pepper. Crisp golden crackling crust, herb-perfumed succulent meat, aromatic fennel and rosemary running throughout.', 'Sliced into panini con porchetta as Roman street food signature; carved at table on Lazio tasting menus; served warm with roasted potatoes; cold cuts for buffet.', '["whole-roast-pre-cooked-4-7kg", "half-roast-vacuum-2kg", "deli-sliced-vacuum-100g", "panino-ready-150g"]'::jsonb, '[]'::jsonb, '["Porchetta romana", "Ariccia porchetta"]'::jsonb, FALSE, 'L2'),
  ('7efd5882-6fb2-c58d-f539-9040eda7e1ee', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto Amatriciano IGP', '["Prosciutto Amatriciano IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Mountain-aged dry-cured ham from Amatrice (Lazio/Marche border), darker color than Parma, more robust salt-aged flavor with pronounced umami and slight game notes from breeze-aged conditions.', 'Sliced for central-Italian salumi boards; component of regional bucatini all''Amatriciana adaptations; paired with mountain pecorino.', '["whole-leg-bone-in-7-9kg", "whole-leg-boneless-vacuum-5-7kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Prosciutto di Amatrice"]'::jsonb, FALSE, 'L2'),
  ('5485f8f4-da3d-b569-da95-caf63e61f145', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto di Carpegna DOP', '["Prosciutto di Carpegna DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sweet, delicate Marche dry-cured ham aged 13+ months, light salt level, soft rosy meat, distinct mild aroma without the pungency of Parma or San Daniele, buttery fat layer.', 'Sliced thin for antipasto; classic pairing with melon or figs in summer service; layered in panini with mozzarella.', '["whole-leg-bone-in-9-12kg", "whole-leg-boneless-vacuum-7-9kg", "half-leg-vacuum-4kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Carpegna ham", "Crudo di Carpegna"]'::jsonb, FALSE, 'L2'),
  ('dddfa108-503e-49d9-039c-3a6807b3b955', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto di Modena DOP', '["Prosciutto di Modena DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sweet dry-cured ham from Po valley, aged minimum 14 months. Pink-red meat, soft white fat, sweet delicate flavor, slightly less aromatic than Parma, smooth pleasant finish.', 'Sliced for antipasto boards; alternative to Parma in Emilia-Romagna restaurants; rolled with melon or grissini for finger food.', '["whole-leg-bone-in-8-10kg", "whole-leg-boneless-vacuum-6-8kg", "half-leg-vacuum-4kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Modena ham", "Crudo di Modena"]'::jsonb, FALSE, 'L2'),
  ('58bc2f3c-ee2b-e9ef-27ee-f12feaf22804', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto di Norcia IGP', '["Prosciutto di Norcia IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Umbrian mountain-aged ham, characteristic pear shape, deep rosy meat with firm texture, intense salt-aged savor, robust mountain character with slight herbal/woodland notes.', 'Sliced for Umbrian antipasto boards; paired with pecorino di fossa and Norcia black truffle; centerpiece of Norcineria charcuterie tradition.', '["whole-leg-bone-in-8-9kg", "whole-leg-boneless-vacuum-6-7kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Norcia ham", "Norcineria-style prosciutto"]'::jsonb, FALSE, 'L2'),
  ('2f421d5c-64da-ef27-4107-f8d0a4114b17', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto di Parma DOP', '["Prosciutto di Parma DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aged dry-cured ham (minimum 14 months, often 18-24), sweet rosy meat with marbled white fat, delicate aroma of dried meadow flowers and dried fruit, signature sweet-savory balance with no bitter aftertaste — the global benchmark of Italian raw ham.', 'Sliced paper-thin for antipasto; classic with melon, fig, mozzarella di bufala, or grissini; layered in panini and pizzas; cured ham bone for risotto stock; ribbons in pasta dishes.', '["whole-leg-bone-in-9-13kg", "whole-leg-boneless-vacuum-7-9kg", "half-leg-vacuum-4-5kg", "quarter-vacuum-2kg", "deli-sliced-vacuum-100g", "deli-sliced-vacuum-80g", "pre-sliced-tray-150g", "gift-pack-200g"]'::jsonb, '[]'::jsonb, '["Parma ham", "Parma prosciutto", "PDO Parma", "Crudo di Parma"]'::jsonb, FALSE, 'L2'),
  ('b7c68cb2-f7f8-d8d2-f3c3-8fc05524acbf', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto di San Daniele DOP', '["Prosciutto di San Daniele DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Friulian dry-cured ham aged minimum 13 months in unique alpine-Adriatic microclimate; characteristic guitar shape with foot intact, deep ruby meat, sweeter and more aromatic than Parma, with delicate floral and dried-fruit notes.', 'Sliced thin for premium antipasto; classically paired with melon, figs, or fresh ricotta; centerpiece of Friulian dégustation; rolled around grissini.', '["whole-leg-bone-in-8-12kg", "whole-leg-boneless-vacuum-7-9kg", "half-leg-vacuum-4kg", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["San Daniele ham", "San Daniele", "Sandaniele"]'::jsonb, FALSE, 'L2'),
  ('520f43ca-3eec-1e12-aca3-329b84ca8a19', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto di Sauris IGP', '["Prosciutto di Sauris IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lightly cold-smoked Friulian dry-cured ham from Carnic Alps, aged minimum 10 months. Pinker than Parma, gentle beechwood smoke aroma, balanced sweet-salty-smoky profile.', 'Sliced thin for alpine-Friulian antipasto; paired with smoked Montasio cheese and rye breads; component of Friulian frico variations.', '["whole-leg-bone-in-7-9kg", "whole-leg-boneless-vacuum-5-7kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Sauris ham", "Saurin smoked prosciutto"]'::jsonb, FALSE, 'L2'),
  ('744e73db-2f03-149d-fb8f-eee8c528e172', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto Toscano DOP', '["Prosciutto Toscano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan dry-cured ham distinguished by aromatic herb-and-pepper rub during seasoning. Saltier and bolder than Parma, robust pork flavor with pronounced rosemary, juniper, and pepper notes.', 'Sliced for Tuscan antipasto with crostini and salt-free Tuscan bread; paired with pecorino toscano; layered in panini; component in Tuscan tagliere.', '["whole-leg-bone-in-9-12kg", "whole-leg-boneless-vacuum-7-9kg", "half-leg-vacuum-4kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Tuscan ham", "Crudo Toscano"]'::jsonb, FALSE, 'L2'),
  ('d72268b0-d1c3-1657-85ae-9ba4a23b6a3a', 'IT', 'Italy', 'cured_meats_charcuterie', 'Prosciutto Veneto Berico-Euganeo DOP', '["Prosciutto Veneto Berico-Euganeo DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sweet aged ham from Veneto Berici and Euganei hills, aged minimum 12 months. Pink-red meat with white fat marbling, sweet and delicate flavor, mild aromatic profile distinct from Parma''s sweetness and San Daniele''s intensity.', 'Sliced for Veneto antipasto boards; paired with Asiago Stagionato; served with grissini and Soave wine.', '["whole-leg-bone-in-8-10kg", "whole-leg-boneless-vacuum-6-8kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Veneto Berico-Euganeo ham", "Prosciutto Veneto"]'::jsonb, FALSE, 'L2'),
  ('93a5b9eb-d601-d11b-8067-27749e97615f', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salama da sugo IGP', '["Salama da sugo IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Ferrara cooked seasoned pork salami, traditionally aged then long-simmered. Intense complex flavor of pork, red wine, cloves, cinnamon, nutmeg; soft moist texture; distinctive sauce-like consistency.', 'Boiled whole, served sliced over creamy mashed potatoes or polenta as Ferrarese signature dish; component of Renaissance-style banquet menus.', '["whole-piece-vacuum-700g-1.2kg", "ready-cooked-vacuum-500g"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Salama da sugo ferrarese", "Ferrara salama"]'::jsonb, FALSE, 'L2'),
  ('006daa24-adf6-52e2-60c8-09759e721460', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame Brianza DOP', '["Salame Brianza DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard salami from Brianza area, fine to medium-coarse grain, balanced lean-fat ratio, delicate sweet-salty profile with light pepper and garlic, mild wine undertones; often less spicy than southern Italian salami.', 'Sliced for Lombard salumi boards with Mortadella and Bresaola; layered in panini; cubed for aperitivo platters.', '["whole-piece-vacuum-700g-1.5kg", "half-piece-vacuum-500g", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Brianza salami", "Salame della Brianza"]'::jsonb, FALSE, 'L2'),
  ('a06f09d3-c658-bab3-0bc5-b43dda5e924d', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame Cremona IGP', '["Salame Cremona IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lombard salami, soft texture from finely-ground meat and ample fat, mild sweet-savory pork flavor with garlic and white wine notes, gentle pepper.', 'Sliced for Lombard antipasto; paired with Grana Padano and mostarda di Cremona; cubed for aperitivo.', '["whole-piece-vacuum-700g-1.5kg", "half-piece-vacuum-500g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Cremona salami", "Salame cremonese"]'::jsonb, FALSE, 'L2'),
  ('4e63b49e-ab94-027e-3636-d182ed0d4c39', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame di Varzi DOP', '["Salame di Varzi DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Pavese salami from Oltrepò mountains, aged minimum 45 days. Coarse grain, rich red meat with white fat, robust pork flavor with garlic and red wine, peppercorns visible throughout.', 'Sliced for Lombard antipasto; paired with Oltrepò Pavese wines and aged formaggi; component in panini.', '["whole-piece-vacuum-500g-1.5kg", "half-piece-vacuum-500g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Varzi salami", "Salame varzese"]'::jsonb, FALSE, 'L2'),
  ('f9acbb30-ee59-0e72-d97f-3096a9c89a31', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame d''oca di Mortara IGP', '["Salame d''oca di Mortara IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lombard cooked goose-and-pork salami from Mortara (Pavia province). Finely-ground rich texture, distinctive deep flavor of cooked goose meat blended with pork, mild wine and spice notes, soft mouthfeel.', 'Sliced for Lombard antipasto, especially in Pavese restaurants; component of Mortara goose festival menus; paired with mostarda and aged Grana.', '["whole-piece-vacuum-500g-1kg", "deli-sliced-vacuum-100g"]'::jsonb, '[10, 11, 12]'::jsonb, '["Salame d''oca", "Mortara goose salami"]'::jsonb, FALSE, 'L2'),
  ('f20bd373-6ab3-7217-1a72-d0257cee2678', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame Felino IGP', '["Salame Felino IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Parma-area salami with distinct elongated flask shape, medium grain. Sweet delicate pork flavor balanced by sea salt, white wine, and garlic; aromatic but not spicy; soft texture with even fat distribution.', 'Sliced for Emilian charcuterie boards with Prosciutto di Parma and Coppa; classically paired with torta fritta (gnocco fritto); aperitivo with Lambrusco.', '["whole-piece-vacuum-700g-1.2kg", "half-piece-vacuum-500g", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Felino salami", "Salame felinese"]'::jsonb, FALSE, 'L2'),
  ('9e6d9c35-51fb-5701-1ff7-426ba350bd86', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame Piacentino DOP', '["Salame Piacentino DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Emilian salami, coarse grain with visible peppercorns, balanced sweet-savory flavor with garlic and red wine, longer aging (minimum 45 days) gives drier firmer texture and concentrated flavor.', 'Sliced for Piacentino salumi platter (with Coppa and Pancetta Piacentina DOP); paired with chiosotto and Gutturnio wine.', '["whole-piece-vacuum-700g-1kg", "half-piece-vacuum-500g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Piacentino salami", "Salame piacentino"]'::jsonb, FALSE, 'L2'),
  ('c289b52e-ee46-28ce-d8ee-a6f08c75eeb3', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame Piemonte IGP', '["Salame Piemonte IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Piedmontese salami flavored with red wine (typically Barbera or Dolcetto) and garlic. Medium-coarse grain, rich savory pork flavor with distinct vinous undertones, balanced spicing with pepper and nutmeg.', 'Sliced for Piedmontese antipasto with grissini Torinesi and tonneé; paired with Castelmagno and Gorgonzola; layered in panini.', '["whole-piece-vacuum-500g-1.2kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Piedmont salami", "Salame piemontese"]'::jsonb, FALSE, 'L2'),
  ('af00dbff-531d-08dd-5a32-b3db4957eaa9', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salame Sant''Angelo IGP', '["Salame Sant''Angelo IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Sicilian salami from Sant''Angelo di Brolo (Messina province), characterized by hand-cut meat (not ground), aged in mountain conditions. Coarse rustic texture, robust pork flavor.', 'Sliced for Sicilian antipasto; paired with Pecorino Siciliano and capers di Pantelleria.', '["whole-piece-vacuum-500g-1kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Sant''Angelo salami"]'::jsonb, TRUE, 'L2'),
  ('1858674f-b575-4d8e-c606-332a03ec626d', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salamini italiani alla cacciatora DOP', '["Salamini italiani alla cacciatora DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Small "hunter''s" salamis (about 80g each), portion-sized for trail consumption. Pure pork, garlic and pepper, balanced spicing without strong regional accent; firm dry texture.', 'Whole salamino as charcuterie board centerpiece (cut tableside); sliced for panini and aperitivo; popular for picnic and outdoor catering.', '["single-piece-80g", "twin-pack-160g", "multipack-vacuum-400g", "deli-bulk-2-3kg"]'::jsonb, '[]'::jsonb, '["Cacciatorino", "Cacciatore", "Cacciatorini"]'::jsonb, FALSE, 'L2'),
  ('9d5b66eb-02eb-faa0-5cf4-2408aaa3c473', 'IT', 'Italy', 'cured_meats_charcuterie', 'Salsiccia di Calabria DOP', '["Salsiccia di Calabria DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian fresh and cured pork sausage flavored with chili and pepper. Spicy assertive profile, rustic texture.', 'Cured form sliced for southern Italian antipasto; fresh form grilled or used in pasta with peperoni cruschi.', '["whole-piece-vacuum-300-500g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Salsiccia calabrese"]'::jsonb, TRUE, 'L2'),
  ('2d967d18-504b-e091-91b4-a1a7e5c3e7ef', 'IT', 'Italy', 'cured_meats_charcuterie', 'Soppressata di Calabria DOP', '["Soppressata di Calabria DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian flat-pressed salami with chili and paprika. Coarse grain visible chunks of fat and lean, fiery-spicy with sweet pepper undertones, robust pork base flavor, firm texture.', 'Sliced for Calabrian salumi boards; component in spicy pasta sauces; layered in pizza calabrese with ''nduja.', '["whole-piece-vacuum-400-700g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Soppressata calabrese", "Sopressata", "Suppressata"]'::jsonb, FALSE, 'L2'),
  ('53babaa2-8291-c8b4-c136-6881a6147e52', 'IT', 'Italy', 'cured_meats_charcuterie', 'Soprèssa Vicentina DOP', '["Soprèssa Vicentina DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Veneto large-format aged salami from Vicenza area. Mild sweet pork flavor with garlic, pepper, cloves, soft texture from extended aging.', 'Sliced for Vicentino antipasto with polenta and aged Asiago; paired with Soave or Bardolino wines.', '["whole-piece-vacuum-1.5-3kg", "half-piece-vacuum-1kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Soprèssa", "Soppressa veneta", "Vicentina soprèssa"]'::jsonb, TRUE, 'L2'),
  ('ea99a839-7d73-059e-611d-07ea8e3327a1', 'IT', 'Italy', 'cured_meats_charcuterie', 'Speck Alto Adige IGP', '["Speck Alto Adige IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'South-Tyrolean lightly-smoked aged ham, deep dark-red lean with thin fat cap, balanced salt-smoke flavor, aromatic with juniper, bay leaf, rosemary; firmer denser texture than Parma due to combined dry-cure plus cold-smoke plus aging.', 'Sliced thin for South-Tyrolean and Alpine antipasto; paired with rye bread, horseradish, and pickles; classic ingredient in Tyrolean Knödel and Tirtlan.', '["whole-piece-bone-in-4-5kg", "whole-piece-boneless-vacuum-3-4kg", "half-piece-vacuum-1.5kg", "deli-sliced-vacuum-100g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Speck dell''Alto Adige", "Südtiroler Markenspeck", "Südtiroler Speck", "Tyrolean speck"]'::jsonb, FALSE, 'L2'),
  ('b478f80a-2382-c378-2f0d-f111c5e5c6af', 'IT', 'Italy', 'cured_meats_charcuterie', 'Valle d''Aosta Jambon de Bosses DOP', '["Valle d''Aosta Jambon de Bosses DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Alpine dry-cured ham from Saint-Rhémy-en-Bosses at 1600m altitude, aged with mountain herbs (juniper, sage, rosemary, garlic). Dense dark-red meat, intense aromatic mountain herb profile, robust salt-aged character.', 'Sliced thin for Alpine antipasto; paired with Fontina DOP and dark rye breads; centerpiece of Valdostan tagliere.', '["whole-leg-bone-in-7-9kg", "half-leg-vacuum-3-4kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Jambon de Bosses", "Bosses ham", "Saint-Rhémy ham"]'::jsonb, FALSE, 'L2'),
  ('90679fb7-ac58-5099-359d-fe73f6c8ff59', 'IT', 'Italy', 'cured_meats_charcuterie', 'Valle d''Aosta Lard d''Arnad DOP', '["Valle d''Aosta Lard d''Arnad DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Pure cured pork back-fat from Arnad village, brined with rosemary, sage, garlic, juniper berries. Translucent ivory color, intensely aromatic mountain-herb flavor, silky cool melt-in-mouth texture distinct from Lardo di Colonnata.', 'Sliced thin laid on warm rye bread or Valdostan focaccia; paired with chestnut honey; rolled around grilled mountain trout.', '["slab-vacuum-400g-1kg", "deli-sliced-vacuum-80g", "pre-sliced-tray-100g"]'::jsonb, '[]'::jsonb, '["Lard d''Arnad", "Lardo di Arnad", "Arnad lardo"]'::jsonb, FALSE, 'L2'),
  ('82ef6e63-cc79-90f7-bdf1-8128b22c7fa0', 'IT', 'Italy', 'cured_meats_charcuterie', 'Zampone Modena IGP', '["Zampone Modena IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Stuffed pig''s trotter with seasoned pork mixture, traditionally cooked. Crisp gelatinous skin exterior, soft pork-and-rind interior, warm spice profile (clove, cinnamon, nutmeg, pepper) similar to Cotechino but earthier.', 'Boiled and sliced into rounds (showing trotter cross-section), traditional New Year''s Eve service with lentils; tasting menu component for regional Emilian themed dinners.', '["vacuum-pack-pre-cooked-700-1kg", "vacuum-pack-raw-1kg", "gift-tin-1kg"]'::jsonb, '[11, 12, 1]'::jsonb, '["Zampone", "Modena zampone"]'::jsonb, FALSE, 'L2'),
  ('9ab2b3eb-d2bb-9277-76f4-d2621175f0a3', 'IT', 'Italy', 'cheeses_dairy', 'Asiago DOP', '["Asiago DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Two distinct styles. Asiago Pressato (fresh, 20-40 days): ivory-white, soft elastic texture, mild milky-buttery flavor, slight grass-and-yogurt notes. Asiago d''Allevo (aged, 4-24+ months): straw-yellow, firmer crumbly texture, intense savory-nutty flavor with grassy alpine notes that deepen with age.', 'Pressato in panini, melted in fondues, on cheese boards as fresh option; d''Allevo grated over polenta and pasta, served on cheese boards, paired with honey and walnuts.', '["wheel-full-8-12kg", "wheel-half-4-6kg", "wedge-vacuum-1kg", "wedge-vacuum-200g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Asiago Pressato", "Asiago d''Allevo", "Asiago Stravecchio", "Asiago Mezzano", "Asiago Vecchio"]'::jsonb, FALSE, 'L2'),
  ('03466b87-74c3-4c46-faaf-6375cfe8cb7f', 'IT', 'Italy', 'cheeses_dairy', 'Bitto DOP', '["Bitto DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard alpine cow-and-goat milk cheese from Valtellina summer pastures, aged minimum 70 days. Straw-yellow paste, firm with small irregular eyes, rich intense aromatic flavor evolving from milky-grassy young to nutty-spicy when aged years.', 'Centerpiece of Valtellina cheese boards; classic ingredient in Pizzoccheri della Valtellina IGP; aged extra-vecchio paired with chestnut honey or Sforzato di Valtellina wine.', '["wheel-full-8-25kg", "wheel-half-4-12kg", "wedge-vacuum-1kg", "wedge-vacuum-300g"]'::jsonb, '[6, 7, 8, 9]'::jsonb, '["Bitto storico", "Bitto della Valtellina"]'::jsonb, FALSE, 'L2'),
  ('6f6e16aa-3e93-4f01-43b5-1c0e26206c35', 'IT', 'Italy', 'cheeses_dairy', 'Bra DOP', '["Bra DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese cow''s milk cheese from Cuneo area in two styles. Bra Tenero (fresh, 45 days): pale yellow, soft yielding texture, mild lactic flavor with grassy notes. Bra Duro (aged 6+ months): straw-yellow firmer paste, intense piquant savory flavor with grassy bite.', 'Tenero on Piedmontese cheese boards and in fondues; Duro grated over agnolotti and tajarin pasta; both paired with Barbera or Dolcetto wines.', '["wheel-full-6-9kg", "wheel-half-3-4kg", "wedge-vacuum-500g", "wedge-vacuum-200g"]'::jsonb, '[]'::jsonb, '["Bra Tenero", "Bra Duro"]'::jsonb, FALSE, 'L2'),
  ('abafaae2-470b-a4c7-8801-5d3c1f853f5d', 'IT', 'Italy', 'cheeses_dairy', 'Burrata di Andria IGP', '["Burrata di Andria IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Apulian fresh mozzarella pouch filled with stracciatella (cream-soaked cheese strands). Bright white exterior, oozing rich cream-and-curds interior, fresh milky-sweet flavor, lush silky-creamy texture; must be eaten within 2-4 days of production.', 'Centerpiece of southern Italian antipasto, served whole on plate to be cut tableside, drizzled with EVOO and torn basil; paired with prosciutto, ripe tomato, or grilled eggplant; not for cooking.', '["single-piece-100g", "single-piece-200g", "single-piece-300g", "twin-pack-200g", "bulk-tray-3kg"]'::jsonb, '[4, 5, 6, 7, 8, 9]'::jsonb, '["Burrata", "Andria burrata"]'::jsonb, FALSE, 'L2'),
  ('d13fa115-739a-5ab5-a9d9-b25ae8618c1c', 'IT', 'Italy', 'cheeses_dairy', 'Caciocavallo Silano DOP', '["Caciocavallo Silano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Southern Italian pasta filata cow''s milk cheese with characteristic teardrop/horse-saddle shape. Pale yellow paste, firm but elastic, rich savory-buttery flavor evolving with age; younger versions milky-mild, aged versions sharp-piquant.', 'Sliced fresh on cheese boards; aged grated over orecchiette and rustic pasta; melted over warm focaccia; classic in southern Italian frittate.', '["whole-piece-1-2.5kg", "half-piece-vacuum-700g", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Caciocavallo", "Caciocavallo del Sud"]'::jsonb, FALSE, 'L2'),
  ('8a6bb589-9a3e-8389-993b-392547f65df6', 'IT', 'Italy', 'cheeses_dairy', 'Canestrato di Moliterno IGP', '["Canestrato di Moliterno IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lucanian sheep-and-goat milk cheese aged in fondaco cellars. Pale ivory paste, firm with small eyes, intense savory tangy flavor with goaty edge and herbal notes from grazing flora.', 'Sliced for Lucanian cheese boards; grated over orecchiette with Lucanica di Picerno and peperoni cruschi; paired with local honey.', '["whole-piece-2-5kg", "half-piece-vacuum-1kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Canestrato lucano", "Moliterno cheese"]'::jsonb, FALSE, 'L2'),
  ('30e69443-f9bc-f3bd-d46a-bd7ff50dab16', 'IT', 'Italy', 'cheeses_dairy', 'Canestrato Pugliese DOP', '["Canestrato Pugliese DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian sheep''s milk cheese aged in canestro (woven baskets) leaving distinctive pattern. Straw-yellow paste, firm dry texture, intense salty-tangy flavor with grass-and-thyme notes.', 'Sliced for southern Italian cheese boards; grated over Apulian orecchiette; paired with fava bean purée and local olive oil.', '["whole-piece-7-14kg", "half-piece-vacuum-3kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Canestrato", "Apulian canestrato"]'::jsonb, FALSE, 'L2'),
  ('24054be8-b313-10ec-7cc3-29f5303fc770', 'IT', 'Italy', 'cheeses_dairy', 'Casatella Trevigiana DOP', '["Casatella Trevigiana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Veneto fresh cow''s milk cheese with very short aging (4-10 days). Bright white, soft creamy melting texture, fresh sweet milky flavor with delicate yogurt tang.', 'Spread on warm bread or polenta; ingredient in Veneto risi e bisi service; component of fresh-cheese platters; melted over cooked vegetables.', '["wheel-small-200-300g", "wheel-medium-500g-1kg", "tub-spreadable-200g"]'::jsonb, '[]'::jsonb, '["Casatella", "Casatella veneta"]'::jsonb, FALSE, 'L2'),
  ('de9caf49-4437-db08-a7fd-9be38cd5320d', 'IT', 'Italy', 'cheeses_dairy', 'Casciotta d''Urbino DOP', '["Casciotta d''Urbino DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Marchigiano sheep-and-cow milk semi-hard cheese (small wheels), aged 15-30 days. Pale ivory, soft yielding texture, mild sweet-grassy flavor with delicate tangy finish.', 'Sliced for central-Italian cheese boards; paired with truffle honey and salumi; component of Marche tagliere.', '["whole-wheel-1kg", "wheel-half-vacuum-500g", "wedge-vacuum-200g"]'::jsonb, '[]'::jsonb, '["Casciotta urbinate", "Urbino cheese"]'::jsonb, FALSE, 'L2'),
  ('826ac470-b411-99b5-8113-17c2fd87e7c6', 'IT', 'Italy', 'cheeses_dairy', 'Castelmagno DOP', '["Castelmagno DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese cow-(and sometimes goat/sheep) milk blue-veined alpine cheese, aged 60-180+ days. Crumbly white-yellow paste with natural blue veining when extra-aged, intense complex flavor combining alpine herbs, mushroom notes, and gentle blue piquancy.', 'Centerpiece of Piedmontese cheese course; classic with chestnut honey and walnut bread; melted into Castelmagno fonduta with truffle.', '["wheel-full-2-7kg", "wheel-half-1-3kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Castelmagno della Valle Grana", "Alpeggio Castelmagno"]'::jsonb, FALSE, 'L2'),
  ('0f0a9301-041d-53b7-3d76-436ab160b772', 'IT', 'Italy', 'cheeses_dairy', 'Fiore Sardo DOP', '["Fiore Sardo DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sardinian raw sheep''s milk hard cheese, traditionally smoked over juniper, aged 3-12+ months. Straw-yellow to amber paste, firm crumbly texture, intense aromatic flavor combining sheep-milk savor, smoke notes, and Mediterranean herb hints.', 'Centerpiece of Sardinian cheese boards; grated over malloreddus and culurgiones; classic ingredient in pesto Genovese (traditional recipe); paired with myrtle berry preserve.', '["wheel-full-1.5-4kg", "wheel-half-vacuum-1kg", "wedge-vacuum-300g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Fiore Sardo dei pastori", "Sardinian fiore"]'::jsonb, FALSE, 'L2'),
  ('3d30b250-40d7-6cc7-5e4d-f32e24ce63d8', 'IT', 'Italy', 'cheeses_dairy', 'Fontina DOP', '["Fontina DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aostan cow''s milk semi-soft cheese aged 80+ days. Pale straw paste, smooth elastic with small eyes, sweet melting buttery-nutty flavor with alpine grass and herb notes that intensify with age.', 'Essential melt cheese — Fonduta Valdostana, Fontina-stuffed crepes, baked into polenta concia; sliced on Alpine cheese boards; melted in panini.', '["wheel-full-8-12kg", "wheel-half-4-6kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "sliced-pre-pack-150g"]'::jsonb, '[]'::jsonb, '["Fontina valdostana", "Fontina d''Aosta", "Fontina alpina"]'::jsonb, FALSE, 'L2'),
  ('86bf6be4-f026-cd28-27c6-4d4d0fbe371a', 'IT', 'Italy', 'cheeses_dairy', 'Formaggella del Luinese DOP', '["Formaggella del Luinese DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard goat''s milk cheese from Lago Maggiore, aged 20-30 days. Pale ivory paste, soft buttery texture, mild fresh goat flavor with grassy notes and clean lactic finish, less pungent than aged goat cheeses.', 'Sliced on Lombard cheese boards; spread on warm crostini with honey; component of risotto al formaggio; paired with light wines.', '["small-wheel-300-700g", "half-wheel-vacuum-300g", "wedge-vacuum-200g"]'::jsonb, '[]'::jsonb, '["Luinese", "Luino goat cheese"]'::jsonb, FALSE, 'L2'),
  ('9eed1f3e-796f-4c48-041d-77360801a753', 'IT', 'Italy', 'cheeses_dairy', 'Formaggio di Fossa di Sogliano DOP', '["Formaggio di Fossa di Sogliano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Pit-aged Romagnolo sheep''s-cow''s milk cheese, buried in tufa-stone pits for 80-100 days. Irregular crumbly amber paste, intensely aromatic with earthy mushroom and damp-cellar notes, complex umami-piquant flavor unlike any other Italian cheese.', 'Centerpiece of Romagnolo cheese course (revealed at the November "Sfossatura"); classic with saba (cooked grape must), fig jam, or chestnut honey; small slivers on tasting menus.', '["whole-piece-1-2kg", "half-piece-vacuum-700g", "wedge-vacuum-200g", "gift-pack-300g"]'::jsonb, '[11, 12, 1, 2]'::jsonb, '["Fossa", "Fossa di Sogliano", "Fossa cheese"]'::jsonb, FALSE, 'L2'),
  ('422b30c0-4ffa-78d4-bae9-afd3c8752795', 'IT', 'Italy', 'cheeses_dairy', 'Formai de Mut dell''Alta Valle Brembana DOP', '["Formai de Mut dell''Alta Valle Brembana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard alpine cow''s milk cheese from Brembana valley, aged 45-60+ days. Straw-yellow paste with small eyes, firm yielding texture, sweet-grassy alpine flavor that deepens to nutty-spicy with age.', 'Sliced on Bergamasco cheese boards; component of casoncelli filling; paired with honey and red Valcalepio wines.', '["wheel-full-8-12kg", "wheel-half-4-6kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[6, 7, 8, 9]'::jsonb, '["Formai de Mut", "Brembana mountain cheese"]'::jsonb, FALSE, 'L2'),
  ('2f714ae5-f26b-9aaa-ce59-99f4b05935f1', 'IT', 'Italy', 'cheeses_dairy', 'Gorgonzola DOP', '["Gorgonzola DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard cow''s milk blue cheese in two styles. Dolce: pale ivory with greenish-blue veining, soft creamy spreadable texture, mild sweet flavor with gentle blue tang. Piccante: firmer crumbly paste with prominent dark-blue veining, robust intense pungent flavor with sharp blue character.', 'Dolce melted into pasta sauces (Gorgonzola e noci), spread on warm polenta, drizzled with chestnut honey; Piccante crumbled on salads, paired with pears and walnuts on cheese boards, ingredient in risotto al Gorgonzola.', '["wheel-full-6-13kg", "wheel-half-3-7kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "crumbled-pre-pack-100g", "tub-spreadable-150g"]'::jsonb, '[]'::jsonb, '["Gorgonzola Dolce", "Gorgonzola Piccante", "Gorgonzola dolcelatte (commercial sub-style)"]'::jsonb, FALSE, 'L2'),
  ('5c603e4a-09e1-643e-8115-a06ee07e1b1e', 'IT', 'Italy', 'cheeses_dairy', 'Grana Padano DOP', '["Grana Padano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Po-valley aged cow''s milk hard cheese (granular). Pale straw paste with characteristic granular texture, savory-sweet umami flavor with notes of fresh fruit and butter, less intense than Parmigiano Reggiano; multiple aging tiers (9-16 mo, 16-20 mo Riserva, 20+ mo Riserva).', 'Grated on pasta and risotto; cubed for aperitivo and salads; shaved on carpaccio; chunks on cheese boards; melt-in for risotto alla milanese; lower price-point alternative to Parmigiano in volume operations.', '["wheel-full-32-44kg", "wheel-half-16-22kg", "wedge-vacuum-1kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g", "shaved-tray-100g"]'::jsonb, '[]'::jsonb, '["Grana", "Padano", "Grana Padano Riserva", "Trentingrana (sub-name from Trentino)"]'::jsonb, FALSE, 'L2'),
  ('a7d2783b-6d6b-d3bb-d1cf-860fe90e13e8', 'IT', 'Italy', 'cheeses_dairy', 'Montasio DOP', '["Montasio DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Friulian cow''s milk cheese in three aging tiers. Fresco (60-120 days): straw paste, mild sweet milky. Mezzano (5-10 mo): firmer, more savory with grassy notes. Stagionato (10+ mo): hard granular, intense umami-savory with piquant edge.', 'Fresco melted in Frico friulano; Mezzano on cheese boards; Stagionato grated over polenta and Friulian gnocchi; classic with prosciutto di San Daniele.', '["wheel-full-6-8kg", "wheel-half-3-4kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Montasio Fresco", "Montasio Mezzano", "Montasio Stagionato", "Stravecchio"]'::jsonb, FALSE, 'L2'),
  ('ba846c15-c947-d097-8064-59156335d803', 'IT', 'Italy', 'cheeses_dairy', 'Monte Veronese DOP', '["Monte Veronese DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Veneto cow''s milk semi-hard cheese from Lessinia mountains, two styles. Latte intero (fresh): pale ivory soft elastic, mild milky-sweet flavor. Allevo (aged 2-12+ mo): straw-yellow firm paste, savory-piquant alpine flavor with grass and herb notes.', 'Latte intero melted into Veneto polenta and risotto; Allevo grated on pasta and grated over bigoli con anatra; on cheese boards with mostarda di Cremona.', '["wheel-full-7-10kg", "wheel-half-3-5kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Monte Veronese latte intero", "Monte Veronese d''allevo"]'::jsonb, FALSE, 'L2'),
  ('d8d0d7f0-6cdb-6dc4-3840-5ba455605127', 'IT', 'Italy', 'cheeses_dairy', 'Mozzarella di Bufala Campana DOP', '["Mozzarella di Bufala Campana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian fresh buffalo-milk pasta filata cheese. Bright porcelain-white exterior, lush milky-cream interior, fresh sweet-tangy buffalo-milk flavor (richer and more complex than cow mozzarella), spongy elastic texture that releases milk when cut. Best within 24-48 hours of production.', 'Centerpiece of Caprese salad with Pomodoro San Marzano DOP and basil; on pizza Margherita; sliced on antipasto boards; paired with prosciutto and figs; not ideal for prolonged cooking (becomes rubbery).', '["single-ball-100g", "single-ball-125g", "single-ball-200g", "single-ball-250g", "single-ball-500g", "twin-pack-250g", "bulk-tray-3kg", "mini-bocconcini-150g", "treccia-braid-200g"]'::jsonb, '[]'::jsonb, '["Mozzarella di bufala", "Buffalo mozzarella", "Mozzarella DOP", "Bufala campana"]'::jsonb, FALSE, 'L2'),
  ('c2a969f5-cfb7-b289-81e1-0683f5c075bd', 'IT', 'Italy', 'cheeses_dairy', 'Mozzarella di Gioia del Colle DOP', '["Mozzarella di Gioia del Colle DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian cow''s-milk mozzarella from Murge plateau, traditional pasta filata. Porcelain-white, soft fresh texture, mild milky-sweet flavor distinct from buffalo (less rich, more delicate); newer DOP than Bufala Campana.', 'Sliced for southern-Italian Caprese alternative; melted on rustic pizzas (especially in Apulian focacceria); component of frittate.', '["single-ball-100g", "single-ball-200g", "twin-pack-250g", "bulk-tray-3kg", "mini-bocconcini-150g", "treccia-200g"]'::jsonb, '[]'::jsonb, '["Mozzarella di Gioia", "Gioia del Colle mozzarella"]'::jsonb, FALSE, 'L2'),
  ('9fc4964f-9c8c-3c17-604e-9e71e0d8a526', 'IT', 'Italy', 'cheeses_dairy', 'Murazzano DOP', '["Murazzano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese sheep''s milk fresh cheese (small wheels) from Langhe area. Bright white, soft creamy texture, mild fresh-yogurt flavor with delicate sheep-milk tang, light grassy notes.', 'On Langhe cheese boards alongside Castelmagno; classic ingredient in Bross (fermented cheese paste) traditional preparation; paired with truffle in season.', '["small-wheel-300-400g", "twin-pack-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Murazzano delle Langhe", "Toma di Murazzano"]'::jsonb, FALSE, 'L2'),
  ('3ffd379a-9d5c-68a0-b077-57a7d254e890', 'IT', 'Italy', 'cheeses_dairy', 'Nostrano Valtrompia DOP', '["Nostrano Valtrompia DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard alpine cow''s milk cheese from Trompia valley with saffron addition. Straw-yellow paste, firm aged texture, characteristic light saffron note over grassy alpine flavor.', 'Sliced for Brescia-area cheese boards; component of Bresciano risotto.', '["wheel-full-8-12kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[6, 7, 8, 9]'::jsonb, '["Nostrano della Valtrompia", "Valtrompia mountain cheese"]'::jsonb, TRUE, 'L2'),
  ('8c719164-e2f1-8484-f7b1-c1f78e24e95f', 'IT', 'Italy', 'cheeses_dairy', 'Parmigiano Reggiano DOP', '["Parmigiano Reggiano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Po-valley aged cow''s milk hard cheese (DOC since 1955, DOP since 1996). Crystalline granular texture with tyrosine crystals, intense umami flavor with notes of dried fruit, broth, brown butter, dried meadow flowers; sharp finish with pleasant piquancy. Aging tiers: 12 mo (mild), 18-24 mo (standard), 30+ mo (intense), 40+ mo (extra-aged premium).', 'Grated on pasta and risotto; shaved on salads, carpaccio, asparagus; chunks on cheese boards with aged balsamic and walnuts; rinds simmered into broths and risotto stocks; melted in fonduta and parmigiana base.', '["wheel-full-38-40kg", "wheel-half-19-20kg", "wheel-quarter-9-10kg", "wedge-vacuum-1kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "wedge-vacuum-150g", "grated-pre-pack-100g", "shaved-tray-100g", "gift-pack-aged-200g"]'::jsonb, '[]'::jsonb, '["Parmesan", "Parmesano", "Reggiano", "PR", "Parmigiano", "Parmigiano-Reggiano"]'::jsonb, FALSE, 'L2'),
  ('2de96d6f-a604-537a-b452-75a228604bf1', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino Crotonese DOP', '["Pecorino Crotonese DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian sheep''s milk cheese from Crotone area in three aging styles (fresh, semi-aged, aged). Pale ivory paste evolving to amber, firm yielding to crumbly texture, sheep-milk savor with grassy Calabrian-flora notes and peppery edge in aged.', 'Fresh on southern cheese boards; semi-aged in pasta with peperoncino; aged grated over rustic pasta with breadcrumbs; paired with bergamot honey.', '["wheel-full-2-5kg", "wheel-half-vacuum-1kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Pecorino crotonese", "Crotone pecorino"]'::jsonb, FALSE, 'L2'),
  ('01eac65b-f82c-a1d2-18b5-5b6a80dfeaf6', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino delle Balze Volterrane DOP', '["Pecorino delle Balze Volterrane DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan sheep''s milk cheese from Volterra cliffs, distinctive crystallized rind from local thistle rennet, aged 60+ days. Straw-yellow paste, firm texture, intense aromatic flavor with characteristic thistle-rennet bitter-floral note.', 'Sliced on Tuscan cheese boards; paired with fig jam and chestnut honey; centerpiece of Volterra-themed pairings.', '["wheel-full-1-2kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Pecorino di Volterra", "Volterra pecorino"]'::jsonb, FALSE, 'L2'),
  ('4eefeee7-37c3-c859-1d4f-a36ac55583dc', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino di Filiano DOP', '["Pecorino di Filiano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lucanian sheep''s milk cheese from Vulture mountain area, aged 180+ days. Pale ivory to amber paste, firm crumbly texture, intense savory-tangy flavor with herbal notes from local pasture (juniper, fennel, wild thyme).', 'Sliced on Lucanian cheese boards; grated over orecchiette; component of caciovino dishes; paired with Aglianico del Vulture wine.', '["wheel-full-2.5-5kg", "half-piece-vacuum-1kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Pecorino del Vulture", "Filiano pecorino"]'::jsonb, FALSE, 'L2'),
  ('6df60180-cd74-68cc-b9f1-ea2b8c587534', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino di Picinisco DOP', '["Pecorino di Picinisco DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio sheep''s milk cheese from Comino valley, aged 30-150 days. Pale ivory paste with small eyes, supple to firm texture, sweet sheep-milk flavor with mountain-herb notes (rosemary, thyme, juniper).', 'On central-Italian cheese boards; component of Lazio carbonara variations; paired with chestnut honey; melted into mountain pasta dishes.', '["wheel-full-700g-2.5kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Picinisco pecorino", "Comino valley pecorino"]'::jsonb, FALSE, 'L2'),
  ('c7c89c7e-c775-b270-01f4-9dafca196c54', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino Romano DOP', '["Pecorino Romano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Salt-rich sheep''s milk hard cheese from Lazio and Sardinia, aged minimum 5 months (Romano), 8+ months (extra-aged). Bone-white to straw paste, hard crumbly texture, intensely savory and salty flavor with sharp piquant finish — saltier than Parmigiano.', 'Essential grated cheese for Roman pasta classics — Cacio e Pepe, Carbonara, Amatriciana, Gricia; shaved on artichoke salads; pairs with peppery wines (Cesanese, Lazio reds).', '["wheel-full-22-33kg", "wheel-half-12-16kg", "wedge-vacuum-1kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Pecorino Romano", "Romano cheese"]'::jsonb, FALSE, 'L2'),
  ('54fe921e-4fd1-241d-646f-41e75dfb7260', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino Sardo DOP', '["Pecorino Sardo DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sardinian sheep''s milk cheese in two styles. Dolce (20-60 days): pale ivory soft paste, mild milky-sweet flavor. Maturo (60+ days, often 6 mo+): firmer amber paste, intense savory-tangy with grassy-herbal Mediterranean notes.', 'Dolce on cheese boards with myrtle preserve; Maturo grated on Sardinian pasta (malloreddus, fregula); component of seadas (fried cheese pastry); paired with Cannonau wine.', '["wheel-full-1.5-4kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Pecorino Sardo Dolce", "Pecorino Sardo Maturo", "Sardinian pecorino"]'::jsonb, FALSE, 'L2'),
  ('cf821daa-3bd5-c1bf-e5c1-c18afb58848b', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino Siciliano DOP', '["Pecorino Siciliano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian sheep''s milk cheese, aged 4+ months, traditionally with peppercorns embedded. Straw-yellow paste, firm crumbly, intense robust flavor with sheep-milk savor and pepper-spice accent; among Italy''s oldest cheeses (mentioned by Homer).', 'Sliced on Sicilian cheese boards; grated over pasta alla Norma and rustic Sicilian pasta; paired with Modica chocolate and orange marmalade; classic with Marsala-pairing.', '["wheel-full-4-12kg", "wheel-half-vacuum-2kg", "wedge-vacuum-300g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Pecorino Siciliano", "Pecorino al pepe (peppered version)", "Tuma (very fresh sub-style)"]'::jsonb, FALSE, 'L2'),
  ('cb55f48f-6178-f58e-e634-97ae39854c75', 'IT', 'Italy', 'cheeses_dairy', 'Pecorino Toscano DOP', '["Pecorino Toscano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan sheep''s milk cheese in fresh and aged styles. Fresco (20+ days): pale ivory soft elastic paste, mild sweet milky flavor. Stagionato (4+ months): firmer straw paste, savory-aromatic with grass-and-herb notes; less intense than Pecorino Romano.', 'Fresco on Tuscan cheese boards (with Prosciutto Toscano); Stagionato grated over Tuscan pasta (pici); paired with chestnut honey, fig jam, or Vin Santo.', '["wheel-full-1-3.5kg", "wedge-vacuum-300g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Pecorino Toscano Fresco", "Pecorino Toscano Stagionato", "Tuscan pecorino"]'::jsonb, FALSE, 'L2'),
  ('e7578101-d091-74df-f08a-512ff222cfe9', 'IT', 'Italy', 'cheeses_dairy', 'Piacentinu Ennese DOP', '["Piacentinu Ennese DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian sheep''s milk cheese from Enna with characteristic saffron infusion and embedded peppercorns. Vivid yellow paste, firm crumbly texture, sheep-milk flavor enhanced by floral saffron and pepper warmth — distinctive aromatic profile.', 'Sliced on Sicilian cheese boards as visual centerpiece; grated over Sicilian rustic pasta; paired with citrus marmalade; component of Sicilian-themed tasting menus.', '["wheel-full-3-5kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Piacentinu di Enna", "Sicilian saffron pecorino"]'::jsonb, FALSE, 'L2'),
  ('788b3ab7-4214-f126-4094-e3f0e10b56e9', 'IT', 'Italy', 'cheeses_dairy', 'Piave DOP', '["Piave DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Veneto cow''s milk cheese from Belluno mountains in five aging tiers (fresh 20-60 days through Vecchio Riserva 18+ months). Pale ivory young, deep amber when aged. Texture firm to granular. Flavor evolves from buttery-mild to intensely savory-sweet with caramel and dried-fruit notes.', 'Younger versions on cheese boards and in panini; aged Vecchio grated like Parmigiano on pasta and risotto; classic with truffle honey.', '["wheel-full-6-7kg", "wheel-half-vacuum-3kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Piave Fresco", "Piave Mezzano", "Piave Vecchio", "Piave Vecchio Riserva", "Piave Vecchio Selezione Oro"]'::jsonb, FALSE, 'L2'),
  ('f7ff581a-bde9-de76-dd4b-b41fd6bf3734', 'IT', 'Italy', 'cheeses_dairy', 'Provola dei Nebrodi DOP', '["Provola dei Nebrodi DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian pasta filata cow''s milk cheese from Nebrodi mountains. Pale yellow paste, smooth elastic texture, mild milky-savory flavor with grassy mountain notes; younger versions sweeter, aged more intense.', 'Sliced on Sicilian cheese boards; melted on rustic Sicilian preparations.', '["whole-piece-1-3kg", "half-piece-vacuum-700g"]'::jsonb, '[]'::jsonb, '["Provola dei Nebrodi", "Nebrodi provola"]'::jsonb, TRUE, 'L2'),
  ('9b6b6b93-f407-323c-2018-4375d192dacf', 'IT', 'Italy', 'cheeses_dairy', 'Provolone del Monaco DOP', '["Provolone del Monaco DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian aged cow''s milk pasta filata cheese from Sorrento peninsula, aged 6-18+ months. Straw-yellow to amber paste, firm hard texture, robust spicy-savory flavor with tangy umami notes and lingering piquant finish.', 'Sliced for Campanian cheese boards; grated over rustic pasta; paired with Lacryma Christi wine; melted in regional preparations.', '["whole-piece-2.5-8kg", "half-piece-vacuum-1.5kg", "wedge-vacuum-300g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Provolone del Monaco", "Sorrento provolone"]'::jsonb, FALSE, 'L2'),
  ('11c11d85-3d9e-ed83-d04b-33673250194c', 'IT', 'Italy', 'cheeses_dairy', 'Provolone Valpadana DOP', '["Provolone Valpadana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Po-valley pasta filata cow''s milk cheese in two styles: Dolce (2-3 months, mild buttery sweet) and Piccante (3+ months with lipase, sharp spicy aged). Pale yellow to amber, smooth firm texture, characteristic provolone tang.', 'Dolce sliced on cheese boards, melted in panini; Piccante grated over rustic pasta, paired with cured meats; both classic in northern Italian antipasti.', '["whole-piece-1-100kg", "half-piece-vacuum-1-5kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "sliced-pre-pack-150g"]'::jsonb, '[]'::jsonb, '["Provolone", "Provolone Dolce", "Provolone Piccante", "Provolone Valpadana"]'::jsonb, FALSE, 'L2'),
  ('2134cf88-8922-4a85-ae8b-af23b5187d62', 'IT', 'Italy', 'cheeses_dairy', 'Puzzone di Moena DOP', '["Puzzone di Moena DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trentino "stinky" cow''s milk washed-rind cheese, aged 90+ days with regular salt-water washing. Reddish-brown rind, ivory paste, intensely pungent aroma with farmyard notes, paradoxically mild creamy savory flavor on palate.', 'Centerpiece of Trentino cheese course; classic with chestnut honey; melted into polenta concia; paired with Teroldego wine.', '["wheel-full-9-10kg", "wheel-half-vacuum-4-5kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Puzzone", "Spretz Tzaorì (Ladin name)"]'::jsonb, FALSE, 'L2'),
  ('e7376db4-99e2-7bce-65fe-2ab68fae2c33', 'IT', 'Italy', 'cheeses_dairy', 'Quartirolo Lombardo DOP', '["Quartirolo Lombardo DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard cow''s milk fresh cheese (5-30 days) — Maggengo "fresh" or Vecchio (30+ days). Square white-yellow wheels with thin rind, soft yielding paste, mild lactic flavor with grassy-fresh notes; aged versions develop savory-piquant edge.', 'Fresco sliced on cheese boards, melted in risotto; Vecchio paired with mostarda di Cremona, walnut bread, or honey; spread on crostini.', '["wheel-full-1.5-3.5kg", "wheel-half-vacuum-1kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Quartirolo", "Quartirolo Maggengo", "Quartirolo Vecchio"]'::jsonb, FALSE, 'L2'),
  ('60af826a-4015-4ea1-9610-92e144089940', 'IT', 'Italy', 'cheeses_dairy', 'Ragusano DOP', '["Ragusano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian cow''s milk pasta filata cheese, distinctive parallelepiped (rectangular) shape, aged 3-12 months. Pale yellow to amber paste, firm dense texture, savory milky-sweet flavor evolving to intense piquant when aged 12+ months.', 'Sliced on Sicilian cheese boards; grated over rustic Sicilian pasta and arancini; paired with Modica chocolate; component of caponata service.', '["whole-piece-10-16kg", "half-piece-vacuum-5kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Caciocavallo Ragusano (historical)", "Ragusan provolone"]'::jsonb, FALSE, 'L2'),
  ('b640cb96-53ea-ce1b-b48f-c5a1900dc07a', 'IT', 'Italy', 'cheeses_dairy', 'Raschera DOP', '["Raschera DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese cow''s milk cheese (with possible sheep/goat addition) from Cuneo area. Aged 30-60+ days. Pale yellow paste with small eyes, soft yielding texture, mild grassy-milky flavor with delicate herbaceous notes; alpine d''Alpeggio sub-style is more intense.', 'Sliced on Piedmontese cheese boards alongside Castelmagno; melted in fonduta; component of regional pasta dishes.', '["wheel-full-7-9kg", "wheel-half-vacuum-3kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Raschera d''Alpeggio (alpine sub-style)"]'::jsonb, FALSE, 'L2'),
  ('704d2fd3-cd72-0920-cedd-31f77cca37ae', 'IT', 'Italy', 'cheeses_dairy', 'Ricotta di Bufala Campana DOP', '["Ricotta di Bufala Campana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Fresh whey-cheese from buffalo milk (whey of Mozzarella di Bufala production). Bright white, soft delicate texture, fresh sweet-creamy flavor distinctly richer than cow ricotta, slight buffalo-milk character.', 'Centerpiece of Campanian dessert course (with honey, candied fruit); filling for cannelloni and ravioli; in cassata and pastiera; spread on warm bread; whipped into mousses; can replace whipped cream in some applications.', '["tub-250g", "tub-500g", "tub-1kg", "tub-bulk-2kg"]'::jsonb, '[]'::jsonb, '["Ricotta di bufala", "Buffalo ricotta"]'::jsonb, FALSE, 'L2'),
  ('aea00706-eb27-580e-e3c3-299ee91be5b1', 'IT', 'Italy', 'cheeses_dairy', 'Ricotta Romana DOP', '["Ricotta Romana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio fresh whey ricotta from sheep''s milk. Bright white soft texture, fresh mild sheep-milk flavor with delicate sweetness, less rich than buffalo ricotta but more characterful than cow ricotta.', 'Filling for Roman ravioli and cannelloni; in maritozzi (cream-filled buns) and pastiera; sweet preparations with honey and cocoa; savory with herbs and pepper for crostini.', '["tub-250g", "tub-500g", "tub-1kg", "basket-fascella-300g"]'::jsonb, '[]'::jsonb, '["Ricotta romana", "Roman sheep ricotta"]'::jsonb, FALSE, 'L2'),
  ('bbddab64-b54e-8d7d-0d98-a559f6cede71', 'IT', 'Italy', 'cheeses_dairy', 'Robiola di Roccaverano DOP', '["Robiola di Roccaverano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese fresh goat''s milk cheese (sometimes blended with cow/sheep). Bright white soft creamy texture, fresh tangy goat-milk flavor with grassy-herbal notes; aged versions develop pungent surface mold.', 'Spread on warm crostini; component of antipasto with grissini and anchovies; whipped with herbs for canapés; paired with Moscato or Acquesi wines.', '["small-wheel-250-400g", "twin-pack-vacuum-200g", "tub-spreadable-150g"]'::jsonb, '[]'::jsonb, '["Robiola di Roccaverano", "Roccaverano cheese"]'::jsonb, FALSE, 'L2'),
  ('e0a7acc7-d82e-63c8-a7b5-defe769f8933', 'IT', 'Italy', 'cheeses_dairy', 'Salva Cremasco DOP', '["Salva Cremasco DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard cow''s milk cheese from Cremasco area, square cuboid shape, aged 75+ days. Pale ivory paste, smooth dense texture (denser than Quartirolo), savory-buttery flavor with light tang; traditional pairing with hot chili-pickled vegetables (Tighe).', 'Sliced on Lombard cheese boards; classic with Tighe pickles; melted in panini.', '["wheel-full-1.3-5kg", "wheel-half-vacuum-1.5kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Salva", "Salva del Cremasco"]'::jsonb, FALSE, 'L2'),
  ('249c41b8-f770-046a-9600-cfa10e9f564a', 'IT', 'Italy', 'cheeses_dairy', 'Silter DOP', '["Silter DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard alpine cow''s milk cheese from Camonica valley, aged 100+ days (semi-aged) to 12+ months (aged). Straw-yellow paste, firm semi-hard texture, savory-aromatic alpine flavor with mountain-grass and herbaceous notes; slightly less intense than Bitto.', 'Sliced on Bresciano cheese boards; grated over polenta and casoncelli; paired with Franciacorta wines.', '["wheel-full-10-16kg", "wheel-half-vacuum-5kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Silter della Valcamonica", "Camonica mountain cheese"]'::jsonb, FALSE, 'L2'),
  ('e7f605b5-619d-8570-34b7-19e718c27abb', 'IT', 'Italy', 'cheeses_dairy', 'Spressa delle Giudicarie DOP', '["Spressa delle Giudicarie DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trentino cow''s milk semi-hard cheese from Giudicarie valleys, aged 3+ months. Pale yellow paste, firm texture, mild grassy-savory alpine flavor.', 'Sliced on Trentino cheese boards; melted into polenta; paired with local cured meats.', '["wheel-full-7-10kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Spressa", "Giudicarie spressa"]'::jsonb, TRUE, 'L2'),
  ('23e2aaf4-e688-2ff1-08fa-91d05c954fcf', 'IT', 'Italy', 'cheeses_dairy', 'Squacquerone di Romagna DOP', '["Squacquerone di Romagna DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Romagnolo fresh cow''s milk cheese with very high moisture, almost runny consistency. Bright white, soft spreadable melting texture, fresh sweet-tangy lactic flavor with delicate creamy mouthfeel.', 'Spread on warm Piadina Romagnola IGP — the canonical pairing — often with prosciutto and rocket; component of Romagnolo antipasto; melted into pasta dishes.', '["tub-100g", "tub-250g", "tub-500g", "tub-bulk-1kg", "fresh-bag-250g"]'::jsonb, '[]'::jsonb, '["Squacquerone", "Squaquaron (dialect)"]'::jsonb, FALSE, 'L2'),
  ('f9e69c96-6bea-04f3-84bb-4a92cc67a1bc', 'IT', 'Italy', 'cheeses_dairy', 'Stelvio DOP', '["Stelvio DOP", "Stilfser DOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'South-Tyrolean cow''s milk semi-soft cheese, aged 60+ days. Pale yellow paste with small eyes and slightly sticky pinkish-brown washed rind, mild aromatic flavor with milky-sweet base and gentle savory edge.', 'Sliced on South-Tyrolean cheese boards; melted in Tyrolean Knödel; paired with rye bread and Speck Alto Adige; component of Alpine Brettljause platter.', '["wheel-full-8-10kg", "wheel-half-vacuum-4kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Stilfser", "Stilfser Käse", "South-Tyrolean Stelvio"]'::jsonb, FALSE, 'L2'),
  ('7569a1a0-3558-6d86-27e0-7412f0471fe2', 'IT', 'Italy', 'cheeses_dairy', 'Strachitunt DOP', '["Strachitunt DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard cow''s milk blue-veined cheese from Val Taleggio, traditional two-curd "two-paste" preparation. Pale ivory paste with natural blue-green veining, soft creamy texture, complex flavor combining Taleggio-like creaminess with mild blue tang and grassy alpine notes.', 'Centerpiece of Bergamasco cheese course; paired with chestnut honey or saba; component of cheese-board with regional cured meats.', '["wheel-full-3-6kg", "wheel-half-vacuum-1.5kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Strachitunt della Val Taleggio", "Bergamasco blue"]'::jsonb, FALSE, 'L2'),
  ('13aa22cc-78e2-97e0-c52c-5192adc0058e', 'IT', 'Italy', 'cheeses_dairy', 'Taleggio DOP', '["Taleggio DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard cow''s milk washed-rind square-shaped cheese, aged 35-40+ days. Salmon-pink rind, pale ivory paste, smooth supple to creamy texture, distinctive aroma stronger than flavor (which is mild fruity-savory with light tang).', 'Sliced on cheese boards; melted on warm polenta or risotto al Taleggio; classic with pears and walnuts; melted in panini and pizza variations; pairs with Franciacorta and Lambrusco.', '["wheel-full-1.7-2.2kg", "wheel-half-vacuum-1kg", "wedge-vacuum-300g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Taleggio della Val Taleggio", "Stracchino Taleggio (historical)"]'::jsonb, FALSE, 'L2'),
  ('16211907-9e37-aeca-45ad-63f4bfaff2af', 'IT', 'Italy', 'cheeses_dairy', 'Toma Piemontese DOP', '["Toma Piemontese DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Piedmontese cow''s milk cheese in fresh and aged versions. Fresh (15+ days): pale ivory soft paste, mild milky-grassy flavor. Aged (60+ days, including Toma di Lanzo and other sub-styles): straw-yellow firmer paste, intense alpine-herb savory flavor.', 'On Piedmontese cheese boards; melted in fonduta; component of regional pasta dishes; aged grated over agnolotti.', '["wheel-full-1.8-9kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Toma", "Toma del Piemonte", "Toma di Lanzo (geographic sub-style)"]'::jsonb, FALSE, 'L2'),
  ('bc0c48e2-ff82-ab04-a341-9e4b99c37be0', 'IT', 'Italy', 'cheeses_dairy', 'Valle d''Aosta Fromadzo DOP', '["Valle d''Aosta Fromadzo DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aostan cow''s milk cheese (sometimes with goat milk), traditional alpine cheese aged 60+ days to 12+ months. Pale yellow paste, semi-hard texture, mild buttery-grassy flavor evolving to savory-piquant with age and goat-milk tang.', 'Sliced on Valdostan cheese boards alongside Fontina; melted into Aostan polenta; component of regional preparations.', '["wheel-full-1-7kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Fromadzo", "Fromadzo valdostano"]'::jsonb, FALSE, 'L2'),
  ('754f5a04-a27c-f0c6-b3d5-dba9200e5166', 'IT', 'Italy', 'cheeses_dairy', 'Valtellina Casera DOP', '["Valtellina Casera DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard cow''s milk semi-skim cheese from Valtellina, aged 70+ days. Straw-yellow paste with small irregular eyes, firm yielding texture, mild milky-sweet flavor with grassy alpine notes; less intense than full-fat Bitto.', 'Essential ingredient in Pizzoccheri della Valtellina IGP and Sciatt; sliced on Valtellinese cheese boards; melted into polenta; paired with Bresaola della Valtellina.', '["wheel-full-7-12kg", "wheel-half-vacuum-3-5kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Casera", "Latteria Casera (historical)"]'::jsonb, FALSE, 'L2'),
  ('8297de58-0c58-98db-4317-0f3c0d3f0679', 'IT', 'Italy', 'cheeses_dairy', 'Vastedda della valle del Belìce DOP', '["Vastedda della valle del Belìce DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian sheep''s milk pasta filata cheese — uniquely the only sheep''s milk pasta filata in Italy. Disk shape, bright white, soft elastic texture, fresh sweet-tangy sheep-milk flavor.', 'Centerpiece of western Sicilian cheese boards; sliced fresh with EVOO and tomato; component of Sicilian antipasto.', '["disc-450-700g", "twin-pack-vacuum-500g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9]'::jsonb, '["Vastedda", "Belìce vastedda"]'::jsonb, TRUE, 'L2'),
  ('27133dcf-29ed-e53f-03f5-a6c326b6ec7d', 'IT', 'Italy', 'olive_oils_olives', 'Alto Crotonese DOP (olive oil)', '["Alto Crotonese DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian EVOO from Crotone uplands, predominantly Carolea cultivar. Medium-intense fruity profile, balanced bitter-pungent notes, characteristic green tomato leaf and almond flavors with subtle artichoke hints.', 'Finishing oil on grilled fish and vegetables, drizzled over Calabrian rustic dishes, pasta with peperoncino, raw on bruschetta.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L", "PET-canister-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio Alto Crotonese", "Crotone DOP"]'::jsonb, FALSE, 'L2'),
  ('25e5d87a-25a9-5efa-6cef-ef7f3298a159', 'IT', 'Italy', 'olive_oils_olives', 'Aprutino Pescarese DOP (olive oil)', '["Aprutino Pescarese DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Abruzzese EVOO from Pescara hills, Dritta and other local cultivars. Medium fruity intensity, balanced bitter and pungent finish, herbaceous notes of artichoke and grass with subtle almond.', 'Finishing oil on grilled meats (Abruzzese arrosticini), drizzled on legume soups, raw on bruschetta with garlic.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Aprutino", "Pescara DOP"]'::jsonb, FALSE, 'L2'),
  ('5d34b249-2717-f927-1a6d-b1e648f7601c', 'IT', 'Italy', 'olive_oils_olives', 'Brisighella DOP (olive oil)', '["Brisighella DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Romagnolo EVOO predominantly from Nostrana di Brisighella cultivar. Distinctive fruity-vegetal profile, balanced harmonious flavor with green-apple and almond notes, low pungency, very early harvest tradition gives bright herbal freshness.', 'Finishing oil on Romagnolo seafood (Adriatic fish), Piadina Romagnola IGP, fresh egg pasta, salads with Squacquerone di Romagna.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Brisighello", "Brisighella oil"]'::jsonb, FALSE, 'L2'),
  ('7faf0321-6d8f-4213-d47b-af6e9224ceaf', 'IT', 'Italy', 'olive_oils_olives', 'Bruzio DOP (olive oil)', '["Bruzio DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian EVOO from Cosenza area in four sub-zones (Fascia Prepollinica, Valle Crati, Colline Joniche Presilane, Sibaritide). Medium fruity intensity, balanced with light bitter and pungent notes, distinctive almond and grass aromas.', 'Finishing oil on Calabrian dishes — pasta with ''nduja, grilled vegetables, fish; raw drizzle on antipasto.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Bruzio", "Cosenza DOP"]'::jsonb, FALSE, 'L2'),
  ('2a5d7a95-4707-f273-0a9e-874ecf100696', 'IT', 'Italy', 'olive_oils_olives', 'Canino DOP (olive oil)', '["Canino DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio EVOO from Tuscia area (Viterbo province), Caninese cultivar. Medium-intense fruity profile, well-balanced bitter-pungent finish, distinctive notes of artichoke, fresh almond, and tomato leaf.', 'Finishing oil on Roman-Lazio dishes (carbonara, cacio e pepe at table), raw on bruschetta, drizzled over pulses.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Canino", "Tuscia oil (Tuscia DOP also exists separately)"]'::jsonb, FALSE, 'L2'),
  ('c759e50b-d0f2-9870-5543-408716eb50fb', 'IT', 'Italy', 'olive_oils_olives', 'Cartoceto DOP (olive oil)', '["Cartoceto DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Marche EVOO from Pesaro hills, blend of Raggiola, Frantoio, Leccino, Moraiolo, Carboncella. Medium-light fruity intensity, balanced harmonious flavor, herbal notes of fresh-cut grass and almond.', 'Finishing oil on Adriatic seafood, Marchigiano pasta, raw on focaccia and bruschetta.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Cartoceto", "Pesaro DOP"]'::jsonb, FALSE, 'L2'),
  ('ca83448d-03b0-4f48-ff5b-33d6dcebaa94', 'IT', 'Italy', 'olive_oils_olives', 'Chianti Classico DOP (olive oil)', '["Chianti Classico DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan EVOO from the Chianti Classico zone, blend of Frantoio, Moraiolo, Leccino, Correggiolo. Robust fruity intensity, pronounced bitter-pungent finish, intense notes of artichoke, tomato leaf, fresh almond — the archetypal "Tuscan style".', 'Finishing oil on bistecca alla Fiorentina (essential), ribollita and pappa al pomodoro at table, raw on bruschetta with salt-free Tuscan bread, fagioli all''uccelletto.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1, 2]'::jsonb, '["Chianti Classico oil", "Chianti DOP olive oil"]'::jsonb, FALSE, 'L2'),
  ('8dce8cec-b6ac-1260-b675-67a67a74913f', 'IT', 'Italy', 'olive_oils_olives', 'Cilento DOP (olive oil)', '["Cilento DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian EVOO from Cilento national park, predominantly Pisciottana cultivar. Medium-intense fruity, balanced bitter-pungent, distinctive notes of artichoke, cardoon, fresh herbs, with characteristic Mediterranean-scrub aroma.', 'Finishing oil on Cilentan/Mediterranean diet preparations, drizzled on legume soups (lenticchie, fagioli), grilled fish, raw with Mozzarella di Bufala Campana.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Cilento", "Pisciottana oil"]'::jsonb, FALSE, 'L2'),
  ('792c1ee2-e31e-3245-773e-c0d099fe2a89', 'IT', 'Italy', 'olive_oils_olives', 'Collina di Brindisi DOP (olive oil)', '["Collina di Brindisi DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian EVOO from Brindisi hills, predominantly Ogliarola Salentina cultivar. Medium-light fruity intensity, gentle bitter-pungent finish, sweet character with green-almond and tomato-leaf notes.', 'Finishing oil on Apulian orecchiette and rustic pastas, fresh tomato salads, drizzled on focaccia barese, raw on burrata.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L", "PET-canister-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Brindisi DOP", "Salentina oil"]'::jsonb, FALSE, 'L2'),
  ('331b1ec5-4d78-6952-0637-df02621d8932', 'IT', 'Italy', 'olive_oils_olives', 'Colline di Romagna DOP (olive oil)', '["Colline di Romagna DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Romagnolo EVOO from Cesena and Forlì hills, blend of local cultivars. Medium fruity intensity, harmonious bitter-pungent profile, herbaceous notes.', 'Finishing oil on Romagnolo dishes, Piadina, seafood preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Colline di Romagna"]'::jsonb, TRUE, 'L2'),
  ('a77264b4-7ab4-41d4-f928-fa131ea9b29f', 'IT', 'Italy', 'olive_oils_olives', 'Colline Pontine DOP (olive oil)', '["Colline Pontine DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio EVOO from Pontina area, predominantly Itrana cultivar. Medium-intense fruity, balanced bitter-pungent, distinctive notes of green tomato, artichoke, almond.', 'Finishing oil on Roman-Lazio dishes, drizzled over Roman pasta classics at table, raw on antipasto, paired with Lazio cheeses.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Colline Pontine", "Itrana oil"]'::jsonb, FALSE, 'L2'),
  ('998ba401-da49-e1ef-31ab-4e6973e7b0fb', 'IT', 'Italy', 'olive_oils_olives', 'Colline Salernitane DOP (olive oil)', '["Colline Salernitane DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian EVOO from Salerno hills, predominantly Rotondella cultivar. Medium-light fruity, balanced delicate flavor, sweet character with light bitter-pungent finish, hints of green herbs.', 'Finishing oil on Campanian seafood, Mozzarella di Bufala Campana DOP service, fresh tomato salads, raw on bruschetta.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Colline Salernitane"]'::jsonb, FALSE, 'L2'),
  ('44ec37e7-095f-3f6f-01e2-f5749d30033c', 'IT', 'Italy', 'olive_oils_olives', 'Colline Teatine DOP (olive oil)', '["Colline Teatine DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Abruzzese EVOO from Chieti hills, blend of Gentile di Chieti, Leccino, Dritta. Medium fruity intensity, balanced bitter-pungent, characteristic notes of fresh almond and artichoke.', 'Finishing oil on Abruzzese arrosticini, brodetto di pesce dell''Adriatico, drizzled on pulses.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Colline Teatine", "Chieti DOP"]'::jsonb, FALSE, 'L2'),
  ('c373c03e-6a3c-38c5-c895-95ebe10deb41', 'IT', 'Italy', 'olive_oils_olives', 'Dauno DOP (olive oil)', '["Dauno DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian EVOO from Foggia province in four sub-zones (Alto Tavoliere, Basso Tavoliere, Gargano, Sub-Appennino), predominantly Coratina, Ogliarola, Peranzana cultivars. Medium-intense fruity, balanced to robust bitter-pungent depending on sub-zone, characteristic notes of green tomato and almond.', 'Finishing oil on Apulian rustic dishes, orecchiette with cime di rapa, drizzled on pulses, raw on focaccia.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Dauno", "Daunia oil", "Foggia DOP"]'::jsonb, FALSE, 'L2'),
  ('cc268812-037b-2120-62a2-f8d12e7ac8ac', 'IT', 'Italy', 'olive_oils_olives', 'Garda DOP (olive oil)', '["Garda DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'EVOO from Lake Garda (the world''s northernmost olive-growing region) in three sub-zones (Bresciano, Orientale, Trentino), predominantly Casaliva, Frantoio, Leccino. Light-medium fruity intensity, gentle balanced flavor, delicate notes of fresh almond, green herbs, light artichoke — very elegant style suited to delicate dishes.', 'Finishing oil on Lake-Garda freshwater fish (lavarello, pesce persico), risotto al pesce di lago, salads, raw on burrata.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Garda Bresciano", "Garda Orientale", "Garda Trentino", "Lake Garda oil"]'::jsonb, FALSE, 'L2'),
  ('ec10d0ac-4a96-57da-e7de-7fdf25700c47', 'IT', 'Italy', 'olive_oils_olives', 'Irpinia – Colline dell''Ufita DOP (olive oil)', '["Irpinia – Colline dell''Ufita DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian EVOO from Avellino province (Ufita valley), predominantly Ravece cultivar (rare and distinctive). Medium-intense fruity, robust bitter-pungent profile, characteristic notes of tomato leaf, green almond, and unripe tomato.', 'Finishing oil on Irpinian rustic preparations, lentils, grilled meats; raw on bruschetta; pairs with Aglianico-based dishes.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Ufita", "Irpinia DOP", "Ravece oil"]'::jsonb, FALSE, 'L2'),
  ('3423dac6-ff7d-8126-28f9-fddbf3876c78', 'IT', 'Italy', 'olive_oils_olives', 'La Bella della Daunia DOP (table olive)', '["La Bella della Daunia DOP (table olive)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian large green table olive (Bella di Cerignola variety) from Foggia province. Bright green to amber color, very large fruit (up to 30g), firm crisp flesh, mild sweet-savory flavor, small pit with high flesh-to-pit ratio.', 'Premium aperitivo olive served whole, stuffed with anchovy or almond; on antipasto boards; in martini-style cocktails; visual centerpiece of olive selection.', '["jar-glass-300g-brine", "jar-glass-500g-brine", "bucket-2kg-brine", "bucket-5kg-brine", "vacuum-pack-200g", "tin-200g"]'::jsonb, '[]'::jsonb, '["Bella di Cerignola", "Cerignola olive"]'::jsonb, FALSE, 'L2'),
  ('205c1d6b-520c-14ac-66ec-ba38667d21d0', 'IT', 'Italy', 'olive_oils_olives', 'Laghi Lombardi DOP (olive oil)', '["Laghi Lombardi DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lombard EVOO from Lake Iseo and Lake Como areas, predominantly Casaliva and other northern cultivars. Light-medium fruity intensity, very delicate balanced flavor, soft notes of fresh almond and green herbs — among Italy''s most delicate styles.', 'Finishing oil on lake fish (carpione, missoltini), light risottos, fresh cheese platters, raw on burrata.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Laghi Lombardi (Lario", "Sebino sub-styles)"]'::jsonb, FALSE, 'L2'),
  ('3e22ee0f-4744-39c8-2eb4-4895f8182e5d', 'IT', 'Italy', 'olive_oils_olives', 'Lametia DOP (olive oil)', '["Lametia DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian EVOO from Lamezia Terme plain, predominantly Carolea cultivar. Medium fruity intensity, balanced bitter-pungent, characteristic notes of green tomato, fresh almond, light artichoke.', 'Finishing oil on Calabrian rustic dishes, drizzled on grilled fish and vegetables, raw on bread and antipasto.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Lametia", "Carolea oil"]'::jsonb, FALSE, 'L2'),
  ('a9457ffa-dea2-b624-c372-d6b273341475', 'IT', 'Italy', 'olive_oils_olives', 'Lucca DOP (olive oil)', '["Lucca DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan EVOO from Lucca province and hills, blend of Frantoio, Leccino, Maurino. Light-medium fruity intensity, well-balanced harmonious flavor (less robust than Chianti Classico), sweet character with delicate bitter-pungent finish.', 'Finishing oil on Tuscan light dishes (fish, vegetables), pairing with farro, raw on bruschetta with salt-free bread.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Lucca DOP", "Lucchese oil"]'::jsonb, FALSE, 'L2'),
  ('5e7f82ad-ff0f-3015-9de0-3fae540a4404', 'IT', 'Italy', 'olive_oils_olives', 'Marche IGP (olive oil)', '["Marche IGP (olive oil)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Marchigiano EVOO regional IGP, blend of local cultivars (Frantoio, Leccino, Raggia, Carboncella, Mignola, Sargano). Medium fruity intensity, harmonious bitter-pungent profile, characteristic notes of artichoke, fresh-cut grass, almond.', 'Finishing oil on Marchigiana cuisine — stoccafisso all''anconetana, vincisgrassi (lasagne), seafood preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio delle Marche"]'::jsonb, FALSE, 'L2'),
  ('1ae713f3-5c46-726f-c5ba-b55bf41d07e5', 'IT', 'Italy', 'olive_oils_olives', 'Molise DOP (olive oil)', '["Molise DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Molisan EVOO regional DOP, blend of Aurina, Gentile di Larino, Olivastro. Medium fruity intensity, balanced flavor profile.', 'Finishing oil on Molisan rustic dishes.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Molise olive oil"]'::jsonb, TRUE, 'L2'),
  ('afdff5b3-7589-1c8a-d6cb-8f2b5b7422e7', 'IT', 'Italy', 'olive_oils_olives', 'Monte Etna DOP (olive oil)', '["Monte Etna DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian EVOO from Etna volcano slopes, predominantly Nocellara Etnea, Brandofino, Tonda Iblea cultivars. Medium-intense fruity, balanced robust profile, distinctive notes of tomato, fresh almond, herbaceous and slightly mineral character from volcanic soils.', 'Finishing oil on Sicilian seafood (Etna red prawns, sword-fish), pasta alla Norma, grilled vegetables, raw with ricotta salata.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Etna oil", "Sicilia Etna DOP"]'::jsonb, FALSE, 'L2'),
  ('19ca7c7c-c931-6231-0c91-08e471c3a3b5', 'IT', 'Italy', 'olive_oils_olives', 'Monti Iblei DOP (olive oil)', '["Monti Iblei DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian EVOO from Iblei mountains (Ragusa-Siracusa), predominantly Tonda Iblea, Moresca, Nocellara Etnea. Robust intense fruity profile, pronounced bitter-pungent finish, distinctive notes of green tomato, fresh-cut grass, mint, almond — among Italy''s most highly-rated DOP oils.', 'Finishing oil on Sicilian premium preparations (red prawns of Mazara, tuna tartare), pasta alla Norma, raw on Cassata-region cheeses.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Iblei oil", "Tonda Iblea DOP", "Ragusa DOP olive oil"]'::jsonb, FALSE, 'L2'),
  ('96be2e9d-49cd-9ca8-c6e9-aaa6f8c31ec2', 'IT', 'Italy', 'olive_oils_olives', 'Nocellara del Belice DOP (table olive)', '["Nocellara del Belice DOP (table olive)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian table olive from Belice valley, prized for both oil and table use. Bright green to dark purple-black depending on harvest stage, large round shape, firm crisp flesh, sweet mild flavor with delicate fruity notes.', 'Premium aperitivo olive on antipasto boards; component of Sicilian preparations (caponata, pasta with olives); cocktail garnish; on cheese platters.', '["jar-glass-300g-brine", "jar-glass-500g-brine", "vacuum-pack-200g", "tin-200g", "bucket-2kg-brine", "bucket-5kg-brine"]'::jsonb, '[]'::jsonb, '["Nocellara", "Castelvetrano olive (commercial name for cured green form)"]'::jsonb, FALSE, 'L2'),
  ('6cdb89de-71c1-a3ef-be71-44e27c959ea8', 'IT', 'Italy', 'olive_oils_olives', 'Olio Campania IGP', '["Olio Campania IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Campanian regional IGP olive oil, blend of local cultivars (Carpellese, Frantoio, Leccino, Pisciottana, Ortolana, Ravece etc.). Medium fruity intensity, balanced harmonious flavor, regional character spanning Campania''s coastal and inland zones.', 'Versatile finishing oil for Campanian cuisine — pizza, pasta, mozzarella, seafood, antipasti.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio di Campania"]'::jsonb, FALSE, 'L2'),
  ('e50c5688-0e57-4d44-603e-d6a1c9995e70', 'IT', 'Italy', 'olive_oils_olives', 'Olio di Calabria IGP', '["Olio di Calabria IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Calabrian regional IGP olive oil, blend of Carolea, Dolce di Rossano, Roggianella, Tondina di Strongoli. Medium-intense fruity, balanced bitter-pungent, regional character.', 'Calabrian rustic cooking, pairs with peperoncino-based dishes, raw on bruschetta.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio Calabrese"]'::jsonb, FALSE, 'L2'),
  ('87570f9a-e62b-e7c1-74c4-6796287e431f', 'IT', 'Italy', 'olive_oils_olives', 'Olio di Puglia IGP', '["Olio di Puglia IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Apulian regional IGP olive oil, blend of Coratina, Ogliarola, Peranzana, Cellina di Nardò, Cima di Mola. Medium-intense to robust fruity, pronounced bitter-pungent (especially Coratina), characteristic notes of green tomato, almond, artichoke — Apulia produces ~40% of Italian olive oil.', 'Finishing oil on Apulian dishes, orecchiette, focaccia, drizzled on legumes; the volume "house oil" of southern Italian restaurants.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L", "PET-canister-3L", "bag-in-box-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Apulian oil", "Olio Pugliese"]'::jsonb, FALSE, 'L2'),
  ('986918f0-9ed0-caa1-ecf9-819ffb933b51', 'IT', 'Italy', 'olive_oils_olives', 'Olio di Roma IGP', '["Olio di Roma IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lazio regional IGP olive oil from Rome and surrounding provinces, blend of Itrana, Carboncella, Caninese, Salviana, Frantoio. Medium fruity intensity, balanced bitter-pungent, regional character spanning Lazio''s olive-growing areas.', 'House oil of Roman cuisine — drizzled on cacio e pepe, carbonara, gricia at table; raw on Roman antipasti; pairs with Lazio pulses.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio Romano"]'::jsonb, FALSE, 'L2'),
  ('a7409806-aadb-039a-378f-cdaeb75aed20', 'IT', 'Italy', 'olive_oils_olives', 'Olio Lucano IGP', '["Olio Lucano IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Lucanian regional IGP olive oil, blend of Maiatica, Coratina, Frantoio, Leccino, Ogliarola del Bradano. Medium fruity intensity, balanced bitter-pungent, regional character with herbal-almond notes.', 'Finishing oil on Lucanian rustic dishes — peperoni cruschi, lagane e fagioli, orecchiette.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio della Basilicata"]'::jsonb, FALSE, 'L2'),
  ('6861bb9f-fc66-4156-2bb4-6658d9bbe670', 'IT', 'Italy', 'olive_oils_olives', 'Oliva Ascolana del Piceno DOP (table olive)', '["Oliva Ascolana del Piceno DOP (table olive)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Marchigiano large green table olive (Ascolana Tenera variety) from Ascoli Piceno area. Bright green color, large rounded shape, very tender crisp flesh, mild sweet-buttery flavor, classic for stuffing and frying.', '**Olive Ascolane all''Ascolana** — pitted, stuffed with seasoned meat mixture, breaded and fried — the iconic Marchigiano antipasto/finger food. Also brined for aperitivo, in mixed olive selections.', '["jar-glass-300g-brine", "jar-glass-500g-brine", "frozen-stuffed-1kg", "frozen-stuffed-bulk-3kg", "vacuum-pack-200g", "bucket-2kg-brine"]'::jsonb, '[]'::jsonb, '["Ascolana Tenera", "Ascolana olive", "Stuffed Ascolane"]'::jsonb, FALSE, 'L2'),
  ('a2bf27e8-fb71-878e-fede-10a923478010', 'IT', 'Italy', 'olive_oils_olives', 'Penisola Sorrentina DOP (olive oil)', '["Penisola Sorrentina DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian EVOO from Sorrento peninsula and Capri, predominantly Minucciola cultivar. Medium-light fruity intensity, balanced delicate flavor, characteristic notes of fresh almond, green herbs, citrus zest hints — distinctively elegant southern style.', 'Finishing oil on Campanian seafood, Sorrento lemon-based dishes, Mozzarella di Bufala Campana service, raw on light pasta dishes.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Penisola Sorrentina", "Sorrento DOP"]'::jsonb, FALSE, 'L2'),
  ('35e800bd-0be1-e45c-99d1-2ffa939a2b00', 'IT', 'Italy', 'olive_oils_olives', 'Pretuziano delle Colline Teramane DOP (olive oil)', '["Pretuziano delle Colline Teramane DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Abruzzese EVOO from Teramo hills, blend of Tortiglione, Frantoio, Leccino, Dritta. Medium fruity intensity, balanced bitter-pungent, characteristic herbal notes.', 'Finishing oil on Abruzzese coastal cuisine, brodetto di pesce, drizzled on pulses.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Pretuziano", "Teramo DOP"]'::jsonb, FALSE, 'L2'),
  ('9cbeb736-c319-7203-cfba-c82718f5e285', 'IT', 'Italy', 'olive_oils_olives', 'Riviera Ligure DOP (olive oil)', '["Riviera Ligure DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Ligurian EVOO from coastal Liguria in three sub-zones (Riviera dei Fiori, Riviera del Ponente Savonese, Riviera di Levante), predominantly Taggiasca cultivar. Light fruity intensity, very delicate sweet-almond profile, soft balanced flavor with negligible bitter-pungent — among Italy''s most delicate styles.', 'Foundation of Ligurian cuisine — pesto Genovese (essential), focaccia di Recco, Ligurian seafood, fresh fish carpaccio, raw on burrata.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Riviera Ligure", "Taggiasca oil", "Riviera dei Fiori", "Riviera Ponente Savonese", "Riviera di Levante"]'::jsonb, FALSE, 'L2'),
  ('fee810c2-f71f-89eb-989d-a66e53aed786', 'IT', 'Italy', 'olive_oils_olives', 'Sabina DOP (olive oil)', '["Sabina DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio EVOO from Sabina hills (Rome-Rieti), blend of Carboncella, Leccino, Raja, Frantoio, Olivago, Salviana. Medium fruity intensity, balanced bitter-pungent, characteristic notes of artichoke and fresh almond.', 'Roman cuisine, pasta classics, drizzled on pulses, antipasto preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Sabina", "Sabino oil"]'::jsonb, FALSE, 'L2'),
  ('4e68c320-a22f-ef0e-2d89-55ea375f4271', 'IT', 'Italy', 'olive_oils_olives', 'Sardegna DOP (olive oil)', '["Sardegna DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sardinian regional DOP olive oil, predominantly Bosana cultivar with Tonda di Cagliari, Nera di Villacidro, Semidana. Medium-intense fruity, balanced bitter-pungent, characteristic notes of artichoke, fresh almond, slight tomato leaf.', 'Sardinian cuisine — fregula, malloreddus, grilled fish, drizzled on pulses, raw on pane carasau.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Olio di Sardegna", "Bosana oil"]'::jsonb, FALSE, 'L2'),
  ('8c44e793-592e-8243-60a0-01bf1dbd8d85', 'IT', 'Italy', 'olive_oils_olives', 'Seggiano DOP (olive oil)', '["Seggiano DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan EVOO from Monte Amiata area, predominantly Olivastra Seggianese cultivar. Medium fruity intensity, balanced bitter-pungent, characteristic notes of artichoke, fresh almond, green herbs.', 'Tuscan cuisine, especially southern Tuscany — drizzled on bistecca, pasta, ribollita.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Seggiano", "Olivastra Seggianese oil"]'::jsonb, FALSE, 'L2'),
  ('5ce15036-b1d9-481a-6a47-6c7ff63f7c8e', 'IT', 'Italy', 'olive_oils_olives', 'Sicilia IGP (olive oil)', '["Sicilia IGP (olive oil)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Sicilian regional IGP olive oil covering whole island, blend of Biancolilla, Cerasuola, Nocellara del Belice, Tonda Iblea, Moresca, Brandofino. Medium-intense fruity, balanced robust profile, characteristic Sicilian notes of tomato, almond, fresh herbs.', 'House oil of Sicilian cuisine — pasta alla Norma, caponata, swordfish, arancini service.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L", "PET-canister-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Sicilian olive oil"]'::jsonb, FALSE, 'L2'),
  ('d0b8c87b-4427-ecc1-49ac-8623def9bcec', 'IT', 'Italy', 'olive_oils_olives', 'Tergeste DOP (olive oil)', '["Tergeste DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Friulian EVOO from Trieste province, predominantly Bianchera/Belica cultivar. Light-medium fruity intensity, balanced delicate flavor, characteristic of north-eastern Adriatic style.', 'Friulian seafood preparations, drizzled on light dishes.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Tergeste", "Trieste DOP"]'::jsonb, TRUE, 'L2'),
  ('31218350-802d-025d-7c7c-e86fba82bfa1', 'IT', 'Italy', 'olive_oils_olives', 'Terra di Bari DOP (olive oil)', '["Terra di Bari DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian EVOO from Bari province in three sub-zones (Castel del Monte, Bitonto, Murgia dei Trulli e delle Grotte), predominantly Coratina, Ogliarola Barese cultivars. Medium-intense fruity, robust bitter-pungent (especially Coratina), characteristic notes of green tomato, almond, artichoke.', 'Apulian dishes — orecchiette with cime di rapa, focaccia barese, raw on burrata, drizzled on legumes.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Terra di Bari", "Bari DOP", "Coratina oil"]'::jsonb, FALSE, 'L2'),
  ('f6c7100e-f39a-f6c4-7dfa-6c79a648d8b5', 'IT', 'Italy', 'olive_oils_olives', 'Terra d''Otranto DOP (olive oil)', '["Terra d''Otranto DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Salentino EVOO from Lecce-Brindisi-Taranto provinces, predominantly Cellina di Nardò and Ogliarola Salentina cultivars. Medium-intense fruity, balanced bitter-pungent, characteristic Salento profile with green-almond and tomato leaf.', 'Salentino cuisine — orecchiette, taralli accompaniment, fresh tomato salads, drizzled on pulses, antipasto preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Terra d''Otranto", "Salento DOP"]'::jsonb, FALSE, 'L2'),
  ('2a755980-851b-32a7-5449-194e87e02212', 'IT', 'Italy', 'olive_oils_olives', 'Terre Aurunche DOP (olive oil)', '["Terre Aurunche DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Campanian EVOO from Terre Aurunche area (Caserta province), predominantly Sessana cultivar. Medium fruity intensity, balanced flavor profile.', 'Campanian rustic dishes, drizzled on local preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Terre Aurunche"]'::jsonb, TRUE, 'L2'),
  ('72f6d2f1-678e-52dc-9160-57f0dc6e896e', 'IT', 'Italy', 'olive_oils_olives', 'Terre di Siena DOP (olive oil)', '["Terre di Siena DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Tuscan EVOO from Siena province, blend of Frantoio, Moraiolo, Leccino, Correggiolo. Medium-intense fruity, robust bitter-pungent in classic Tuscan style, notes of artichoke, tomato leaf, fresh almond.', 'Sienese-Tuscan cuisine, drizzled on bistecca, pici pasta, ribollita.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Terre di Siena", "Sienese DOP"]'::jsonb, FALSE, 'L2'),
  ('7dca50f7-26a2-6f80-ae6f-11dccc7e79f7', 'IT', 'Italy', 'olive_oils_olives', 'Terre Tarentine DOP (olive oil)', '["Terre Tarentine DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Apulian EVOO from Taranto province, blend of Leccino, Coratina, Frantoio, Ogliarola. Medium fruity intensity.', 'Apulian rustic cuisine.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Terre Tarentine", "Taranto DOP"]'::jsonb, TRUE, 'L2'),
  ('c1e6af60-d260-c297-31d4-5fec35e1c840', 'IT', 'Italy', 'olive_oils_olives', 'Toscano IGP (olive oil)', '["Toscano IGP (olive oil)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Tuscan regional IGP olive oil covering all Tuscany, blend of Frantoio, Moraiolo, Leccino. Robust fruity intensity, pronounced bitter-pungent, characteristic Tuscan notes of artichoke, tomato leaf, fresh almond — the "house Tuscan" benchmark style.', 'Foundation of Tuscan cuisine — bistecca alla Fiorentina, ribollita, panzanella, fagioli all''uccelletto, pinzimonio, raw on bruschetta with salt-free Tuscan bread; the most exported Italian regional oil.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "glass-bottle-1L", "tin-3L", "tin-5L", "PET-canister-3L", "bag-in-box-5L"]'::jsonb, '[10, 11, 12, 1, 2]'::jsonb, '["Toscano", "Tuscan IGP", "Olio Toscano"]'::jsonb, FALSE, 'L2'),
  ('dc96c45b-372f-c82f-412d-356bf0935ce1', 'IT', 'Italy', 'olive_oils_olives', 'Tuscia DOP (olive oil)', '["Tuscia DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio EVOO from Tuscia/Viterbo area, predominantly Frantoio, Caninese, Leccino. Medium fruity intensity, balanced bitter-pungent, characteristic notes of artichoke and fresh almond.', 'Lazio cuisine, pasta classics, drizzled on regional pulses (lentils, fagioli del Purgatorio).', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Tuscia", "Viterbo DOP"]'::jsonb, FALSE, 'L2'),
  ('b4eb90b5-48bb-5296-c671-2447c364a067', 'IT', 'Italy', 'olive_oils_olives', 'Umbria DOP (olive oil)', '["Umbria DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Umbrian regional DOP olive oil in five sub-zones (Colli Assisi-Spoleto, Colli Martani, Colli Amerini, Colli Orvietani, Colli del Trasimeno), predominantly Moraiolo, Frantoio, Leccino. Medium-intense fruity, robust bitter-pungent (especially Colli Assisi-Spoleto), characteristic notes of artichoke, fresh-cut grass, almond — most concentrated Italian DOP zone for olive culture.', 'Umbrian cuisine — strangozzi pasta with truffle, lentils di Castelluccio, grilled meats, raw on bruschetta with truffle.', '["glass-bottle-250ml", "glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1, 2]'::jsonb, '["Umbria", "Olio Umbro", "Colli Assisi-Spoleto", "Colli Martani", "Colli Amerini", "Colli Orvietani", "Colli del Trasimeno"]'::jsonb, FALSE, 'L2'),
  ('248df4d4-27b3-b593-e454-a74f49db89ce', 'IT', 'Italy', 'olive_oils_olives', 'Val di Mazara DOP (olive oil)', '["Val di Mazara DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian EVOO from Mazara valley (western Sicily), predominantly Biancolilla, Cerasuola, Nocellara del Belice cultivars. Medium fruity intensity, balanced harmonious flavor, characteristic Sicilian notes of tomato, almond, fresh herbs.', 'Western Sicilian cuisine, especially Trapani area — fish couscous, pesto trapanese, busiate pasta.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Val di Mazara", "Mazara DOP"]'::jsonb, FALSE, 'L2'),
  ('1a3102d5-5a25-333d-7b6b-a6f2fe8a00c6', 'IT', 'Italy', 'olive_oils_olives', 'Valdemone DOP (olive oil)', '["Valdemone DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian EVOO from Messina province (Valdemone area), blend of local cultivars. Medium fruity intensity.', 'North-eastern Sicilian cuisine.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Valdemone"]'::jsonb, TRUE, 'L2'),
  ('f982203d-ff71-79d8-636e-e548534b5e96', 'IT', 'Italy', 'olive_oils_olives', 'Valle del Belice DOP (olive oil)', '["Valle del Belice DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian EVOO from Belice valley, predominantly Nocellara del Belice (also a table olive DOP — same cultivar). Medium-intense fruity, balanced bitter-pungent, characteristic notes of fresh tomato, green almond, herbs.', 'Western Sicilian cuisine, drizzled on Sicilian preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Belice", "Belìce oil"]'::jsonb, FALSE, 'L2'),
  ('f0dfaedd-91af-fc51-a9be-9caaf6313bce', 'IT', 'Italy', 'olive_oils_olives', 'Valli Trapanesi DOP (olive oil)', '["Valli Trapanesi DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian EVOO from Trapani valleys, predominantly Cerasuola and Nocellara del Belice cultivars. Medium-intense fruity, balanced bitter-pungent, characteristic notes of tomato, fresh almond, slight herbal.', 'Western Sicilian cuisine — pesto trapanese, fish couscous, busiate, raw on Mediterranean preparations.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Valli Trapanesi", "Trapani DOP"]'::jsonb, FALSE, 'L2'),
  ('137f0ba7-9330-ea2a-11be-74a6bbd15003', 'IT', 'Italy', 'olive_oils_olives', 'Veneto DOP (olive oil)', '["Veneto DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Veneto regional DOP olive oil in three sub-zones (Valpolicella, Euganei e Berici, del Grappa), predominantly Grignano, Favarol, Casaliva, Frantoio. Light-medium fruity intensity, balanced delicate flavor, sweet character with light bitter-pungent.', 'Veneto cuisine, light dishes, freshwater fish, drizzled on risotti, raw on antipasto.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Veneto Valpolicella", "Veneto Euganei e Berici", "Veneto del Grappa"]'::jsonb, FALSE, 'L2'),
  ('1a0cf5de-e3fc-5d15-7f68-579afd0b2d6a', 'IT', 'Italy', 'olive_oils_olives', 'Vulture DOP (olive oil)', '["Vulture DOP (olive oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lucanian EVOO from Vulture mountain (extinct volcano area, also famous for Aglianico wine). Predominantly Ogliarola del Vulture cultivar. Medium fruity intensity, balanced harmonious flavor, characteristic notes of artichoke, fresh almond, light volcanic minerality.', 'Lucanian cuisine — pasta with peperoni cruschi, lentils, drizzled on rustic preparations; pairs with Aglianico del Vulture-themed menus.', '["glass-bottle-500ml", "glass-bottle-750ml", "tin-3L", "tin-5L"]'::jsonb, '[10, 11, 12, 1]'::jsonb, '["Vulture", "Aglianico-area oil"]'::jsonb, FALSE, 'L2'),
  ('44bd46d9-aae3-a6a6-5170-ee8cfc351621', 'IT', 'Italy', 'fruits_nuts', 'Amarene Brusche di Modena IGP', '["Amarene Brusche di Modena IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Modenese sour cherry preserve, deep ruby color, intense sweet-sour balance, distinctive bitter-almond undertone from the variety, syrupy texture with whole pitted cherries. Note: this IGP appears in both fruits_nuts and sweets_pastry_confectionery — described here only.', 'Topping for vanilla gelato, panna cotta, ricotta-based desserts; pairing with aged Parmigiano on cheese boards; component of zuccotto and cassata; cocktail garnish.', '["jar-glass-200g", "jar-glass-400g", "jar-glass-1kg", "bucket-bulk-3kg"]'::jsonb, '[]'::jsonb, '["Amarene di Modena", "Sour cherries Modena"]'::jsonb, FALSE, 'L2'),
  ('9cbc0722-f2b3-89eb-dc4c-a3f3f1b33c22', 'IT', 'Italy', 'fruits_nuts', 'Arancia del Gargano IGP', '["Arancia del Gargano IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Apulian orange from Gargano peninsula, two varieties (Bionda Comune, Duretta del Gargano). Bright orange skin, juicy fragrant flesh, balanced sweet-acid flavor with floral notes from sea-influenced microclimate.', 'Fresh juice service, salads with fennel and olives, marmalade production, citrus-based desserts.', '["crate-10kg", "crate-15kg", "retail-net-bag-2kg", "retail-net-bag-3kg"]'::jsonb, '[12, 1, 2, 3, 4]'::jsonb, '["Arancia bionda del Gargano", "Duretta del Gargano"]'::jsonb, FALSE, 'L2'),
  ('c7f140aa-6573-f347-0f14-90219fc16f33', 'IT', 'Italy', 'fruits_nuts', 'Arancia di Ribera DOP', '["Arancia di Ribera DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Sicilian Washington Navel orange from Ribera area (Agrigento). Large bright-orange fruit, very juicy, distinctively sweet (low acidity), seedless, easy-peel — among Italy''s premier eating oranges.', 'Premium fresh juice service, fruit-plate dessert, salads with fennel and olive oil, in pastry cream, candied for cassata.', '["crate-10kg", "crate-15kg", "retail-net-bag-2kg", "retail-net-bag-3kg"]'::jsonb, '[12, 1, 2, 3, 4, 5]'::jsonb, '["Ribera DOP", "Washington Navel di Ribera"]'::jsonb, FALSE, 'L2'),
  ('74094727-e6c0-0bc3-3e83-58eb4fa14afc', 'IT', 'Italy', 'fruits_nuts', 'Arancia Rossa di Sicilia IGP', '["Arancia Rossa di Sicilia IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Sicilian blood orange from Catania-Enna-Siracusa area, three varieties (Tarocco, Moro, Sanguinello). Distinctive ruby-red flesh, intensely flavored juice with raspberry and cherry notes, balanced sweet-acid; the iconic Italian blood orange.', 'Fresh juice (especially "spremuta di arancia rossa" Sicilian breakfast classic), fennel-orange salad, granita, ricotta-orange desserts, savory pairings with duck and pork.', '["crate-10kg", "crate-15kg", "retail-net-bag-2kg", "retail-net-bag-3kg"]'::jsonb, '[12, 1, 2, 3, 4]'::jsonb, '["Tarocco", "Moro", "Sanguinello", "Sicilian blood orange"]'::jsonb, FALSE, 'L2'),
  ('9a05f8c2-4829-e206-f23c-4af9702c10bd', 'IT', 'Italy', 'fruits_nuts', 'Bergamotto di Reggio Calabria DOP (essential oil)', '["Bergamotto di Reggio Calabria DOP (essential oil)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Calabrian bergamot fruit DOP — note this is the essential oil, not the fresh fruit. Vivid yellow oil with intensely aromatic floral-citrus profile, bitter-sweet-fresh character, foundational note in Earl Grey tea and Eau de Cologne perfumery.', 'Pastry chef use — bergamot panna cotta, bergamot tea-flavored desserts, custards, gelato; cocktail bitters; aromatic component in chocolate truffles.', '["glass-bottle-30ml", "glass-bottle-50ml", "glass-bottle-100ml", "glass-bottle-250ml", "professional-bulk-1L"]'::jsonb, '[11, 12, 1, 2]'::jsonb, '["Bergamotto di Reggio Calabria", "Reggio bergamot oil"]'::jsonb, FALSE, 'L2'),
  ('68b3aaef-f3c3-4ce0-8479-090999d81f08', 'IT', 'Italy', 'fruits_nuts', 'Castagna Cuneo IGP', '["Castagna Cuneo IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Piedmontese chestnut from Cuneo area, three varieties (Bracalla, Castagna della Madonna, Marrone Burnett). Large smooth dark-mahogany shell, sweet creamy starchy flesh, balanced flavor.', 'Roasted whole as autumn aperitivo (caldarroste), boiled with bay leaves, candied (marrons glacés), in chestnut soup and risotto, chestnut-flour gnocchi.', '["crate-10kg", "crate-15kg", "vacuum-pack-cooked-500g", "frozen-peeled-1kg", "dried-1kg"]'::jsonb, '[10, 11, 12]'::jsonb, '["Castagna Cuneese", "Cuneo chestnut"]'::jsonb, FALSE, 'L2'),
  ('36d9ab69-095e-e7fb-4163-5dc8a796d78c', 'IT', 'Italy', 'fruits_nuts', 'Castagna del Monte Amiata IGP', '["Castagna del Monte Amiata IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Tuscan chestnut from Amiata mountain (Siena-Grosseto), large chestnut with thin shell, sweet flesh with subtle vanilla note. Three varieties (Marrone, Bastarda Rossa, Cecio).', 'Roasted as caldarroste, in Amiata chestnut soup, dried for Amiata chestnut flour and traditional polenta dolce, in autumn pasta dishes.', '["crate-10kg", "crate-15kg", "vacuum-pack-cooked-500g", "frozen-peeled-1kg"]'::jsonb, '[10, 11, 12]'::jsonb, '["Marrone dell''Amiata", "Amiata chestnut"]'::jsonb, FALSE, 'L2'),
  ('a6d60a3e-93b6-1784-d774-325c66a46883', 'IT', 'Italy', 'fruits_nuts', 'Castagna di Montella IGP', '["Castagna di Montella IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Campanian chestnut from Montella (Avellino province), small to medium size, very sweet flesh with characteristic balanced sweet-starchy flavor, easy to peel.', 'Caldarroste, in Irpinian autumn dishes, candied, dried as chestnut flour, ingredient in Christmas Italian sweets.', '["crate-10kg", "crate-15kg", "vacuum-pack-cooked-500g", "dried-1kg"]'::jsonb, '[10, 11, 12]'::jsonb, '["Montella", "Irpinia chestnut"]'::jsonb, FALSE, 'L2'),
  ('b910316d-2ccc-e9c2-bed7-7c58df9a8519', 'IT', 'Italy', 'fruits_nuts', 'Castagna di Vallerano DOP', '["Castagna di Vallerano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Lazio chestnut from Vallerano (Viterbo province), Marrone Vallerano variety. Large mahogany shell, sweet flesh.', 'Caldarroste, candied, in Lazio autumn dishes, ingredient in chestnut-honey desserts.', '["crate-10kg", "crate-15kg"]'::jsonb, '[10, 11, 12]'::jsonb, '["Marrone di Vallerano"]'::jsonb, FALSE, 'L2'),
