  ('61ad1c18-715d-9e8a-b063-5692ef979b90', 'ES', 'Spain', 'vinegars_condiments', 'Vinagre de Jerez al Pedro Ximénez DOP', '["Vinagre de Jerez al Pedro Ximénez DOP", "Vinagre de Jerez al Moscatel DOP (sub-styles)"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Sherry-vinegar variants made from PX or Moscatel sweet sherry. Distinctively sweet-tart profile with intense raisin-honey notes (PX) or floral-citrus notes (Moscatel).', 'Premium reduction sauces; with foie gras; on fruit salads; in Spanish high-end pastry.', '["glass-bottle-250ml", "glass-bottle-500ml", "gift-bottle-250ml"]'::jsonb, '[]'::jsonb, '["Vinagre PX", "Vinagre Moscatel"]'::jsonb, FALSE, 'L2'),
  ('a00f105a-6494-9f87-c4c6-216f9cf4eb69', 'ES', 'Spain', 'vinegars_condiments', 'Vinagre del Condado de Huelva DOP', '["Vinagre del Condado de Huelva DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Andalusian wine vinegar DOP from Huelva (Condado area). Aged in solera system, similar profile to Jerez but with Huelva-region terroir.', 'Andalusian regional preparations.', '["glass-bottle-500ml", "gift-bottle-500ml"]'::jsonb, '[]'::jsonb, '["Vinagre del Condado"]'::jsonb, FALSE, 'L2'),
