  ('158d7f78-0cd2-65c3-6695-3ad857b19746', 'ES', 'Spain', 'seafood_conservas', 'Pulpo de Galicia (status — heritage, IGP status verify Layer 1)', '["Pulpo de Galicia (status — heritage, IGP status verify Layer 1)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Galician octopus, traditional preparation as **pulpo a la gallega / a feira** — boiled, sliced, dressed with paprika (pimentón), EVOO, and sea salt on wooden plate.', 'Galician restaurant signature; in pulpería culture; pairs with Albariño and Mencía.', '["whole-fresh-2-4kg", "vacuum-pack-cooked-500g", "vacuum-pack-cooked-1kg", "jar-conserved-200g"]'::jsonb, '[]'::jsonb, '["Pulpo gallego"]'::jsonb, FALSE, 'L2'),
  ('9d1b7baf-e15c-631e-a129-4f69e1d73c9b', 'ES', 'Spain', 'seafood_conservas', 'Sardinas (status — Galician heritage; sardinas en aceite de oliva premium tradition; status verify)', '["Sardinas (status — Galician heritage; sardinas en aceite de oliva premium tradition; status verify)"]'::jsonb, 'OTHER', '["OTHER"]'::jsonb, '', '', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, TRUE, 'L2'),
