  ('e7eab1e3-fb5a-6608-1a1d-0e392f6f1b6e', 'ES', 'Spain', 'seafood_conservas', 'Erizo de mar', '["Erizo de mar", "Sea urchin (status — heritage seafood, not separately IGP)"]'::jsonb, 'OTHER', '["OTHER", "PGI"]'::jsonb, '', '', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, TRUE, 'L2'),
  ('5b7f7817-600e-c153-f7f3-8a0f5c75a3f8', 'ES', 'Spain', 'seafood_conservas', 'Almeja de Carril (status — Galician heritage shellfish, status verify Layer 1)', '["Almeja de Carril (status — Galician heritage shellfish, status verify Layer 1)"]'::jsonb, 'OTHER', '["OTHER"]'::jsonb, 'Galician high-end clam from Carril.', 'Premium Galician shellfish service.', '["mesh-bag-fresh-500g"]'::jsonb, '[]'::jsonb, '["Almeja de Carril"]'::jsonb, TRUE, 'L2'),
  ('894e5b6a-9902-a42f-c624-e8d6e4b4239c', 'ES', 'Spain', 'rice_pasta_grains', 'Arroz del Delta del Ebro DOP', '["Arroz del Delta del Ebro DOP", "Arròs del Delta de l''Ebre DOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Catalan rice DOP from Delta del Ebro (Tarragona), Bahía, Tebre, Bomba, Marisma varieties. Distinctive Bomba variety — small round grain, very high water-absorption capacity (3:1 ratio), holds shape well in cooking. Pearl-white grains, balanced starch profile.', '**Foundation of paella valenciana, fideuà, arroz negro** — Bomba especially prized for paella due to high absorption and grain integrity; pairs with Cava.', '["vacuum-pack-1kg", "vacuum-pack-500g", "paper-bag-1kg", "gift-pack-1kg", "professional-bulk-5kg"]'::jsonb, '[]'::jsonb, '["Arròs del Delta de l''Ebre", "Bomba del Delta", "Delta Ebro rice"]'::jsonb, FALSE, 'L2'),
  ('8e9b49d3-bf08-697e-58a2-84fab4c7edc5', 'ES', 'Spain', 'rice_pasta_grains', 'Arroz de Calasparra DOP', '["Arroz de Calasparra DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Murcian rice DOP from Calasparra area, Bomba and Balilla x Sollana varieties. Distinctive — high-altitude cold-water cultivation, slow-grown grain with high absorption.', 'Premium paella rice; in Murcian arroz al horno.', '["vacuum-pack-1kg", "vacuum-pack-500g", "paper-bag-1kg", "gift-pack-1kg"]'::jsonb, '[]'::jsonb, '["Arroz de Calasparra", "Calasparra rice", "Bomba de Calasparra"]'::jsonb, FALSE, 'L2'),
  ('e5c0dd09-fbba-98dd-93db-3e7911c3fd4b', 'ES', 'Spain', 'rice_pasta_grains', 'Arroz de Valencia DOP', '["Arroz de Valencia DOP", "Arròs de València DOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Valencian rice DOP from Albufera-Valencia area, Senia, Bahía, Bomba varieties. The "homeland" rice of paella valenciana.', '**Foundation of authentic paella valenciana** — preferred over other Spanish rices for Valencian paella service; in arroz a banda, arroz negro.', '["vacuum-pack-1kg", "vacuum-pack-500g", "paper-bag-1kg", "gift-pack-1kg"]'::jsonb, '[]'::jsonb, '["Arròs de València", "Valencia rice"]'::jsonb, FALSE, 'L2'),
  ('6c3e7d8c-9d18-b17c-b3cb-d507978f023b', 'ES', 'Spain', 'rice_pasta_grains', 'Pan de Cea IGP', '["Pan de Cea IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Galician rustic round bread IGP from Ourense (Cea), traditional wood-oven baking. Thick crust, dense moist crumb, characteristic country-bread profile — among Spain''s most famous breads.', 'Galician bread service; with regional cheeses and cured meats; bocadillos.', '["whole-loaf-1kg", "whole-loaf-2kg"]'::jsonb, '[]'::jsonb, '["Pan de Cea", "Cea bread"]'::jsonb, FALSE, 'L2'),
  ('4b086a73-3431-323a-f38c-6ad1981a0cec', 'FR', 'France', 'cheeses_dairy', 'Abondance AOP', '["Abondance AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Savoyard alpine cow''s milk pressed cheese from Abondance breed, aged 90+ days. Pale ivory paste with small "saumâtre" eyes, firm fudgy texture, fruity hazelnut flavor with characteristic alpine flora notes; concave heel from traditional cerclage de bois.', 'Centerpiece of Savoyard cheese boards; melted in tartiflette and Berthoud (the iconic Abondance preparation — half-wheel hollowed, doused in white wine and garlic, oven-fired); paired with Apremont and Roussette de Savoie wines.', '["wheel-full-7-12kg", "wheel-half-vacuum-3-5kg", "wedge-vacuum-500g", "wedge-vacuum-200g"]'::jsonb, '[]'::jsonb, '["Tomme d''Abondance", "Vacherin d''Abondance (historical)"]'::jsonb, FALSE, 'L2'),
  ('5e5a8c62-42b4-e7df-3b47-5907c1d45ab0', 'FR', 'France', 'cheeses_dairy', 'Banon AOP', '["Banon AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Provençal goat''s milk soft cheese wrapped in chestnut leaves and tied with raffia, aged 15+ days. Ivory paste, soft creamy melting texture, intensely aromatic with goat-milk tang, chestnut-leaf vegetal note, and characteristic eau-de-vie-mouillée hint (some affineurs douse in marc).', 'Plateau de fromages centerpiece (visual showpiece); spread on warm baguette toasts; component of Provençal apéritif boards; paired with rosé de Provence and Bandol.', '["single-wheel-90-100g", "gift-pack-twin-200g"]'::jsonb, '[4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Banon de Banon", "Fromage de Banon"]'::jsonb, FALSE, 'L2'),
  ('aaa26b96-86ae-c7fd-0944-2d8533e8cf8b', 'FR', 'France', 'cheeses_dairy', 'Beaufort AOP', '["Beaufort AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Savoyard alpine cow''s milk pressed cooked cheese (gruyère family), aged minimum 5 months, traditionally up to 18-24+ months. Concave heel ("talon concave") signature shape. Pale yellow paste, firm dense texture, intensely fruity flavor evolving from buttery-floral young to nutty-savory aged with characteristic lait-cuit caramel note. Three styles: Beaufort (year-round), Beaufort d''été (summer milk, June-October), Beaufort Chalet d''Alpage (highest-altitude summer chalet production, premium).', 'Foundation Savoyard cheese — fondue savoyarde (essential), cheese boards, gratins, shaved on salads, in Beaufort soufflé, melted in croque-Beaufort.', '["wheel-full-20-70kg", "wheel-quarter-vacuum-5-15kg", "wedge-vacuum-1kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Beaufort d''été", "Beaufort Chalet d''Alpage", "Gruyère de Beaufort (historical)"]'::jsonb, FALSE, 'L2'),
  ('bdd4206c-97fe-13cf-6ada-abbcdf8f4583', 'FR', 'France', 'cheeses_dairy', 'Bleu d''Auvergne AOP', '["Bleu d''Auvergne AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Auvergne cow''s milk blue cheese aged minimum 21 days. Ivory-white paste with prominent dark blue-green Penicillium roqueforti veining, soft creamy moist texture, robust pungent salty-spicy flavor with mineral-mushroom notes — more accessible and balanced than Roquefort.', 'Plateau de fromages classic; melted in sauce bleu for steak; crumbled in salads with walnuts; pairs with Sauternes, Banyuls, Maury vins doux.', '["wheel-full-2-3kg", "wheel-half-vacuum-1.5kg", "wedge-vacuum-300g", "wedge-vacuum-150g", "crumbled-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Bleu d''Auvergne", "Auvergne blue"]'::jsonb, FALSE, 'L2'),
  ('7583475f-e7c0-f99f-8099-7271f6966c7c', 'FR', 'France', 'cheeses_dairy', 'Bleu de Gex Haut-Jura AOP', '["Bleu de Gex Haut-Jura AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Jura cow''s milk blue cheese aged minimum 21 days. Pale ivory paste with delicate marbled blue-green veining, semi-firm texture, milder than Roquefort or Bleu d''Auvergne, with characteristic hazelnut-mountain-grass notes and gentle blue tang.', 'Plateau de fromages; melted in Jura sauce for poached chicken; gentle blue option for cheese course; paired with vin jaune from Arbois.', '["wheel-full-7.5kg", "wheel-half-vacuum-3.5kg", "wedge-vacuum-300g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Bleu de Gex", "Bleu de Septmoncel", "Bleu du Haut-Jura"]'::jsonb, FALSE, 'L2'),
  ('1160b07c-a915-5aad-56af-b260c18d27ff', 'FR', 'France', 'cheeses_dairy', 'Bleu des Causses AOP', '["Bleu des Causses AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aveyron cow''s milk blue cheese aged in same Causses caves as Roquefort. Ivory paste with assertive blue-green veining, firm crumbly texture, intense salty-pungent flavor with sharp Penicillium character — cow-milk counterpart to Roquefort.', 'Plateau de fromages; in tartines; melted in sauces; paired with Banyuls and Sauternes.', '["wheel-full-2.3-3kg", "wheel-half-vacuum-1.5kg", "wedge-vacuum-300g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Bleu des Causses"]'::jsonb, FALSE, 'L2'),
  ('8051a270-4467-c3b4-7a89-913a40c3cabe', 'FR', 'France', 'cheeses_dairy', 'Bleu du Vercors-Sassenage AOP', '["Bleu du Vercors-Sassenage AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Vercors cow''s milk semi-soft blue cheese aged 21+ days. Pale ivory paste with delicate blue-green veining, soft fudgy texture, mild balanced blue flavor with characteristic alpine-grass freshness — among the gentlest French blues.', 'Plateau de fromages; melted in Vercors-style ravioles dauphinoises sauce; with walnuts and pears.', '["wheel-full-4-4.5kg", "wheel-half-vacuum-2kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Sassenage", "Bleu de Sassenage", "Vercors-Sassenage"]'::jsonb, FALSE, 'L2'),
  ('462d306e-1ef4-9336-089e-d77916ee9d55', 'FR', 'France', 'cheeses_dairy', 'Brie de Meaux AOP', '["Brie de Meaux AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Île-de-France cow''s milk soft bloomy-rind cheese aged minimum 4 weeks. White Penicillium candidum rind, ivory-cream paste, distinctively soft to oozing creamy texture at peak ripeness, mushroomy-buttery flavor with pronounced fresh straw and toasted-cream notes — the historical "Roi des Fromages".', 'Plateau de fromages essential (kingpin position); served at room temperature for full ooze; in baked Brie en croûte; with fig jam and walnut bread; pairs with Champagne and Pinot Noir.', '["wheel-full-2.5-3kg", "wheel-half-1.5kg", "wheel-quarter-700g", "wedge-vacuum-300g", "wedge-vacuum-150g", "mini-coulant-200g"]'::jsonb, '[]'::jsonb, '["Brie de Meaux", "King of Cheeses", "Roi des Fromages", "Brie"]'::jsonb, FALSE, 'L2'),
  ('0fe15e5c-40e1-7e44-6b68-8638e50f6d8e', 'FR', 'France', 'cheeses_dairy', 'Brie de Melun AOP', '["Brie de Melun AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Île-de-France cow''s milk soft bloomy-rind cheese aged minimum 4 weeks, smaller and saltier than Brie de Meaux. White-streaked rust-spotted rind, ivory paste, soft texture, robustly aromatic flavor with intense farmyard notes and salty-savory finish — more rustic than Brie de Meaux.', 'Plateau de fromages alongside Brie de Meaux for contrast; preferred by French amateurs for character; pairs with bold reds (Bourgogne, Châteauneuf-du-Pape).', '["wheel-full-1.5-1.8kg", "wheel-half-900g", "wheel-quarter-450g", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Brie de Melun"]'::jsonb, FALSE, 'L2'),
  ('e88fbfd7-0d69-fa8a-32ac-6f6c34e438c6', 'FR', 'France', 'cheeses_dairy', 'Brocciu AOP', '["Brocciu AOP", "Brocciu Corse AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Corsican fresh whey-cheese (sheep''s or goat''s milk whey, traditionally double-heated). Bright white, soft delicate texture, fresh sweet-creamy flavor with subtle whey-tang and characteristic Corsican-flora notes.', 'Foundation of Corsican cuisine — sturzapretti dumplings, fiadone (Corsican lemon-Brocciu cheesecake), filling for ravioli; sweet preparations with honey and chestnut flour; spread on warm bread with figs.', '["tub-fresh-250g", "tub-fresh-500g", "tub-fresh-1kg", "basket-fascella-300g", "aged-Passu-vacuum-300g"]'::jsonb, '[11, 12, 1, 2, 3, 4, 5, 6]'::jsonb, '["Brocciu", "Brocciu Corse", "Brocciu Passu (aged variant)"]'::jsonb, FALSE, 'L2'),
  ('61c14b11-0e4c-bb1a-4896-7c782e78c71c', 'FR', 'France', 'cheeses_dairy', 'Camembert de Normandie AOP', '["Camembert de Normandie AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Normandy cow''s milk (lait cru — raw milk, mandatory for AOP) soft bloomy-rind cheese aged minimum 22 days. White Penicillium rind, ivory paste with characteristic golden-cream gradient when ripe, soft to runny texture at peak, intensely aromatic with mushroom-cream-cabbage farmyard notes — pungent and earthy, distinct from industrial pasteurized Camembert.', 'Plateau de fromages classic; baked whole in box ("Camembert au four") for sharing; with sliced apple and Calvados; pairs with cidre de Normandie and Pinot Noir.', '["wheel-full-250g", "gift-pack-2x250g"]'::jsonb, '[]'::jsonb, '["Camembert AOP", "Camembert lait cru", "Normandy Camembert"]'::jsonb, FALSE, 'L2'),
  ('824f01c8-250d-7b75-0e67-dea763d5b9d9', 'FR', 'France', 'cheeses_dairy', 'Cantal AOP', '["Cantal AOP", "Cantal-Salers AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Auvergne cow''s milk pressed uncooked cheese (cheddar''s ancestor), aged in three tiers: Cantal Jeune (30-60 days, mild and milky), Cantal Entre-Deux (3-6 months, balanced), Cantal Vieux (6-12+ months, intense and tangy). Pale ivory to amber paste with fudgy crumbly texture, evolving flavor from milky-grassy to sharply tangy-savory.', 'Plateau de fromages; aged Vieux grated in Auvergne aligot and truffade; cubed in salads; melted in panini; one of France''s most consumed cheeses.', '["wheel-full-35-45kg", "wheel-quarter-vacuum-9-11kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "cubed-pack-200g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Cantal Jeune", "Cantal Entre-Deux", "Cantal Vieux", "Fourme de Cantal (historical)"]'::jsonb, FALSE, 'L2'),
  ('664954fb-5c75-7d06-3a7f-516c9b49890f', 'FR', 'France', 'cheeses_dairy', 'Chabichou du Poitou AOP', '["Chabichou du Poitou AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Poitevin goat''s milk small log-shaped soft cheese aged 10-30 days. Wrinkled white-grey natural rind (mottled with bluish mold acceptable), ivory paste, semi-firm to creamy texture, fresh tangy goat flavor with hazelnut-grass notes.', 'Plateau de fromages with chèvre selection; sliced on warm crouton with honey and thyme; pairs with Sancerre and Quincy.', '["single-log-150g", "gift-pack-twin-300g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Chabichou", "Cabichou (dialect)"]'::jsonb, FALSE, 'L2'),
  ('1b10563e-920f-953b-348f-b083728f5cae', 'FR', 'France', 'cheeses_dairy', 'Chaource AOP', '["Chaource AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Champagne cow''s milk soft bloomy-rind cheese (cylindrical shape, taller than Camembert), aged minimum 14 days. White downy rind, ivory paste, soft creamy texture with mousse-like center, mild milky-mushroom flavor with delicate salty-savory finish.', 'Plateau de fromages; particularly classic with Champagne (regional pairing) — the Champenois aperitif fromage; in baked Chaource recipes.', '["wheel-full-450g  or wheel-full-250g", "wheel-half-vacuum-225g"]'::jsonb, '[]'::jsonb, '["Chaource"]'::jsonb, FALSE, 'L2'),
  ('f7199b86-7d19-94ad-e279-4bc86d5a56b8', 'FR', 'France', 'cheeses_dairy', 'Charolais AOP', '["Charolais AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Burgundian goat''s milk small drum-shaped cheese aged 16+ days. Ivory paste with thin natural rind that develops blue-grey mottling with age, semi-firm to firm texture, mild fresh goat flavor evolving to assertive aged character — distinguished from other chèvres by its taller drum shape.', 'Plateau de fromages with chèvre selection; classic Burgundian apéritif; pairs with Mâcon-Villages and Pouilly-Fuissé.', '["single-drum-250-300g", "gift-pack-twin-500g"]'::jsonb, '[]'::jsonb, '["Charolais", "Charolais de Bourgogne"]'::jsonb, FALSE, 'L2'),
  ('757e3ccb-930c-cf4c-7303-e5b439340b5a', 'FR', 'France', 'cheeses_dairy', 'Chevrotin AOP', '["Chevrotin AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Savoyard goat''s milk pressed semi-cooked cheese (the goat-milk counterpart to Reblochon, made by same alpine farmers from chevrière flocks). Aged 21+ days. Pinkish-orange washed rind, ivory paste, supple creamy texture, balanced goat-milk flavor with light tang and delicate mountain-flora notes.', 'Plateau de fromages with Savoyard selection; tartiflette de chèvre; rare specialty pairing for chèvre amateurs in Alpine restaurants.', '["wheel-full-250-350g", "wheel-half-vacuum-150g"]'::jsonb, '[4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Chevrotin des Aravis", "Chevrotin du Massif des Bauges"]'::jsonb, FALSE, 'L2'),
  ('48b8bdd4-a275-655a-f299-6d32df40feb4', 'FR', 'France', 'cheeses_dairy', 'Comté AOP', '["Comté AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Franche-Comté alpine cow''s milk pressed cooked cheese (gruyère family), Montbéliarde and Simmental breeds, aged minimum 4 months, typically 6-18 months, premium "Comté Extra-Vieux" 24-36+ months. Pale ivory-yellow to deep amber, firm dense texture with occasional small crystalline tyrosine, intensely complex flavor: young (4-8 mo) milky-floral, classic (12-18 mo) hazelnut-butter-salted, vieux (24+ mo) tobacco-leather-caramel-roasted-nut. France''s most-produced AOP cheese.', 'Foundation of plateau de fromages; fondue comtoise; soufflé au Comté; gratin de macaroni; gougères; cheese tartine; pairs with Vin Jaune, Champagne, and Sauternes.', '["wheel-full-32-45kg", "wheel-quarter-vacuum-8-12kg", "wedge-vacuum-1kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "cubed-pack-200g", "grated-pre-pack-100g", "shaved-tray-100g", "gift-pack-aged-300g"]'::jsonb, '[]'::jsonb, '["Comté", "Gruyère de Comté (historical)", "Vieux Comté", "Comté Extra-Vieux"]'::jsonb, FALSE, 'L2'),
  ('c790ba03-8526-6c4a-7b57-b13abd697010', 'FR', 'France', 'cheeses_dairy', 'Crottin de Chavignol AOP', '["Crottin de Chavignol AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Berry-Sancerrois goat''s milk small button-shaped cheese aged 10+ days, evolves dramatically with age: young (10-20 days, white pelliclé and creamy), demi-sec (20-30 days, firmer ivory), bleui (30-50 days, blue-grey mold), repassé (50+ days, hard amber, very intense). Tangy goat-milk flavor evolves from fresh-floral to intensely sharp-savory.', '**Crottin chaud** — warmed on toast over salade verte, the iconic French bistro starter; aged versions on plateau de fromages; classic Sancerre wine pairing.', '["single-button-60g", "single-button-50g", "gift-tray-6x60g", "gift-tray-12x60g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Crottin", "Sancerrois Crottin"]'::jsonb, FALSE, 'L2'),
  ('971af2d0-e0b4-11dc-806d-36342f809164', 'FR', 'France', 'cheeses_dairy', 'Crème de Bresse AOP', '["Crème de Bresse AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Bresse-Bressois cow''s milk crème fraîche AOP, lactic-fermented thick-set cream. Bright ivory color, dense smooth texture, fresh tangy flavor with characteristic Bresse-grass-fed sweetness; minimum 36% fat content per AOP rules.', 'Foundation Bressois cuisine — Volaille de Bresse à la crème, gratins, tarts (tarte au sucre Bressoise), savory and sweet sauces, in pastry cream and quenelle preparations.', '["tub-200g", "tub-500g", "tub-bulk-1kg", "tub-bulk-3kg", "professional-bulk-5L"]'::jsonb, '[]'::jsonb, '["Crème de Bresse", "Bresse cream"]'::jsonb, FALSE, 'L2'),
  ('7e7b2f5a-8ec4-2f7a-1cfa-02f4fafa1eaf', 'FR', 'France', 'cheeses_dairy', 'Beurre de Bresse AOP', '["Beurre de Bresse AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Bresse-Bressois cow''s milk butter from same Crème de Bresse base. Bright golden-yellow color, characteristically firm texture (high oleic content from grass-fed Bresse milk), nutty-sweet butter flavor with delicate hazelnut undertone.', 'Premium butter for fine dining — beurre noisette, beurre blanc, sauce béarnaise, pastry use (croissants, brioche, feuilletage); plated tableside butter service; finishing butter for sauces.', '["plaquette-250g", "plaquette-500g", "doux-or-demi-sel-250g", "professional-bulk-1kg", "professional-bulk-5kg"]'::jsonb, '[]'::jsonb, '["Beurre de Bresse"]'::jsonb, FALSE, 'L2'),
  ('53011dcf-4b6b-6adc-0010-67b2d53308c4', 'FR', 'France', 'cheeses_dairy', 'Beurre Charentes-Poitou AOP', '["Beurre Charentes-Poitou AOP", "Beurre des Charentes AOP", "Beurre des Deux-Sèvres AOP"]'::jsonb, 'PDO', '["PDO", "PDO", "PDO"]'::jsonb, 'Charente-Poitou cow''s milk butter (the "Le Beurre" of French gastronomy — premier French butter region). Bright pale-yellow color, exceptionally smooth creamy texture, delicate sweet-buttery flavor with floral notes — among France''s most prized butters, lower-water-content cooking butter favored by pâtissiers.', 'Premium pastry butter (essential for croissant, mille-feuille, kouign-amann, brioche feuilletée); beurre blanc and butter sauces; finishing butter; the standard French restaurant butter.', '["plaquette-250g", "plaquette-500g", "professional-bulk-1kg", "professional-bulk-5kg", "professional-bulk-25kg", "beurre-de-tourage-pastry-2kg"]'::jsonb, '[]'::jsonb, '["Beurre Charentes-Poitou", "Beurre des Charentes", "Beurre des Deux-Sèvres", "Échiré-style butter (Échiré is a famous brand)"]'::jsonb, FALSE, 'L2'),
  ('c502e6e0-ca66-4901-0090-fcef12e4af90', 'FR', 'France', 'cheeses_dairy', 'Beurre d''Isigny AOP', '["Beurre d''Isigny AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Normandy cow''s milk butter from Isigny-sur-Mer area, AOP since 1986. Bright golden-yellow (highest in France, from beta-carotene of Normande cows on prés salés grass), distinctly creamy and rich, with characteristic hazelnut-floral notes and slightly higher fat than Charentes-Poitou. Iconic premium butter.', 'Premium pastry butter (extensively used in haute pâtisserie); beurre blanc and Normandy butter sauces; finishing butter; tableside butter service; ingredient in caramels Isigny.', '["plaquette-250g", "plaquette-500g", "motte-tradition-1kg", "professional-bulk-1kg", "professional-bulk-5kg", "beurre-de-tourage-2kg"]'::jsonb, '[]'::jsonb, '["Beurre d''Isigny", "Isigny butter", "Isigny Sainte-Mère (commercial brand)"]'::jsonb, FALSE, 'L2'),
  ('214b9f5d-dfa9-29aa-80d6-6f59c3431da4', 'FR', 'France', 'cheeses_dairy', 'Crème d''Isigny AOP', '["Crème d''Isigny AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Normandy cow''s milk crème fraîche AOP, lactic-fermented thick-set cream paired with the Beurre d''Isigny terroir. Bright ivory-yellow tinge, dense thick texture (highest density French AOP cream), rich creamy flavor with light tang.', 'Foundation Norman cuisine — sole normande, poulet vallée d''Auge, tarte normande aux pommes, Camembert sauces; pastry use (chantilly, mousse, ganache); tableside crème service.', '["tub-200g", "tub-400g", "tub-bulk-1kg", "tub-bulk-3kg", "professional-bulk-5L"]'::jsonb, '[]'::jsonb, '["Crème d''Isigny", "Isigny cream"]'::jsonb, FALSE, 'L2'),
  ('5d8990e1-9c19-ab98-6413-7d6281024499', 'FR', 'France', 'cheeses_dairy', 'Époisses AOP', '["Époisses AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Burgundian cow''s milk washed-rind soft cheese, aged minimum 4 weeks with regular brine and Marc de Bourgogne washing. Distinctive bright orange-red shiny rind, ivory-cream paste with oozing texture at peak, intensely pungent aroma with assertive ammonia-savory-meaty flavor — among Europe''s most aromatic cheeses.', 'Plateau de fromages climax (placed last, strongest); spread on bread and pain d''épices; baked Époisses with garlic; pairs ONLY with Marc de Bourgogne, Trappiste-style beer, or sweet wine — disrupts most table wines.', '["wheel-full-250g", "wheel-full-700g", "gift-pack-twin-500g"]'::jsonb, '[]'::jsonb, '["Époisses", "Époisses de Bourgogne"]'::jsonb, FALSE, 'L2'),
  ('45764774-dcbf-76b0-9036-5fb50545d1cb', 'FR', 'France', 'cheeses_dairy', 'Fourme d''Ambert AOP', '["Fourme d''Ambert AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Auvergne cow''s milk blue cheese in distinctive tall cylindrical shape, aged minimum 28 days. Pale ivory paste with delicate evenly-distributed blue-green Penicillium veining, semi-soft moist creamy texture, balanced gentle blue flavor — among the mildest French blues.', 'Plateau de fromages (gentle blue option); melted in tartes salées; with pears and walnuts; gateaway blue for cheese-shy diners; pairs with Sauternes and late-harvest wines.', '["wheel-full-2-2.5kg", "wheel-half-vacuum-1kg", "wedge-vacuum-300g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Fourme d''Ambert", "Auvergne tall blue"]'::jsonb, FALSE, 'L2'),
  ('72731211-8d53-a56f-d94a-acda55129207', 'FR', 'France', 'cheeses_dairy', 'Fourme de Montbrison AOP', '["Fourme de Montbrison AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Forez cow''s milk blue cheese (close relative of Fourme d''Ambert in cylindrical shape), aged minimum 32 days, traditional gouttière-aged on pine planks. Pale ivory paste, slightly drier and firmer than Ambert, with characteristic blue-green veining and pine-resin influence from gouttière aging — slightly more pronounced flavor than Ambert.', 'Plateau de fromages; same uses as Fourme d''Ambert; preferred by Forez-region restaurants.', '["wheel-full-2.1-2.7kg", "wheel-half-vacuum-1.2kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Fourme de Montbrison", "Forez blue"]'::jsonb, FALSE, 'L2'),
  ('9fcf5848-6d4a-64c6-7ef0-cdd3afb64315', 'FR', 'France', 'cheeses_dairy', 'Gruyère IGP (France)', '["Gruyère IGP (France)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Note: French Gruyère IGP (registered 2013) is distinct from Swiss Gruyère AOP. French version from Savoie-Franche-Comté, aged 5+ months, characterized by **eyes the size of a pea to a cherry** (a defining IGP feature distinguishing French from Swiss Gruyère which is eyeless). Pale ivory-yellow paste, firm texture, fruity-savory flavor with hazelnut and cooked-milk notes.', 'Fondue (regional alternative to Comté); gratin dauphinois; soufflés; melted in croque-monsieur; commercial alternative to Comté in volume operations.', '["wheel-full-25-40kg", "wheel-quarter-vacuum-7-10kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Gruyère français", "Gruyère de France", "Gruyère IGP"]'::jsonb, FALSE, 'L2'),
  ('e79c505c-f5c0-046e-1a05-e2960837872e', 'FR', 'France', 'cheeses_dairy', 'Laguiole AOP', '["Laguiole AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aubrac cow''s milk pressed uncooked cheese (related to Cantal and Salers), aged minimum 4 months, often 6-18+. Tall cylindrical shape, pale ivory to amber paste, firm crumbly texture, robust tangy-savory flavor with green-grass notes evolving to nutty-piquant when aged — the Aubrac cheese.', 'Plateau de fromages; **aligot de l''Aubrac** (essential — fresh Laguiole tomme melted with mashed potato, garlic, butter to elastic stretchy texture); shaved on Aubrac steak; with truffe d''été in summer.', '["wheel-full-25-50kg", "wheel-quarter-vacuum-6-12kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "tomme-fraîche-aligot-1kg"]'::jsonb, '[]'::jsonb, '["Laguiole", "Fourme de Laguiole"]'::jsonb, FALSE, 'L2'),
  ('98064648-5bef-0f4b-2b9b-86f4395c0dd7', 'FR', 'France', 'cheeses_dairy', 'Langres AOP', '["Langres AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Champagne cow''s milk washed-rind soft cheese with distinctive bowl-shaped depression on top ("la fontaine", traditionally filled with Champagne or Marc). Bright orange-rust rind, ivory paste, semi-soft creamy texture, intensely aromatic with farmyard notes, tangy-savory flavor.', '**Champagne tradition** — fontaine filled with Champagne tableside; on plateau de fromages; pairs with Champagne, Marc de Champagne, sweet wines.', '["wheel-full-180g  or 800g", "gift-pack-twin-360g"]'::jsonb, '[]'::jsonb, '["Langres"]'::jsonb, FALSE, 'L2'),
  ('79649c71-7273-e2e6-4cfe-7f6c4852b0ec', 'FR', 'France', 'cheeses_dairy', 'Livarot AOP', '["Livarot AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Normandy cow''s milk washed-rind soft cheese, distinctive cylindrical shape banded with five reed-strips ("Le Colonel"). Aged 1-3 months with brine and annatto-rind washing. Bright orange-red rind, ivory paste, supple texture, intensely aromatic farmyard flavor with savory salty-tangy edge — between Pont-l''Évêque and Époisses in pungency.', 'Plateau de fromages (Norman selection alongside Camembert and Pont-l''Évêque); pairs with Calvados and cidre fermier de Normandie.', '["wheel-full-450g", "wheel-full-250g", "gift-pack-twin-500g"]'::jsonb, '[]'::jsonb, '["Livarot", "Le Colonel"]'::jsonb, FALSE, 'L2'),
  ('2f6550d1-e45b-306c-c766-75bf64ce27a4', 'FR', 'France', 'cheeses_dairy', 'Maroilles AOP', '["Maroilles AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Picardy-Avesnois cow''s milk washed-rind soft cheese, aged 5 weeks minimum (often longer for Vieux Maroilles). Bright orange-red shiny rind, ivory paste, soft supple texture, intensely pungent aroma with assertive farmyard notes, salty-savory flavor with characteristic sticky texture from washing.', '**Tarte au Maroilles / Flamiche au Maroilles** (signature regional pies); on plateau de fromages; pairs with regional Northern French beer (Bières du Nord) rather than wine.', '["wheel-full-720g", "wheel-full-540g", "wheel-full-360g", "wheel-full-180g", "gift-pack-twin-500g"]'::jsonb, '[]'::jsonb, '["Maroilles", "Marolles", "Maroles (historical)"]'::jsonb, FALSE, 'L2'),
  ('f937e159-8992-aedc-cb6b-93d0566e54c3', 'FR', 'France', 'cheeses_dairy', 'Mont d''Or AOP', '["Mont d''Or AOP", "Vacherin du Haut-Doubs AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Franche-Comté cow''s milk soft washed-rind cheese, distinctively cradled in spruce-bark "boîte d''épicéa", aged minimum 21 days. Salmon-orange rind, almost-liquid ivory paste at peak, intensely creamy texture, fragrant with characteristic spruce-resin aroma and savory-fungal-buttery flavor — produced ONLY September 15 to May 15 (seasonal AOP rule).', '**Boîte chaude** — entire cheese baked in its spruce box with garlic and white wine, eaten with potatoes and charcuterie — the iconic Mont d''Or service; on plateau de fromages; spread on bread.', '["boîte-épicéa-450g", "boîte-épicéa-800g", "boîte-épicéa-2kg", "boîte-épicéa-3kg"]'::jsonb, '[9, 10, 11, 12, 1, 2, 3, 4, 5]'::jsonb, '["Mont d''Or", "Vacherin du Haut-Doubs", "Vacherin (commercial term often used)"]'::jsonb, FALSE, 'L2'),
  ('5f81edca-dd8b-8c93-d1ea-3b5edca54bb6', 'FR', 'France', 'cheeses_dairy', 'Morbier AOP', '["Morbier AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Franche-Comté cow''s milk pressed uncooked cheese with distinctive horizontal black ash line through the middle (historical practice of layering morning and evening curd). Aged 45+ days. Pinkish-orange washed rind, pale ivory paste split by signature ash band, supple semi-firm texture, mild fruity-creamy flavor with hint of cellar-mushroom and gentle bitter-tang from ash layer.', 'Plateau de fromages (visual showpiece — the ash line); melted in tartiflette variations; in raclette-style hot service; pairs with Vin Jaune and Arbois reds.', '["wheel-full-5-8kg", "wheel-half-vacuum-3kg", "wedge-vacuum-500g", "wedge-vacuum-200g"]'::jsonb, '[]'::jsonb, '["Morbier"]'::jsonb, FALSE, 'L2'),
  ('4fb03a74-943c-ceef-2047-75514aa8f319', 'FR', 'France', 'cheeses_dairy', 'Munster AOP', '["Munster AOP", "Munster-Géromé AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Vosges cow''s milk washed-rind soft cheese, aged 21+ days (often longer). Bright orange shiny rind, ivory paste, soft creamy texture, intensely aromatic with assertive farmyard notes, salty-savory tangy flavor — among France''s most pungent cheeses.', 'Plateau de fromages; baked Munster with cumin and potatoes (Alsatian tradition); pairs with Gewurztraminer (regional pairing) and Pinot Gris d''Alsace; cumin seeds traditional accompaniment.', '["wheel-full-450g", "wheel-full-1.5kg", "wheel-half-vacuum-225g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Munster", "Munster-Géromé", "Géromé (Lorraine name)"]'::jsonb, FALSE, 'L2'),
  ('d83d58d9-880d-c3fa-f133-c18fa4bfd157', 'FR', 'France', 'cheeses_dairy', 'Neufchâtel AOP', '["Neufchâtel AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Normandy cow''s milk soft bloomy-rind cheese in iconic heart shape (also brick, square, log, drum). Aged 10+ days. White Penicillium rind, ivory paste, creamy semi-soft texture, mild buttery-mushroom flavor with characteristic salty-savory finish — among France''s oldest cheeses (12th century origin).', 'Plateau de fromages (visual heart-shape charm); romantic-themed service for Valentine''s; pairs with cidre fermier and Pommeau de Normandie.', '["heart-shape-200g", "heart-shape-600g", "brick-100g", "brick-200g", "log-200g", "gift-pack-heart-200g"]'::jsonb, '[]'::jsonb, '["Neufchâtel", "Bondart (heart shape historical name)"]'::jsonb, FALSE, 'L2'),
  ('b5deb6a7-86eb-6ecd-bb24-61290fb75669', 'FR', 'France', 'cheeses_dairy', 'Ossau-Iraty AOP', '["Ossau-Iraty AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Basque-Béarn raw sheep''s milk pressed uncooked cheese, aged 80-180+ days. Pale ivory to amber paste, firm yielding texture, characteristic sheep-milk flavor with sweet-floral notes (mountain pasture: sage, thyme, fennel) evolving to caramel-nutty when aged. Two terroirs: Pays Basque (Iraty) and Béarn (Ossau).', '**Plateau de fromages with cherry preserve** (confiture de cerises noires d''Itxassou — the canonical pairing); shaved on salads; in Basque country dégustation menus; pairs with Jurançon and Irouléguy.', '["wheel-full-2-7kg", "wheel-half-vacuum-1.5kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Ossau-Iraty", "Ardi-Gasna (Basque)", "Fromage de Brebis (generic)", "Esbareich (sub-style)"]'::jsonb, FALSE, 'L2'),
  ('ae36b4d2-5057-4cb2-31cf-f9db463d7b69', 'FR', 'France', 'cheeses_dairy', 'Pélardon AOP', '["Pélardon AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Cévennes-Languedoc goat''s milk small button-shaped cheese aged 11+ days. Ivory paste with thin natural rind that evolves from white-floral to grey-bluish with age, soft to semi-firm texture, balanced fresh tangy-goat flavor with herbaceous Cévenol notes.', 'Plateau de fromages with chèvre selection; warmed on toast for salades estivales; pairs with Saint-Chinian and Pic Saint-Loup.', '["single-button-60g", "gift-pack-6x60g", "gift-pack-12x60g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Pélardon", "Pélardon des Cévennes"]'::jsonb, FALSE, 'L2'),
  ('5c8ee7d0-f2f7-7ed4-328f-35fc0a62910d', 'FR', 'France', 'cheeses_dairy', 'Picodon AOP', '["Picodon AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Drôme-Ardèche goat''s milk small disk cheese aged 14+ days, often longer for Picodon affiné méthode Dieulefit (rinsed in eau-de-vie). Ivory paste with thin natural rind evolving from white-cream to grey-blue, semi-firm to firm texture, balanced tangy goat flavor with herbal-grassy notes; aged Méthode Dieulefit develops sharp savory complexity.', 'Plateau de fromages chèvre selection; on toast with honey and walnuts; pairs with Côtes-du-Rhône, Crozes-Hermitage.', '["single-disk-60g", "gift-pack-6x60g", "méthode-Dieulefit-100g aged"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Picodon", "Picodon de l''Ardèche", "Picodon de la Drôme", "Méthode Dieulefit"]'::jsonb, FALSE, 'L2'),
  ('4282af9e-7a44-77a8-2c5e-87973bd607e4', 'FR', 'France', 'cheeses_dairy', 'Pont-l''Évêque AOP', '["Pont-l''Évêque AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Normandy cow''s milk square-shaped washed-rind soft cheese, aged 18+ days. Pale gold-orange rind, pale ivory paste, supple creamy texture, balanced flavor with mild farmyard notes and sweet-grassy finish — milder than Livarot, more refined than industrial washed-rind cheeses.', 'Plateau de fromages Norman selection; with sliced apple; pairs with cidre and Calvados.', '["square-block-220g", "square-block-1kg", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Pont-l''Évêque", "Pont-l''Évêque petit (small format)"]'::jsonb, FALSE, 'L2'),
  ('f00e3c0d-5b9a-1e90-2359-a75bf0773274', 'FR', 'France', 'cheeses_dairy', 'Pouligny-Saint-Pierre AOP', '["Pouligny-Saint-Pierre AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Berry goat''s milk pyramid-shaped soft cheese (truncated pyramid, the "Eiffel Tower of cheese"), aged 10+ days. Ivory paste with thin natural rind evolving from white-cream to bluish, semi-soft to firm texture, fresh tangy goat flavor with grassy and almond notes.', 'Plateau de fromages chèvre selection (visual showpiece); pairs with Sancerre, Quincy, Reuilly; on toast with honey.', '["pyramid-250g", "pyramid-150g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Pouligny-Saint-Pierre", "Pyramide de Pouligny", "Tour Eiffel (nickname)"]'::jsonb, FALSE, 'L2'),
  ('e81bf021-f63e-dfb7-7eaa-9101beddfeee', 'FR', 'France', 'cheeses_dairy', 'Reblochon AOP', '["Reblochon AOP", "Reblochon de Savoie AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Savoyard cow''s milk washed-rind soft pressed cheese, aged 21+ days. Saffron-orange rind, ivory paste, supple creamy texture, mild buttery-fruity-hazelnut flavor with delicate alpine-grass notes — the iconic Savoyard cheese.', '**Tartiflette** (essential — the Reblochon is melted whole on top of potatoes and lardons, the iconic French alpine après-ski dish); on plateau de fromages; classic with Savoyard wines; in croziflette and other regional gratins.', '["wheel-full-450g", "wheel-full-280g", "wheel-half-vacuum-225g"]'::jsonb, '[]'::jsonb, '["Reblochon", "Reblochon de Savoie", "Reblochon fermier", "Reblochonnet"]'::jsonb, FALSE, 'L2'),
  ('063a1a1b-fe4c-4094-d1b8-c95db22c421c', 'FR', 'France', 'cheeses_dairy', 'Rocamadour AOP', '["Rocamadour AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Quercy goat''s milk small disk-shaped soft cheese aged 6+ days. Ivory paste with thin pale rind, semi-soft to creamy texture, mild fresh tangy goat flavor with sweet-floral notes — among France''s most accessible chèvres.', 'Plateau de fromages chèvre selection; warmed on toast; in salade au chèvre chaud; pairs with Cahors and Bergerac.', '["single-disk-35g", "gift-pack-6x35g", "gift-pack-12x35g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Rocamadour", "Cabécou de Rocamadour (historical)"]'::jsonb, FALSE, 'L2'),
  ('b9910610-de5f-b94f-cb16-b50966813542', 'FR', 'France', 'cheeses_dairy', 'Roquefort AOP', '["Roquefort AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aveyron raw sheep''s milk blue cheese aged in caves of Combalou near Roquefort-sur-Soulzon, minimum 90 days, often 5-9 months. Ivory paste richly veined with assertive blue-green Penicillium roqueforti, semi-soft moist crumbly texture, intensely savory flavor with saltiness, sharp blue tang, and complex sweet-buttery sheep-milk base — France''s oldest documented cheese, AOP since 1925 (the first ever).', '**The plateau de fromages climax** — placed last, eaten last; **Roquefort sauce** for steak; crumbled in salade aux noix; with poire belle and walnut bread; **mandatory pairing with Sauternes** (canonical Roquefort-Sauternes association); also Banyuls, Maury, late-harvest sweet wines.', '["wheel-full-2.5-3kg", "wheel-half-vacuum-1.5kg", "wedge-vacuum-300g", "wedge-vacuum-150g", "wedge-vacuum-100g", "crumbled-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Roquefort", "Bleu de Brebis (generic)", "Le Roi des Fromages (alongside Brie de Meaux)"]'::jsonb, FALSE, 'L2'),
  ('159abf1d-cc1d-9add-b56e-f746f6b4614f', 'FR', 'France', 'cheeses_dairy', 'Saint-Nectaire AOP', '["Saint-Nectaire AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Auvergne cow''s milk pressed uncooked cheese, aged 28+ days on rye-straw mats (which leave characteristic basket-weave pattern on rind). Greyish-white rind speckled with yellow-orange-pink molds, ivory paste, supple creamy texture, balanced flavor with hazelnut-mushroom-cellar notes and characteristic earthy terroir character.', 'Plateau de fromages; melted in Auvergne aligot variations; pairs with Chanturgue and Côtes d''Auvergne wines.', '["wheel-full-1.7kg", "wheel-half-vacuum-850g", "wedge-vacuum-300g", "wedge-vacuum-150g"]'::jsonb, '[]'::jsonb, '["Saint-Nectaire", "Saint-Nectaire fermier", "Saint-Nectaire laitier"]'::jsonb, FALSE, 'L2'),
  ('b13a9261-b498-26a4-2da8-3aa3e98c9934', 'FR', 'France', 'cheeses_dairy', 'Sainte-Maure de Touraine AOP', '["Sainte-Maure de Touraine AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Touraine goat''s milk distinctive log-shaped cheese with central straw running lengthwise (rye straw), traditionally rolled in vegetable-charcoal ash, aged 10+ days. Charcoal-grey to white-cream rind, ivory paste, semi-soft texture, balanced fresh tangy goat flavor with hazelnut and grass notes.', '**Plateau de fromages chèvre selection** (visual signature — the log with straw and ash); sliced for salade aux noix; pairs with Vouvray, Touraine Sauvignon.', '["single-log-250g", "gift-pack-twin-500g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Sainte-Maure de Touraine", "Sainte-Maure (without geographic suffix)", "Saint Maure (variant spelling)"]'::jsonb, FALSE, 'L2'),
  ('0c7471ea-7d9c-6835-502e-3ee9140c3a7f', 'FR', 'France', 'cheeses_dairy', 'Salers AOP', '["Salers AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Cantal cow''s milk pressed uncooked cheese, AOP-restricted to lait cru from Salers-breed cows on summer pastures (May 1 to October 31 production only). Pale ivory to amber paste, firm crumbly texture, intensely tangy-savory flavor with assertive grass-pasture notes and pronounced terroir character — the wildest, most artisanal of Cantal-family cheeses.', 'Plateau de fromages premium Auvergne; in aligot de tradition; centerpiece of Cantal-Auvergne dégustation.', '["wheel-full-35-50kg", "wheel-quarter-vacuum-9-12kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[5, 6, 7, 8, 9, 10]'::jsonb, '["Salers", "Salers Tradition", "Salers Haute-Montagne"]'::jsonb, FALSE, 'L2'),
  ('06522fab-aa7a-502f-0321-6d981b5c40e7', 'FR', 'France', 'cheeses_dairy', 'Selles-sur-Cher AOP', '["Selles-sur-Cher AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Loire Valley goat''s milk small round cheese rolled in vegetable-charcoal ash, aged 10+ days. Charcoal-grey to white-cream rind, ivory paste, semi-soft texture, balanced fresh tangy goat flavor with delicate hazelnut and grass notes.', 'Plateau de fromages chèvre selection; warmed on toast with honey; pairs with Sancerre, Pouilly-Fumé, Touraine.', '["single-disk-150g", "gift-pack-twin-300g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Selles-sur-Cher"]'::jsonb, FALSE, 'L2'),
  ('41183316-eda2-3423-4c8a-5755ffd5a721', 'FR', 'France', 'cheeses_dairy', 'Tome des Bauges AOP', '["Tome des Bauges AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Savoie cow''s milk pressed uncooked cheese from Massif des Bauges, aged 90+ days. Greyish-brown natural rind, ivory paste, supple semi-firm texture, mild milky flavor with characteristic cellar-mushroom and alpine-grass notes — gentler than Beaufort or Abondance.', 'Plateau de fromages Savoyard selection; in tartiflette variations; pairs with Apremont and Roussette de Savoie.', '["wheel-full-1.2kg", "wheel-half-vacuum-600g", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Tome des Bauges", "Toma des Bauges (Savoyard spelling)"]'::jsonb, FALSE, 'L2'),
  ('821c2038-4812-eb6e-f8f9-9c28b658f84f', 'FR', 'France', 'cheeses_dairy', 'Valençay AOP', '["Valençay AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Berry goat''s milk truncated pyramid-shaped cheese rolled in vegetable-charcoal ash, aged 11+ days. Charcoal-grey to white rind, ivory paste, semi-soft texture, balanced fresh tangy goat flavor — visually similar to Pouligny-Saint-Pierre but with ash coat and characteristic flat-top shape (legend: Napoleon ordered the top cut after disastrous Spanish campaign).', 'Plateau de fromages chèvre selection (visual showpiece); pairs with Reuilly, Sancerre, Touraine.', '["truncated-pyramid-220g", "truncated-pyramid-mini-110g"]'::jsonb, '[3, 4, 5, 6, 7, 8, 9, 10]'::jsonb, '["Valençay", "Valencay (variant spelling)"]'::jsonb, FALSE, 'L2'),
  ('94303a4d-63c6-1afc-10a8-34f8ca780439', 'FR', 'France', 'cheeses_dairy', 'Saint-Marcellin IGP', '["Saint-Marcellin IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Dauphiné cow''s milk small soft cheese aged 10+ days. Thin pinkish-cream rind develops with age, ivory paste, soft to oozing texture at peak, mild buttery-mushroom flavor with delicate tangy finish.', 'Plateau de fromages; **caillé / very runny stage classic French bistro service** (eaten with spoon from terra-cotta dish "faisselle" or spread on bread); pairs with Saint-Joseph and Crozes-Hermitage.', '["single-disk-80g", "single-disk-100g", "gift-pack-6x80g", "terra-cotta-faisselle-150g"]'::jsonb, '[]'::jsonb, '["Saint-Marcellin"]'::jsonb, FALSE, 'L2'),
  ('d0f391eb-387a-2cb3-778a-b7d64f10dd4e', 'FR', 'France', 'cheeses_dairy', 'Tomme de Savoie IGP', '["Tomme de Savoie IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Savoie cow''s milk pressed uncooked cheese, IGP since 1996, aged 30-90+ days. Greyish-brown natural rind with characteristic mottled molds, ivory paste with small eyes, supple semi-firm texture, mild lactic-buttery flavor with delicate hazelnut and cellar notes — among the most consumed French cheeses, available in lait entier and mi-grasse versions.', 'Plateau de fromages everyday option; in raclette and gratins; melted in tartines; cubed in salads.', '["wheel-full-1.5-2kg", "wheel-half-vacuum-1kg", "wedge-vacuum-500g", "wedge-vacuum-250g"]'::jsonb, '[]'::jsonb, '["Tomme de Savoie", "Tomme savoyarde"]'::jsonb, FALSE, 'L2'),
  ('92f6393b-b865-a024-6cee-4fa10c0d44b1', 'FR', 'France', 'cheeses_dairy', 'Emmental de Savoie IGP', '["Emmental de Savoie IGP", "Emmental français est-central IGP"]'::jsonb, 'PGI', '["PGI", "PGI"]'::jsonb, 'Savoyard or central-eastern France cow''s milk pressed cooked cheese (Swiss Emmental''s French cousin), aged 10+ weeks, characterized by large round eyes (the "trous"). Pale ivory-yellow paste, firm dense texture, mild buttery-fruity flavor with characteristic hazelnut-grass notes — milder than Comté, more fruity than industrial Emmental.', 'Volume cheese for fondue, gratin dauphinois, croque-monsieur, cheese sandwiches, melt-in cooking; cubed in salads; the workhorse French restaurant cheese.', '["wheel-full-70-100kg", "wheel-quarter-vacuum-15-25kg", "wedge-vacuum-500g", "wedge-vacuum-250g", "cubed-pack-200g", "sliced-pack-150g", "grated-pre-pack-100g"]'::jsonb, '[]'::jsonb, '["Emmental de Savoie", "Emmental français est-central", "Emmental français"]'::jsonb, FALSE, 'L2'),
  ('60f67733-51d6-8f9c-89e4-8195b31a8b7b', 'FR', 'France', 'cured_meats_charcuterie', 'Andouille de Vire IGP', '["Andouille de Vire IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Norman cooked sausage made from concentric rolls of pork tripe and chitterlings, smoked over beechwood. Distinctive concentric circular cross-section pattern, dark mahogany skin, robust smoky-savory flavor with farmyard offal character.', 'Sliced thick on Norman charcuterie boards; warmed in pommes au cidre; classic Norman bistro starter; pairs with cidre fermier.', '["whole-piece-vacuum-400-700g", "half-piece-vacuum-300g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Andouille de Vire", "Vire andouille"]'::jsonb, FALSE, 'L2'),
  ('71cd1a82-03ab-8abd-0fcb-968053726828', 'FR', 'France', 'cured_meats_charcuterie', 'Andouille de Guémené IGP (proposed', '["Andouille de Guémené IGP (proposed", "pending status — listed for comprehensive coverage)"]'::jsonb, 'PGI', '["PGI", "OTHER"]'::jsonb, 'Breton concentric tripe-roll cooked sausage from Guémené-sur-Scorff. Similar style to Andouille de Vire but smoked differently and with regional variations.', 'Breton charcuterie boards; pairs with Breton beer and cidre.', '["whole-piece-vacuum-400-700g"]'::jsonb, '[]'::jsonb, '["Andouille de Guémené"]'::jsonb, FALSE, 'L2'),
  ('4267c0b2-511d-c21b-31dd-663a42ca8114', 'FR', 'France', 'cured_meats_charcuterie', 'Boudin blanc de Rethel IGP', '["Boudin blanc de Rethel IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Champenois white sausage made from milk-soaked breadcrumbs and minced veal/pork, traditionally seasoned with mace, nutmeg, pepper. Pale ivory color, very fine smooth texture, delicately flavored with characteristic dairy-spice profile.', 'Pan-fried in butter as Christmas-season classic; served with apples Calvados or Champenois mustard; in cocottes Champenoises.', '["vacuum-pack-fresh-200g", "vacuum-pack-fresh-400g", "gift-pack-300g"]'::jsonb, '[11, 12, 1]'::jsonb, '["Boudin blanc de Rethel", "White pudding Rethel"]'::jsonb, FALSE, 'L2'),
  ('f981f36f-500c-74f7-7c08-2569147fbc78', 'FR', 'France', 'cured_meats_charcuterie', 'Coppa de Corse AOP', '["Coppa de Corse AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Corsican cured pork shoulder/neck (analogous to Italian coppa) from local pig breeds (Nustrale primarily), aged minimum 7 months. Deep ruby meat with marbled fat, dense firm texture, intensely savory flavor with herb-de-maquis notes (fennel, juniper, myrtle from acorn-and-chestnut diet).', 'Premium Corsican charcuterie board; thinly sliced for antipasto; pairs with Corsican wines (Patrimonio, Ajaccio).', '["whole-piece-vacuum-1.5-2.5kg", "deli-sliced-vacuum-100g", "gift-sliced-pack-200g"]'::jsonb, '[]'::jsonb, '["Coppa di Corsica", "Corsican coppa"]'::jsonb, FALSE, 'L2'),
  ('4b14aa1b-09af-d016-ec2c-6cf2335d731d', 'FR', 'France', 'cured_meats_charcuterie', 'Lonzo de Corse AOP', '["Lonzo de Corse AOP", "Lonzu de Corse AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Corsican cured pork loin (analogous to Italian lonza) from Nustrale pigs, aged minimum 4 months. Deep red lean meat with thin fat cap, firm texture, intense savory pork flavor with characteristic Corsican-maquis aromatic profile from chestnut-acorn diet.', 'Corsican charcuterie board (with Coppa and Prisuttu); thinly sliced; pairs with Corsican AOP wines.', '["whole-piece-vacuum-1-1.5kg", "deli-sliced-vacuum-100g", "gift-sliced-pack-200g"]'::jsonb, '[]'::jsonb, '["Lonzo de Corse", "Lonzu", "Corsican loin"]'::jsonb, FALSE, 'L2'),
  ('6c4e946c-12fc-24de-ba5c-0f8e4f239534', 'FR', 'France', 'cured_meats_charcuterie', 'Prisuttu de Corse AOP', '["Prisuttu de Corse AOP", "Jambon sec de Corse AOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Corsican dry-cured ham from Nustrale pigs, aged minimum 12 months (often 24+). Deep ruby meat with marbled fat, dense firm texture, intensely complex flavor combining sweet pork base with maquis-influenced aromatic notes (chestnut, juniper, fennel) — the most prized Corsican charcuterie product.', 'Premium Corsican antipasto, sliced very thin; centerpiece of Corsican dégustation menus; pairs with Patrimonio and Vin de Corse.', '["whole-leg-bone-in-6-9kg", "whole-leg-boneless-vacuum-5-7kg", "deli-sliced-vacuum-100g", "gift-sliced-pack-200g"]'::jsonb, '[]'::jsonb, '["Prisuttu", "Prisuttu di Corsica", "Jambon sec de Corse", "Corsican ham"]'::jsonb, FALSE, 'L2'),
  ('c2163bdb-bfa8-671b-5eca-c1fb38698b3d', 'FR', 'France', 'cured_meats_charcuterie', 'Jambon de Bayonne IGP', '["Jambon de Bayonne IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Basque-Béarn dry-cured ham from south-west France, aged minimum 7 months (often 9-12+), salted with Salies-de-Béarn salt. Deep rosy meat with white fat cap, delicate sweet-salty flavor, characteristic floral-aromatic profile, less aggressive than Italian counterparts.', 'Sliced thin for plateau de charcuterie; classic with melon (jambon-melon); in piperade and pipérade-jambon; with Basque pelota-game cheese; pairs with Jurançon and Irouléguy.', '["whole-leg-bone-in-7-9kg", "whole-leg-boneless-vacuum-5-7kg", "half-leg-vacuum-3kg", "deli-sliced-vacuum-100g", "deli-sliced-vacuum-80g", "pre-sliced-tray-150g"]'::jsonb, '[]'::jsonb, '["Jambon de Bayonne", "Bayonne ham"]'::jsonb, FALSE, 'L2'),
  ('a1447ae7-7cea-3139-f05c-bd3532b2b223', 'FR', 'France', 'cured_meats_charcuterie', 'Jambon de Lacaune IGP', '["Jambon de Lacaune IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Tarn dry-cured ham from Lacaune mountains, aged minimum 7 months. Deep ruby meat, balanced sweet-salty flavor with characteristic mountain-aged character.', 'Plateau de charcuterie alongside Bayonne; sliced thin; pairs with Languedoc wines.', '["whole-leg-bone-in-7-9kg", "whole-leg-boneless-vacuum-5-7kg", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Jambon de Lacaune"]'::jsonb, FALSE, 'L2'),
  ('03f48942-01f5-0b76-b011-ac65fe193332', 'FR', 'France', 'cured_meats_charcuterie', 'Jambon noir de Bigorre AOP', '["Jambon noir de Bigorre AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Pyrenean dry-cured ham from Porc Noir de Bigorre breed (rare native black pig), aged minimum 20 months (often 30-36). Very dark meat with rich golden-marbled fat, dense complex texture, intensely flavored with deep umami, walnut, and characteristic chestnut-fed pork notes — France''s most prestigious dry-cured ham (limited production).', 'Premium tasting-menu antipasto, very thinly sliced; minimal accompaniment to highlight flavor; pairs with Madiran and Pacherenc-du-Vic-Bilh.', '["whole-leg-bone-in-7-10kg", "whole-leg-boneless-vacuum-5-8kg", "deli-sliced-vacuum-80g", "gift-sliced-pack-100g"]'::jsonb, '[]'::jsonb, '["Jambon noir de Bigorre", "Porc Noir de Bigorre ham", "Noir de Bigorre"]'::jsonb, FALSE, 'L2'),
  ('cad782d5-fc3c-21c1-7c22-70271259b5cd', 'FR', 'France', 'cured_meats_charcuterie', 'Saucisse de Morteau IGP', '["Saucisse de Morteau IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Franche-Comté smoked pork sausage with characteristic wooden peg ("cheville") closure, smoked over conifer wood in traditional tuyé chimney. Coarse-ground pork, distinctive deep-smoky flavor, robust texture, balanced spicing with garlic and pepper.', 'Poached and sliced over potato salad (potée comtoise); with lentilles vertes du Puy; in cassoulet variations; classic Franc-Comtois bistro dish.', '["whole-piece-vacuum-300-400g", "whole-piece-vacuum-500g", "pre-cooked-vacuum-300g"]'::jsonb, '[]'::jsonb, '["Saucisse de Morteau", "Belle de Morteau (premium grade)"]'::jsonb, FALSE, 'L2'),
  ('63025452-4158-9f72-0e2f-1d096f238282', 'FR', 'France', 'cured_meats_charcuterie', 'Saucisse de Montbéliard IGP', '["Saucisse de Montbéliard IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Franche-Comté smoked pork sausage from Montbéliard area, similar to Morteau but smaller, finer-textured, distinctively flavored with cumin (the differentiator from Morteau). Characteristic smoke profile from beechwood.', 'Same applications as Morteau but more delicate; in salade comtoise; with comté cheese; pan-fried with shallots.', '["whole-piece-vacuum-150-250g", "twin-pack-300g"]'::jsonb, '[]'::jsonb, '["Saucisse de Montbéliard"]'::jsonb, FALSE, 'L2'),
  ('8549ae48-d74b-fbee-2cf1-a3e3228e6bd9', 'FR', 'France', 'cured_meats_charcuterie', 'Saucisson sec d''Auvergne IGP', '["Saucisson sec d''Auvergne IGP", "Saucisse sèche d''Auvergne IGP"]'::jsonb, 'PGI', '["PGI", "PGI"]'::jsonb, 'Auvergne dry-cured pork salami, aged 21+ days. Coarse-ground pork with visible white fat cubes, balanced pork-and-pepper flavor with garlic notes, firm chewy texture.', 'Plateau de charcuterie classic French bistro selection; aperitif slicing; cubed for picnic and outdoor service; pairs with Côtes d''Auvergne and Saint-Pourçain.', '["whole-piece-vacuum-200-300g", "half-piece-vacuum-150g", "deli-sliced-vacuum-100g", "mini-saucisson-80g"]'::jsonb, '[]'::jsonb, '["Saucisson sec d''Auvergne", "Saucisse sèche d''Auvergne", "Auvergne saucisson"]'::jsonb, FALSE, 'L2'),
  ('8cf03ce6-64ad-ed48-42a8-6a0f745553de', 'FR', 'France', 'cured_meats_charcuterie', 'Pâté de Campagne Breton IGP', '["Pâté de Campagne Breton IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Breton coarse-ground pork pâté with characteristic chunky texture, traditional rustic preparation with onion, herbs, and Breton flavor profile. Brown-pink color, dense moist texture, robust pork-savory flavor with onion and herb notes.', 'Plateau de charcuterie / tapas service; spread on country bread with cornichons and Breton butter; classic Breton bistro starter; pairs with Muscadet.', '["terrine-200g", "terrine-400g", "sliced-vacuum-200g", "gift-pack-2x200g", "professional-bulk-1kg"]'::jsonb, '[]'::jsonb, '["Pâté de Campagne Breton", "Breton country pâté"]'::jsonb, FALSE, 'L2'),
  ('adf2ab91-d8b0-1ff6-c406-01993558040f', 'FR', 'France', 'cured_meats_charcuterie', 'Rillettes de Tours IGP', '["Rillettes de Tours IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Touraine slow-cooked pork rillettes (shredded confit pork preserved in its own fat). Pale-rose to golden color depending on cooking, fibrous shredded texture, rich pork flavor with characteristic Touraine seasoning (salt, pepper, white wine).', 'Spread on toast or country bread for plateau de charcuterie; classic French bistro starter; pairs with Vouvray and Touraine wines.', '["terrine-glass-150g", "terrine-glass-300g", "professional-bulk-1kg"]'::jsonb, '[]'::jsonb, '["Rillettes de Tours", "Tours rillettes", "Rillettes tourangelles"]'::jsonb, FALSE, 'L2'),
  ('499fdb27-09a7-862f-0297-6c3497fa22c4', 'FR', 'France', 'cured_meats_charcuterie', 'Rillettes du Mans IGP (proposed; verify Layer 1 status)', '["Rillettes du Mans IGP (proposed; verify Layer 1 status)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Le Mans pork rillettes, similar to Tours but with regional preparation differences.', 'Same as Tours rillettes.', '["terrine-glass-150g", "terrine-glass-300g"]'::jsonb, '[]'::jsonb, '["Rillettes du Mans"]'::jsonb, FALSE, 'L2'),
  ('b2800a91-9de5-b790-6874-225a5b743bb4', 'FR', 'France', 'cured_meats_charcuterie', 'Volaille de Bresse AOP', '["Volaille de Bresse AOP", "Poulet de Bresse AOP", "Chapon de Bresse AOP"]'::jsonb, 'PDO', '["PDO", "PDO", "PDO"]'::jsonb, 'Bresse-Bressois (Ain-Saône-et-Loire-Jura) free-range poultry from Bresse-Gauloise breed, the only AOP poultry in France. Distinctive blue feet, white plumage, red comb (the "tricolore"). White-pink meat with golden fat marbling, intensely flavored with characteristic walnut-grass-corn-fed notes, firm meaty texture, low water-loss when cooking. **Chapon de Bresse** (capon, castrated male) is the Christmas-luxury variant — larger, fattier, more tender.', '**Premium restaurant centerpiece** — Volaille de Bresse à la crème, en vessie (cooked in pig bladder, classic Bocuse), rotisseried; chapon for Christmas service; pairs with Champagne and white Burgundy.', '["whole-bird-fresh-1.5-2kg", "whole-bird-fresh-3-4kg", "eviscerated-vacuum-1.5-2kg", "gift-bird-Christmas-3-5kg", "leg-portion-300g", "breast-portion-200g"]'::jsonb, '[]'::jsonb, '["Volaille de Bresse", "Poulet de Bresse", "Chapon de Bresse", "Poularde de Bresse", "Dinde de Bresse", "Bresse chicken"]'::jsonb, FALSE, 'L2'),
  ('57b964e4-6a5d-cb3d-d140-c365bcfebe41', 'FR', 'France', 'cured_meats_charcuterie', 'Volailles d''Alsace IGP', '["Volailles d''Alsace IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Alsatian free-range poultry IGP. Distinctive yellow-skinned chicken (corn-fed) with firm meaty white-pink flesh, robust farm-raised flavor.', 'Roasted whole, in coq au Riesling and Alsatian poultry preparations; pairs with Riesling and Pinot Gris.', '["whole-bird-fresh-1.5-2.5kg", "eviscerated-vacuum-1.5-2.5kg", "leg-portion-300g", "breast-portion-200g"]'::jsonb, '[]'::jsonb, '["Volailles d''Alsace", "Poulet jaune d''Alsace", "Alsatian chicken"]'::jsonb, FALSE, 'L2'),
  ('5e2e2634-00be-d33d-d7a9-c16fae1f725f', 'FR', 'France', 'cured_meats_charcuterie', 'Volailles d''Ancenis IGP', '["Volailles d''Ancenis IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Loire-Atlantique free-range poultry from Ancenis area. Firm flavorful flesh.', 'Loire Valley regional poultry preparations; pairs with Muscadet and Anjou wines.', '["whole-bird-fresh-1.5-2kg", "eviscerated-vacuum-1.5-2kg", "leg-portion-300g"]'::jsonb, '[]'::jsonb, '["Volailles d''Ancenis"]'::jsonb, FALSE, 'L2'),
  ('1f4a2897-a030-7ec0-4198-48613e2439b4', 'FR', 'France', 'cured_meats_charcuterie', 'Volailles d''Auvergne IGP', '["Volailles d''Auvergne IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Auvergne free-range poultry IGP. Robust flavored flesh from highland farming.', 'Auvergne regional preparations; with Saint-Nectaire and Cantal cheese sauces.', '["whole-bird-fresh-1.5-2kg"]'::jsonb, '[]'::jsonb, '["Volailles d''Auvergne"]'::jsonb, FALSE, 'L2'),
