  ('7ccb0f77-2242-2de1-4852-e2de33f0e230', 'FR', 'France', 'cured_meats_charcuterie', 'Volailles de Vendée IGP', '["Volailles de Vendée IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Vendée free-range poultry IGP, including duck. Distinctive Atlantic-marsh saline grazing.', 'Vendée regional preparations; alongside Challans duck.', '["whole-bird-fresh-1.5-2.5kg"]'::jsonb, '[]'::jsonb, '["Volailles de Vendée"]'::jsonb, FALSE, 'L2'),
  ('7782c133-92a8-4b8e-f0c0-e4a05e075399', 'FR', 'France', 'cured_meats_charcuterie', 'Bœuf de Charolles AOP', '["Bœuf de Charolles AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Burgundian beef from Charolais breed (Saône-et-Loire-Allier-Loire), AOP since 2010 — the only AOP beef in France. Bright cherry-red lean meat with white-cream marbling, characteristic Charolais texture (firm-but-yielding, well-marbled), intensely flavored with sweet-savory beefy character — France''s most prestigious beef appellation.', '**Premium steakhouse beef** — entrecôte, faux-filet, filet, côte de bœuf for-two; aged dry for 21-45 days; centerpiece of Charolais-Burgundian dégustation; pairs with Pommard, Volnay, Côte de Beaune.', '["carcass-side-150-200kg", "primal-cuts-vacuum-various", "faux-filet-1-2kg", "entrecôte-300-400g", "filet-200-300g", "côte-de-bœuf-1-1.5kg", "dry-aged-pavé-200-300g"]'::jsonb, '[]'::jsonb, '["Bœuf de Charolles", "Charolais Burgundy beef"]'::jsonb, FALSE, 'L2'),
