  ('edaa09e7-77ef-b5d9-ff03-ade4e4261384', 'FR', 'France', 'cured_meats_charcuterie', 'Bœuf de Vendée IGP', '["Bœuf de Vendée IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Vendée beef IGP. Firm beef from Atlantic-coastal farming.', 'Western France regional preparations.', '["Same as other beef IGPs"]'::jsonb, '[]'::jsonb, '["Bœuf de Vendée"]'::jsonb, FALSE, 'L2'),
