  ('63cf7ceb-dd4a-9b7f-e36b-e2eb26c56c38', 'FR', 'France', 'cured_meats_charcuterie', 'Veau du Limousin IGP', '["Veau du Limousin IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Limousin veal IGP from heritage Limousine breed milk-fed calves. Pale pink fine flesh, delicate flavor.', 'Premium veal preparations; pairs with Bordeaux whites.', '["Same as Aveyron veal"]'::jsonb, '[]'::jsonb, '["Veau du Limousin", "Limousin veal"]'::jsonb, FALSE, 'L2'),
  ('0c890e50-7e14-d06a-1742-4fc99f64ff51', 'FR', 'France', 'cured_meats_charcuterie', 'Agneau de l''Aveyron IGP', '["Agneau de l''Aveyron IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Aveyron lamb IGP from Roquefort sheep-area farming (Lacaune breed primarily, lacaune-laitière for Roquefort). Lean pink meat, delicate sweet flavor with grass-fed character.', 'Premium spring lamb preparations — gigot, côtes, navarin; classic Easter-spring service; pairs with Saint-Chinian, Faugères.', '["carcass-half-10-15kg", "primal-cuts-vacuum-various", "gigot-2-3kg", "côtes-rack-800g-1.2kg", "épaule-1-1.5kg"]'::jsonb, '[3, 4, 5, 6]'::jsonb, '["Agneau de l''Aveyron"]'::jsonb, FALSE, 'L2'),
