  ('76c7a19f-516b-1456-7b6b-bf00f987d4f3', 'FR', 'France', 'fruits_nuts', 'Pomme de terre de l''Île de Ré AOP', '["Pomme de terre de l''Île de Ré AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Charente-Maritime island potato AOP from Île de Ré, multiple early varieties (Alcmaria, Starlette, Charlotte). Distinctive small-medium new-season potato with thin skin, creamy yellow flesh, slightly salty sea-influenced flavor (terroir effect from coastal sandy soil).', '**Premium new potato for spring/summer service** — boiled or steamed with butter, in salade landaise, with Charente-Poitou butter; Atlantic-coast restaurant centerpiece.', '["crate-fresh-2.5kg", "crate-fresh-5kg", "retail-tray-1kg", "mesh-bag-500g"]'::jsonb, '[4, 5, 6, 7]'::jsonb, '["Pomme de terre de l''Île de Ré", "Île de Ré potato"]'::jsonb, FALSE, 'L2'),
  ('db126ae0-4815-a64e-baed-be391d3160d8', 'FR', 'France', 'fruits_nuts', 'Pomme du Limousin AOP', '["Pomme du Limousin AOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Limousin apple AOP, predominantly Golden Delicious from high-altitude orchards (Limousin terroir). Characteristic golden-yellow color with red blush, crisp tender white flesh, distinctively balanced sweet-tart flavor — France''s only AOP apple.', 'Premium dessert apple for tarte tatin, tarte normande, fruit plates; with Auvergne-Limousin cheese course; juice and cider production.', '["crate-15kg", "crate-18kg", "retail-tray-2kg", "retail-net-bag-3kg"]'::jsonb, '[]'::jsonb, '["Pomme du Limousin", "Golden Limousin"]'::jsonb, FALSE, 'L2'),
