  ('1decdfb6-024e-73c6-ea5d-7316e8c7ff9c', 'FR', 'France', 'rice_pasta_grains', 'Farine de blé noir de Bretagne IGP', '["Farine de blé noir de Bretagne IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Brittany buckwheat flour IGP, distinctive grey-flecked dark flour, characteristic earthy-nutty buckwheat flavor.', '**Foundation of Breton galettes** (savory crêpes) — the iconic Breton restaurant dish; in regional pancakes; mixed with wheat for pasta-making.', '["paper-bag-500g", "paper-bag-1kg", "professional-bulk-5kg", "professional-bulk-25kg"]'::jsonb, '[]'::jsonb, '["Farine de blé noir", "Buckwheat flour Brittany"]'::jsonb, FALSE, 'L2'),
