  ('01bcf103-b8c5-fa05-62e1-546e65224fa9', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Alheira de Mirandela IGP', '["Alheira de Mirandela IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Trás-os-Montes traditional sausage IGP from Mirandela, distinctive — bread-thickened, with poultry/game meat (originally a converso-Jewish-Portuguese substitute for pork sausage; today also pork variants), seasoned with garlic, paprika. Pale beige-pink color, soft sausage texture, distinctive bread-and-meat balance, mild garlic-paprika flavor — the iconic Portuguese alheira.', '**Foundation of Portuguese tasca service** — Alheira frita com ovo escalfado e batatas fritas (the canonical Portuguese pub dish — fried alheira with poached egg and chips); grilled; pairs with Douro reds and Vinho Verde.', '["vacuum-pack-pair-200-400g", "individual-link-150g", "professional-bulk-1kg"]'::jsonb, '[]'::jsonb, '["Alheira de Mirandela"]'::jsonb, FALSE, 'L2'),
  ('1a38d2e1-e73b-2c5e-6100-656a0f5eba58', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Alheira de Barroso-Montalegre IGP', '["Alheira de Barroso-Montalegre IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Trás-os-Montes alheira variant from Barroso/Montalegre area. Similar profile to Mirandela.', 'Same Portuguese tasca applications.', '["Same as Mirandela"]'::jsonb, '[]'::jsonb, '["Alheira de Barroso"]'::jsonb, FALSE, 'L2'),
  ('a41abb8d-70d3-e7d8-3c20-b0a65279669e', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Alheira de Vinhais IGP', '["Alheira de Vinhais IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Trás-os-Montes alheira variant from Vinhais. Similar profile.', 'Same applications.', '["Same"]'::jsonb, '[]'::jsonb, '["Alheira de Vinhais"]'::jsonb, FALSE, 'L2'),
  ('6639c9e2-f842-cbe9-e4ee-3bb60b889881', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Farinheira de Estremoz e Borba IGP', '["Farinheira de Estremoz e Borba IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Alentejano sausage IGP — distinctive flour-based preparation (the "farinheira" = "flour sausage"), pork fat, paprika, garlic, no real meat (or minimal). Pale beige color, soft texture, mild balanced flavor.', 'Pan-fried as petisco; in Alentejano stews; with eggs.', '["vacuum-pack-200-300g"]'::jsonb, '[]'::jsonb, '["Farinheira"]'::jsonb, FALSE, 'L2'),
  ('ac49ebbd-c237-eacc-d10c-5be7517c3fd4', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Farinheira de Portalegre IGP', '["Farinheira de Portalegre IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Alentejano farinheira variant from Portalegre. Similar profile.', 'Same applications.', '["Same"]'::jsonb, '[]'::jsonb, '["Farinheira de Portalegre"]'::jsonb, FALSE, 'L2'),
  ('1ca00d2d-8d3b-77a6-7da4-e2ae5b48b625', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Morcela de Estremoz e Borba IGP', '["Morcela de Estremoz e Borba IGP", "Morcela de Assar de Portalegre IGP"]'::jsonb, 'PGI', '["PGI", "PGI"]'::jsonb, 'Alentejano blood sausage IGPs. Dark mahogany color, soft fine texture, robust blood-and-spice flavor with bread thickening and rice/onion variations.', 'Petisco; in Alentejano stews; grilled with apples.', '["vacuum-pack-300-400g"]'::jsonb, '[]'::jsonb, '["Morcela de Estremoz", "Morcela Alentejana"]'::jsonb, FALSE, 'L2'),
  ('bbf53ebd-f5c6-3e6c-0bf5-400bc811369b', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Sangueira de Barroso-Montalegre IGP', '["Sangueira de Barroso-Montalegre IGP", "Cacholeira Branca de Portalegre IGP", "Painho de Portalegre IGP"]'::jsonb, 'PGI', '["PGI", "PGI", "PGI"]'::jsonb, 'Various Trás-os-Montes/Alentejano sausage IGPs covering blood sausages and traditional regional preparations.', 'Regional charcutaria; petiscos; in regional stews.', '["vacuum-pack-200-400g"]'::jsonb, '[]'::jsonb, '["Sangueira", "Cacholeira Branca", "Painho"]'::jsonb, FALSE, 'L2'),
  ('c352a964-7608-9bb3-80ba-a80219187d61', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Mortadela de Portalegre IGP', '["Mortadela de Portalegre IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Alentejano cooked emulsified sausage from Portalegre, Portuguese-style mortadela. Pale pink color, fine texture, balanced flavor.', 'Charcutaria board; sliced thin for sandwiches.', '["vacuum-pack-300-500g", "deli-sliced-vacuum-100g"]'::jsonb, '[]'::jsonb, '["Mortadela de Portalegre"]'::jsonb, FALSE, 'L2'),
  ('719685bb-d987-6937-ca5c-b02503aab44b', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Mertolenga DOP', '["Carne Mertolenga DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Alentejano beef DOP from native Mertolenga breed (Beja-Évora-Portalegre). Bright cherry-red meat with characteristic native-breed marbling, robust flavor from montado-grazed cattle.', 'Premium Alentejano steakhouse beef; pairs with Alentejano reds.', '["carcass-half-150kg", "primal-cuts-vacuum-various", "lombo-1-1.5kg", "vazia-300-400g"]'::jsonb, '[]'::jsonb, '["Mertolenga", "Carne Mertolenga"]'::jsonb, FALSE, 'L2'),
  ('51545167-bd9f-8302-ad70-73e317ac9f45', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Maronesa DOP', '["Carne Maronesa DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trás-os-Montes beef DOP from native Maronesa breed (Vila Real-Bragança). Distinctive long-horned breed, characteristic dark meat with intense beefy flavor.', 'Trás-os-Montes steakhouse; in Posta Maronesa preparation.', '["Same as other beef DOPs"]'::jsonb, '[]'::jsonb, '["Maronesa", "Posta Maronesa"]'::jsonb, FALSE, 'L2'),
  ('989604ef-c008-951f-5365-46b5b44aecfe', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Arouquesa DOP', '["Carne Arouquesa DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Beira-Norte beef DOP from native Arouquesa breed (Aveiro-Viseu). Tender flavored meat.', 'Beira regional cuisine.', '["Same"]'::jsonb, '[]'::jsonb, '["Arouquesa"]'::jsonb, FALSE, 'L2'),
  ('7b3e034c-1ea6-9aaa-ac4d-16100141952f', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Mirandesa DOP', '["Carne Mirandesa DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trás-os-Montes beef DOP from native Mirandesa breed (Bragança, Miranda do Douro plateau). Distinctive characteristic Mirandesa profile, intensely beefy.', '**Posta Mirandesa** — the iconic Trás-os-Montes wood-grilled beef preparation; pairs with Douro reds.', '["Same as other beef DOPs"]'::jsonb, '[]'::jsonb, '["Mirandesa", "Posta Mirandesa"]'::jsonb, FALSE, 'L2'),
  ('a5090348-d3e6-eef1-4b50-3723912e880a', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Cachena da Peneda DOP', '["Carne Cachena da Peneda DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Minho beef DOP from native Cachena breed (Serra da Peneda). Small breed with very intense beefy flavor.', 'Minho regional cuisine; premium artisanal beef.', '["Same"]'::jsonb, '[]'::jsonb, '["Cachena"]'::jsonb, FALSE, 'L2'),
  ('10a81521-2273-5774-fc08-a74882101146', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Marinhoa DOP', '["Carne Marinhoa DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Beira-Litoral beef DOP from native Marinhoa breed (Aveiro coastal area). Characteristic Marinhoa flavor.', 'Coastal Beira regional cuisine.', '["Same"]'::jsonb, '[]'::jsonb, '["Marinhoa"]'::jsonb, FALSE, 'L2'),
  ('8083efd5-6185-bb47-97af-9b78c5475861', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Barrosã DOP', '["Carne Barrosã DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trás-os-Montes/Minho beef DOP from native Barrosã breed (Boticas-Montalegre area). Long-horned breed, characteristic mountain-grazed flavor.', 'Barroso-Trás-os-Montes regional cuisine.', '["Same"]'::jsonb, '[]'::jsonb, '["Barrosã"]'::jsonb, FALSE, 'L2'),
  ('de79dfc4-c64b-f417-805a-fa9c0d9a3794', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Alentejana DOP', '["Carne Alentejana DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Alentejano beef DOP from native Alentejana breed (Évora-Beja). Characteristic montado-grazed beefy flavor.', 'Alentejano steakhouse; pairs with Alentejano reds.', '["Same"]'::jsonb, '[]'::jsonb, '["Alentejana"]'::jsonb, FALSE, 'L2'),
  ('ff339eeb-d2dd-ae68-d669-f2ee71f2b5a9', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne Charneca DOP', '["Carne Charneca DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Ribatejano-Alentejano beef DOP from Charneca-region cattle.', 'Ribatejo regional cuisine.', '["Same"]'::jsonb, '[]'::jsonb, '["Charneca"]'::jsonb, FALSE, 'L2'),
  ('f65eb99a-9cea-3d5d-c979-0a0800c9d627', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carne de Bovino Cruzado dos Lameiros do Barroso IGP', '["Carne de Bovino Cruzado dos Lameiros do Barroso IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Barroso (Trás-os-Montes) cross-bred cattle IGP from Lameiros area.', 'Regional cuisine.', '["Same as other beef"]'::jsonb, '[]'::jsonb, '["Bovino Cruzado dos Lameiros"]'::jsonb, TRUE, 'L2'),
  ('4030f1a6-72b8-dd6f-e956-59f642f342ee', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Carnalentejana DOP', '["Carnalentejana DOP", "Carne de Porco Alentejano DOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Alentejano pork DOP from porco preto Alentejano (Iberian black pig). Pinkish-red meat with golden marbled fat, intensely flavored from acorn-and-pasture montado feed.', '**Foundation of Alentejano cuisine** — Carne de porco à Alentejana (the iconic preparation with clams), in açorda Alentejana, foundation pork for Presunto de Barrancos production.', '["carcass-half-40-50kg", "primal-cuts-vacuum-various", "lombo-1-2kg", "secreto-300-500g", "presa-300-400g"]'::jsonb, '[]'::jsonb, '["Carne de Porco Alentejano", "Porco Preto Alentejano"]'::jsonb, FALSE, 'L2'),
  ('79d1b666-68fc-1c94-4a3f-f5fd9fdef8dc', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Borrego do Baixo Alentejo IGP', '["Borrego do Baixo Alentejo IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Alentejano lamb IGP. Lean delicate flesh from montado-grazed Merina-breed flocks.', 'Alentejano cuisine; in ensopado de borrego.', '["carcass-half-10-15kg", "primal-cuts", "perna-2-3kg"]'::jsonb, '[3, 4, 12]'::jsonb, '["Borrego Alentejano"]'::jsonb, FALSE, 'L2'),
  ('5b53879e-2422-de6a-df0b-b4a23fca7bc8', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Borrego de Montemor-o-Novo IGP', '["Borrego de Montemor-o-Novo IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Alentejano lamb IGP from Montemor area.', 'Same Alentejano applications.', '["Same"]'::jsonb, '[3, 4, 12]'::jsonb, '["Borrego de Montemor"]'::jsonb, FALSE, 'L2'),
  ('fb63ba07-20e3-e846-faa1-f40308747fed', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Borrego Serra da Estrela DOP', '["Borrego Serra da Estrela DOP", "Borrego da Serra da Estrela DOP"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, 'Beira lamb DOP from Bordaleira de Serra da Estrela breed (same flocks as Serra da Estrela cheese). Delicate flavored meat, characteristic mountain-pasture profile.', 'Beira regional cuisine; with Serra da Estrela cheese course.', '["Same"]'::jsonb, '[3, 4, 12]'::jsonb, '["Borrego Serra da Estrela"]'::jsonb, FALSE, 'L2'),
  ('153fe908-fcad-2c27-3da0-2f2e843a1a22', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Borrego Terrincho DOP', '["Borrego Terrincho DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trás-os-Montes lamb DOP from Churra Terrincha breed.', 'Trás-os-Montes regional cuisine; cabrito-style preparations.', '["Same"]'::jsonb, '[3, 4, 12]'::jsonb, '["Borrego Terrincho"]'::jsonb, FALSE, 'L2'),
  ('843c3645-ef32-ff68-7d28-10b77b83e18d', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Borrego de Barroso IGP', '["Borrego de Barroso IGP", "Anho de Barroso IGP"]'::jsonb, 'PGI', '["PGI", "PGI"]'::jsonb, 'Trás-os-Montes lamb IGP from Barroso area, Galega and Bordaleira de Entre-Douro-e-Minho breeds.', 'Barroso regional cuisine.', '["Same"]'::jsonb, '[3, 4, 12]'::jsonb, '["Anho de Barroso"]'::jsonb, FALSE, 'L2'),
  ('f7fd241a-d3c1-025a-13d8-a592a77ebbb3', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Cabrito Transmontano DOP', '["Cabrito Transmontano DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Trás-os-Montes goat-kid DOP. Tender pale flesh, delicate flavor.', '**Cabrito assado no forno** (oven-roasted kid) — Trás-os-Montes restaurant signature; classic Easter dish.', '["whole-kid-3-5kg", "half-kid-vacuum-2kg", "primal-cuts-vacuum-various"]'::jsonb, '[3, 4, 12]'::jsonb, '["Cabrito Transmontano"]'::jsonb, FALSE, 'L2'),
  ('9bd4fe98-8fac-9d44-6984-247e094721f3', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Cabrito de Barroso IGP', '["Cabrito de Barroso IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Trás-os-Montes goat-kid IGP from Barroso area.', 'Barroso regional cuisine.', '["Same"]'::jsonb, '[3, 4, 12]'::jsonb, '["Cabrito de Barroso"]'::jsonb, FALSE, 'L2'),
  ('d00174f9-0c92-65fa-49dc-4471193cc59f', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Cabrito do Alentejo IGP', '["Cabrito do Alentejo IGP", "Cabrito de Beira IGP", "Cabrito da Gralheira IGP", "Cabrito das Terras Altas do Minho IGP"]'::jsonb, 'PGI', '["PGI", "PGI", "PGI", "PGI"]'::jsonb, 'Various regional cabrito IGPs across Portugal. Tender pale kid flesh.', 'Regional Easter and Christmas dishes.', '["Same as other cabritos"]'::jsonb, '[3, 4, 12]'::jsonb, '["Various regional names"]'::jsonb, FALSE, 'L2'),
  ('3467b5d4-de96-bbb7-e20a-82ce73747d1e', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Capão de Freamunde IGP', '["Capão de Freamunde IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Minho capon IGP from Freamunde (Paços de Ferreira). Larger than chicken, fattier, more tender, pale yellow flesh from corn-feed.', '**Christmas Minho specialty** — Capão de Freamunde recheado (stuffed) Christmas centerpiece.', '["whole-bird-fresh-3-5kg", "eviscerated-vacuum-3-4kg", "gift-bird-Christmas-3-5kg"]'::jsonb, '[11, 12]'::jsonb, '["Capão de Freamunde"]'::jsonb, FALSE, 'L2'),
  ('5f5c6a62-a552-773a-3105-02dc67896bf0', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Cordeiro Bragançano DOP (status verify Layer 1)', '["Cordeiro Bragançano DOP (status verify Layer 1)"]'::jsonb, 'PDO', '["PDO"]'::jsonb, '', '', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, TRUE, 'L2'),
  ('68e7f786-2c6e-b78c-41c0-aeb006eb58e6', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Cordeiro Mirandês DOP', '["Cordeiro Mirandês DOP", "Cordeiro de Miranda do Douro DOP (status verify)"]'::jsonb, 'PDO', '["PDO", "PDO"]'::jsonb, '', '', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, TRUE, 'L2'),
  ('b9108fbf-1d1a-5f19-c19b-ad5db9270d0c', 'PT', 'Portugal', 'cured_meats_charcuterie', 'Frango do Campo (status — Label, may not be IGP)', '["Frango do Campo (status — Label, may not be IGP)"]'::jsonb, 'PGI', '["PGI"]'::jsonb, '', '', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, TRUE, 'L2'),
  ('f7bda6eb-d0c3-5e19-492c-80235ccdfd6c', 'PT', 'Portugal', 'fruits_nuts', 'Maçã de Alcobaça IGP', '["Maçã de Alcobaça IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Estremaduran apple IGP from Alcobaça-Cister monastery area. Multiple varieties (Golden, Royal Gala, Granny Smith, Reinette). Crisp tender flesh, balanced sweet-tart flavor.', 'Fresh fruit service; in maçã assada (baked apple — Portuguese classic); cider production.', '["crate-15kg", "retail-tray-2kg"]'::jsonb, '[]'::jsonb, '["Maçã de Alcobaça"]'::jsonb, FALSE, 'L2'),
