INSERT INTO gi_entries (gi_id, country_code, country, category, primary_gi_name, all_gi_names, gi_type_primary, gi_types_all, tasting_notes, horeca_use, packaging_formats, seasonal_months, aliases, is_data_thin, source_layer) VALUES
  ('285155f8-5100-af82-b30c-e99e2a22ee72', 'PT', 'Portugal', 'fruits_nuts', 'Maçã Bravo de Esmolfe DOP', '["Maçã Bravo de Esmolfe DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Beira apple DOP from Esmolfe area, distinctive native variety. Small to medium fruit, distinctive russeted golden skin, very firm crisp flesh, intensely aromatic with characteristic pear-rose-apple profile — among Portugal''s most prized apples.', 'Premium dessert apple; in maçã assada com vinho do Porto; on cheese boards.', '["crate-10kg", "retail-tray-2kg", "gift-pack-2kg"]'::jsonb, '[9, 10, 11, 12]'::jsonb, '["Bravo de Esmolfe", "Esmolfe apple"]'::jsonb, FALSE, 'L2'),
  ('b0c25a5b-81a5-0fe0-2112-49c62336665b', 'PT', 'Portugal', 'fruits_nuts', 'Pêra Rocha do Oeste DOP', '["Pêra Rocha do Oeste DOP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Estremaduran pear DOP from Oeste region (Cadaval-Bombarral-Caldas). Distinctive Rocha variety — pale yellow-green with russeted patches, crisp tender flesh, balanced sweet-tart flavor — Portugal''s most exported pear.', 'Premium dessert pear; in poached-pear desserts; with Portuguese cheese course.', '["crate-15kg", "retail-tray-2kg", "gift-pack-2kg"]'::jsonb, '[8, 9, 10, 11, 12, 1]'::jsonb, '["Pêra Rocha", "Rocha do Oeste", "Rocha pear"]'::jsonb, FALSE, 'L2'),
  ('d513fedf-72b5-73be-baf5-eba96bb23587', 'PT', 'Portugal', 'fruits_nuts', 'Pêssego da Cova da Beira IGP', '["Pêssego da Cova da Beira IGP"]'::jsonb, 'PGI', '["PGI"]'::jsonb, 'Beira peach IGP from Cova da Beira area. Multiple varieties, sweet juicy fruit.', 'Fresh dessert; in pêssego em vinho do Porto.', '["crate-fresh-5kg", "retail-tray-1kg"]'::jsonb, '[6, 7, 8, 9]'::jsonb, '["Pêssego Cova da Beira"]'::jsonb, FALSE, 'L2'),
  ('493c967a-9f73-3a94-ceb3-b41d3ddb51d8', 'PT', 'Portugal', 'fruits_nuts', 'Cereja da Cova da Beira IGP', '["Cereja da Cova da Beira IGP", "Cereja de São Julião IGP", "Cereja do Fundão IGP"]'::jsonb, 'PGI', '["PGI", "PGI", "PGI"]'::jsonb, 'Beira regional cherry IGPs. Bright red fruit, juicy firm flesh, sweet-tart flavor.', 'Fresh fruit service; in jams and preserves.', '["crate-fresh-5kg", "retail-tray-500g", "retail-tray-1kg"]'::jsonb, '[5, 6, 7]'::jsonb, '["Various regional names"]'::jsonb, FALSE, 'L2'),
  ('efd862a1-9cce-6e82-a49d-5c4dc67553d8', 'PT', 'Portugal', 'fruits_nuts', 'Castanha de Padrela DOP', '["Castanha de Padrela DOP", "Castanha dos Soutos da Lapa DOP", "Castanha da Terra Fria DOP", "Castanha de Marvão-Portalegre DOP"]'::jsonb, 'PDO', '["PDO", "PDO", "PDO", "PDO"]'::jsonb, 'Trás-os-Montes/Beira/Alentejo chestnut DOPs. Sweet creamy flesh, characteristic Portuguese-soutos profile.', 'Castanhas assadas (roasted chestnuts — São Martinho November tradition); in regional pastry; chestnut flour for traditional bread.', '["crate-fresh-10kg", "vacuum-pack-cooked-500g", "dried-1kg", "gift-pack-300g"]'::jsonb, '[10, 11, 12]'::jsonb, '["Various regional names"]'::jsonb, FALSE, 'L2'),
