  ('3de9c323-a8e8-3652-9df9-7ad190f45bca', 'GR', 'Greece', 'cheeses_dairy', 'Sfela POP', '["Sfela POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Peloponnesian sheep-and-goat-milk cheese POP from Lakonia, traditional thin-strip-shape brine-cured. White color, firm texture, intensely salty flavor.', 'Lakonian regional cuisine.', '["vacuum-pack-300g", "brine-tin-1kg"]'::jsonb, '[]'::jsonb, '["Sfela"]'::jsonb, FALSE, 'L2'),
