  ('36138307-53ed-b89b-21d7-e744085fe3bf', 'GR', 'Greece', 'cheeses_dairy', 'Ladotyri Mytilinis POP', '["Ladotyri Mytilinis POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aegean Lesvos sheep-and-goat-milk cheese POP, distinctive — aged in olive oil after initial drying. Pale yellow paste from oil-aging, firm dense texture, balanced flavor with characteristic oil-aged complexity.', 'Lesvos and Aegean island cuisine; on mezze.', '["wedge-vacuum-300g", "oil-jar-aged-500g"]'::jsonb, '[]'::jsonb, '["Ladotyri", "Lesvos cheese"]'::jsonb, FALSE, 'L2'),
  ('11d20ecc-4f46-6b5d-31ba-4afa2462337a', 'GR', 'Greece', 'cheeses_dairy', 'Metsovone POP', '["Metsovone POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Epirote smoked cow''s-and-sheep-milk cheese POP from Metsovo. Distinctive smoke-darkened amber rind from beechwood smoking, ivory-cream paste, semi-firm texture, intensely savory smoky flavor.', '**Greek saganaki** premium variant; with kombrosit (regional sausage); on mezze.', '["whole-piece-smoked-300-500g", "wedge-vacuum-200g"]'::jsonb, '[]'::jsonb, '["Metsovone", "Smoked Metsovo cheese"]'::jsonb, FALSE, 'L2'),
  ('4cf66fe3-e7c7-4db0-0bfb-65fbf615c002', 'GR', 'Greece', 'cheeses_dairy', 'San Mihali POP', '["San Mihali POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aegean Syros sheep-and-cow-milk cheese POP from San Michali (Syros). Pale ivory paste, firm dense texture, balanced flavor.', 'Cycladic island cuisine.', '["wheel-full-3-7kg", "wedge-vacuum-300g"]'::jsonb, '[]'::jsonb, '["San Mihali", "Syros cheese"]'::jsonb, FALSE, 'L2'),
  ('03a681aa-f7cd-5e2a-cde7-0698152b4f36', 'GR', 'Greece', 'cheeses_dairy', 'Kopanisti POP', '["Kopanisti POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Cycladic sheep-and-goat-milk cheese POP, distinctive — kneaded fermented cheese with Penicillium-like blue mold, intensely pungent flavor. Greyish color, soft spreadable creamy texture, robust salty-savory blue-cheese-like profile.', 'Cycladic mezze; spread on bread; with ouzo and tsipouro.', '["tub-200g", "tub-300g"]'::jsonb, '[]'::jsonb, '["Kopanisti", "Cycladic blue"]'::jsonb, FALSE, 'L2'),
  ('cf5bebce-bc19-8995-a7c5-0b2b973f0469', 'GR', 'Greece', 'cheeses_dairy', 'Pichtogalo Chanion POP', '["Pichtogalo Chanion POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Cretan fresh sheep-and-goat-milk cheese POP from Chania. Bright white, soft pudding-like texture (the name means "thick yogurt"), mild fresh-creamy flavor.', 'Cretan dakos; in pastry; in regional preparations.', '["tub-200g", "tub-300g", "tub-500g"]'::jsonb, '[]'::jsonb, '["Pichtogalo Chanion"]'::jsonb, FALSE, 'L2'),
  ('1c0d5569-4679-9413-bc2e-45f821c67c0c', 'GR', 'Greece', 'cheeses_dairy', 'Formaella Arachovas Parnassou POP', '["Formaella Arachovas Parnassou POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Peloponnesian-Boeotian sheep-and-goat-milk cheese POP from Arachova area. Distinctive cylindrical shape, smoke-cured over fire, firm dense texture, savory smoky flavor.', 'Saganaki preparation; Arachova-mountain regional cuisine.', '["cylinder-300-500g", "vacuum-pack-200g"]'::jsonb, '[]'::jsonb, '["Formaella Arachovas"]'::jsonb, FALSE, 'L2'),
