  ('8dbbf8a4-4566-89e5-c84f-b4fb21dec319', 'GR', 'Greece', 'cheeses_dairy', 'Kalathaki Limnou POP', '["Kalathaki Limnou POP"]'::jsonb, 'PDO', '["PDO"]'::jsonb, 'Aegean Limnos sheep-and-goat-milk cheese POP, distinctive basket-shaped (kalathaki = "little basket"), brine-cured. White color, semi-soft texture, salty-tangy flavor (similar to Feta but with basket-shape signature).', 'Limnos cuisine; in salads; mezze.', '["vacuum-pack-300-500g", "brine-tin-1kg"]'::jsonb, '[]'::jsonb, '["Kalathaki Limnou", "Limnos cheese"]'::jsonb, FALSE, 'L2'),
